-- Poems batch 190
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('efe11eb1-0bc1-47ed-afdf-1b8602eecab3','訪西澗王深道  其一','戴復古','宋','宋诗','song-poetry','','[]','諸王居處僻，古屋滿山坡。',48,'全唐诗/poet.song.182000.json','["諸王居處僻，古屋滿山坡。", "傳到宋淳祐，來從晉永和。", "詩書歷年久，名勝結交多。", "一澗流芳潤，滔滔秋水波。"]'),
('19465dd8-686d-4541-9019-27c3dafe6912','訪西澗王深道  其二','戴復古','宋','宋诗','song-poetry','','[]','諸老傷凋謝，凄凉屬此時。',48,'全唐诗/poet.song.182000.json','["諸老傷凋謝，凄凉屬此時。", "相從一夜語，忍讀四哀詩。", "世事生愁緒，秋風吹鬢絲。", "黄花香晚節，說與秀巖知。"]'),
('715f07ef-7b82-4bdb-b1a3-dd50b4445d8b','東谷王子文死讀其詩文有感','戴復古','宋','宋诗','song-poetry','','[]','東谷今何在，騎鯨去渺茫。',48,'全唐诗/poet.song.182000.json','["東谷今何在，騎鯨去渺茫。", "荆花半零落，巖桂自芬芳。", "議論波瀾闊，文章氣脈長。", "遺編猶可考，何必計存亡。"]'),
('cb040600-75a6-49a6-9b4f-28214421b6e9','挽溫嶺丁竹坡','戴復古','宋','宋诗','song-poetry','','[]','瀟灑復瀟灑，是爲丁竹坡。',48,'全唐诗/poet.song.182000.json','["瀟灑復瀟灑，是爲丁竹坡。", "生涯渾草草，詩句自多多。", "恨不識是叟，悲哉作此歌。", "數編遺稿在，不共葬烟蘿。"]'),
('3604cd54-4ce7-4d30-82d1-5e67085fe91d','廣東漕李實夫四首  其一','戴復古','宋','宋诗','song-poetry','','[]','乾坤雖廣大，人物不能多。',48,'全唐诗/poet.song.182000.json','["乾坤雖廣大，人物不能多。", "議論還諸老，文章自一科。", "從橫負才畧，緩急任干戈。", "不有濟時傑，其如世事何。"]'),
('de321aab-c87f-41ec-b529-f9b9b82e47f7','廣東漕李實夫四首  其二','戴復古','宋','宋诗','song-poetry','','[]','志士規模遠，非時展布難。',48,'全唐诗/poet.song.182000.json','["志士規模遠，非時展布難。", "莫言南地暖，須念北風寒。", "楮賤傷財力，兵驕稔禍端。", "盛衰關氣數，天下幾時安。"]'),
('80b29134-1792-4e23-a896-b6318706cd5d','廣東漕李實夫四首  其三','戴復古','宋','宋诗','song-poetry','','[]','千里長城手，如何在廣州。',48,'全唐诗/poet.song.182000.json','["千里長城手，如何在廣州。", "共談天下事，莫上斗南樓。", "瘦露封侯骨，忠懷報國秋。", "丁寧北來鴈，邊信怕沉浮。"]'),
('48517705-2f68-4ad0-88f9-fdcdcc87402f','廣東漕李實夫四首  其四','戴復古','宋','宋诗','song-poetry','','[]','忘家甘旅食，憂國屬愁顔。',48,'全唐诗/poet.song.182000.json','["忘家甘旅食，憂國屬愁顔。", "有客佩金印，何人守玉關。", "風霜晚秋後，天地夕陽間。", "痛灑傷時淚，別公歸故山。"]'),
('d6a2d468-e929-44de-b3c4-0a855a0cb5a9','求安','戴復古','宋','宋诗','song-poetry','','[]','愁來須强遣，老去只求安。',48,'全唐诗/poet.song.182000.json','["愁來須强遣，老去只求安。", "酒熟思招客，詩成勝得官。", "梅花天下白，雪片夜深寒。", "衲被蒙頭睡，翛然百慮寬。"]'),
('9bab2152-493e-4f85-b532-ebb0b5257af6','秋日早行','戴復古','宋','宋诗','song-poetry','','[]','鴈叫秋容老，烏飛曙色分。',48,'全唐诗/poet.song.182000.json','["鴈叫秋容老，烏飛曙色分。", "晨炊何草草，宿酒尚醺醺。", "野曠連滄海，山長带白雲。", "馬行沙上路，驚起白鷗群。"]'),
('a43025f8-fd35-4ec6-b99c-59f6d9431bf4','何季皋司理故人也作詩見相勉意二首  其一','戴復古','宋','宋诗','song-poetry','','[]','梅花庾嶺外，別是一山川。',48,'全唐诗/poet.song.182000.json','["梅花庾嶺外，別是一山川。", "那使民無訟，須知獄有冤。", "心常存正直，法不尚平反。", "于氏緣何事，陰功到子孫。"]'),
('f6540107-a7e3-4d4a-ac71-f80e73bd0798','何季皋司理故人也作詩見相勉意二首  其二','戴復古','宋','宋诗','song-poetry','','[]','南州通外國，濁海溷清波。',48,'全唐诗/poet.song.182000.json','["南州通外國，濁海溷清波。", "人以廉稱少，官從辟奏多。", "持身宜潔白，事上莫依阿。", "話別無他語，留心政事科。"]'),
('28d00959-9d73-4f1c-bb9a-9a18989b00a6','石洲遇陳季申話舊','戴復古','宋','宋诗','song-poetry','','[]','綠樹挂烏帽，清波照白頭。',48,'全唐诗/poet.song.182000.json','["綠樹挂烏帽，清波照白頭。", "合隨秋燕去，那作賈胡留。", "紅吐檳榔唾，香薰茉莉毬。", "樽前話疇昔，一笑不能休。"]'),
('ff300e61-8b3d-40aa-947c-4413794235bc','廣州所見','戴復古','宋','宋诗','song-poetry','','[]','風波行險道，萬里絕人烟。',48,'全唐诗/poet.song.182000.json','["風波行險道，萬里絕人烟。", "幾箇下番客，經年渡海船。", "人皆貪舶貨，我獨惜青錢。", "囗囗囗囗囗，留心禁漏川。"]'),
('e2d1fe0f-9ed2-41dd-b061-a8a7f3f3d197','書事','戴復古','宋','宋诗','song-poetry','','[]','喜作羊城客，忘爲鶴髮翁。',48,'全唐诗/poet.song.182000.json','["喜作羊城客，忘爲鶴髮翁。", "問天求酒量，翻海洗詩窮。", "已過西南道，適遭東北風。", "扁舟載明月，枉作賣油公。"]'),
('2ec24bf3-ba4b-4b05-a802-0b6c3f68c8cc','別李司直蕭小山','戴復古','宋','宋诗','song-poetry','','[]','老作五羊客，時從二妙游。',48,'全唐诗/poet.song.182000.json','["老作五羊客，時從二妙游。", "文星照南斗，吾道欲東周。", "合作金閨彥，那爲玉帳留。", "嚴徐聞有召，吾亦辦歸舟。"]'),
('4b1c9fdc-3ba5-41bc-adf5-b9c169239deb','峽山二首  其一','戴復古','宋','宋诗','song-poetry','','[]','山近江如束，林深路欲迷。',48,'全唐诗/poet.song.182000.json','["山近江如束，林深路欲迷。", "平沙印虎跡，絕壁聽猿啼。", "綠水人誰釣，黄茅地可畦。", "幽居堪避世，何必武陵溪。"]'),
('bb740628-0109-4b61-8489-2ce7e6fd7440','峽山二首  其二','戴復古','宋','宋诗','song-poetry','','[]','欲訪飛來殿，維舟上峽山。',48,'全唐诗/poet.song.182000.json','["欲訪飛來殿，維舟上峽山。", "有溪流屋下，無路入雲間。", "犀解捐金索，猿能記玉環。", "無從旌往事，有地足躋攀。"]'),
('bf5be289-4ca0-487d-87b0-bdd65efc851e','舟行英德江上和許季如詩','戴復古','宋','宋诗','song-poetry','','[]','趺坐篷窗底，客身無事時。',48,'全唐诗/poet.song.182000.json','["趺坐篷窗底，客身無事時。", "閑觀曲江帖，因和許渾詩。", "舟楫聊乘興，溪山若獻奇。", "數峰英石美，天巧豈人爲。"]'),
('b5f22ce9-b218-447e-bf7f-253765c02916','重陽舟中','戴復古','宋','宋诗','song-poetry','','[]','扁舟何寂寞，絕不見人家。',48,'全唐诗/poet.song.182000.json','["扁舟何寂寞，絕不見人家。", "無處沽村酒，何從問菊花。", "溪山澹相對，節序謾云嘉。", "牢裹烏紗帽，西風日又斜。"]'),
('f158b993-24e7-4c5f-8fad-75747d036a3f','故人陳秘書家有感  其一','戴復古','宋','宋诗','song-poetry','','[]','晚春風雨後，花絮落無聲。',48,'全唐诗/poet.song.182000.json','["晚春風雨後，花絮落無聲。", "綠泛新荷出，青鋪細草生。", "私蛙爲誰噪，老犬伴人行。", "舊日狂賓客，樽前笑不成。"]'),
('3f741b96-2d35-45a9-b002-ebd1296ba34e','故人陳秘書家有感  其二','戴復古','宋','宋诗','song-poetry','','[]','林塘劫火後，更作兩家分。',48,'全唐诗/poet.song.182000.json','["林塘劫火後，更作兩家分。", "笋拆頭搶地，松高氣拂雲。", "老夫來訪舊，稚子解談文。", "自是麒麟種，那隨鴈鶩群。"]'),
('fd77b280-7cb0-4e75-a01c-4bb35a99b2d7','聞時事','戴復古','宋','宋诗','song-poetry','','[]','鴈豈關兵氣，魚常被火災。',48,'全唐诗/poet.song.182000.json','["鴈豈關兵氣，魚常被火災。", "御軍先擇將，立國可無財。", "濟世須人物，忠言是福媒。", "西山今已往，更待鶴山來。"]'),
('e27f9d52-30e5-4ac6-a365-ea8c7ed7d14b','口號送椰心簟劉使君','戴復古','宋','宋诗','song-poetry','','[]','適有椰心席，慇。',49,'全唐诗/poet.song.182000.json','["適有椰心席，慇。", "懃持贈君。", "來從三嶼國，織作五花文。", "凉暖宜冬夏，清光隔垢氛。", "桃笙與蘄簟，優劣迥然分。"]'),
('4d82bdee-2d7d-4752-bfdf-039e60122b89','懷江村何宏甫自贛上寄林檎','戴復古','宋','宋诗','song-poetry','','[]','人好物亦好，交深誼轉深。',48,'全唐诗/poet.song.182000.json','["人好物亦好，交深誼轉深。", "他鄉如對面，異體實同心。", "未得平安報，相思長短吟。", "無從回去馬，有便寄來禽。"]'),
('fbe5ee6b-bb53-45ed-9e6a-dba760ac526c','投江西曾憲二首  其一','戴復古','宋','宋诗','song-poetry','','[]','樞星居紫極，遥映使星明。',48,'全唐诗/poet.song.182000.json','["樞星居紫極，遥映使星明。", "天下推名德，君家好弟兄。", "一臺振綱紀，列郡想風聲。", "不試褰帷手，官曹未易清。"]'),
('a9105ed2-f497-44ae-91b7-3cc0c9b4637e','投江西曾憲二首  其二','戴復古','宋','宋诗','song-poetry','','[]','諸賢皆在位，治效尚遲遲。',48,'全唐诗/poet.song.182000.json','["諸賢皆在位，治效尚遲遲。", "汙吏未能去，明君若可欺。", "外臺天耳目，正士國根基。", "既攬澄清轡，那無按察時。"]'),
('3f16a9da-37f2-4229-847f-2d35bb195f1c','臨江小泊','戴復古','宋','宋诗','song-poetry','','[]','艤舟楊柳下，一笑上茶樓。',48,'全唐诗/poet.song.182000.json','["艤舟楊柳下，一笑上茶樓。", "適與胡僧遇，非因越女留。", "雲行山自在，沙合水分流。", "獨酌臨清泚，知心是白鷗。"]'),
('99bfb485-acbf-4129-8cc4-e67f75be9646','寄鄭潤甫提幹','戴復古','宋','宋诗','song-poetry','','[]','吾鄉有佳士，官小患才多。',48,'全唐诗/poet.song.182000.json','["吾鄉有佳士，官小患才多。", "文可登詞苑，直宜居諫坡。", "春風能活物，砥柱不隨波。", "客裏喜相遇，飄零柰我何。"]'),
('6604046a-e2fa-4b8e-b983-9ce6aa423064','趙丞話舊','戴復古','宋','宋诗','song-poetry','','[]','憶作齊安別，相逢直到今。',48,'全唐诗/poet.song.182000.json','["憶作齊安別，相逢直到今。", "寒溫片時話，故舊百年心。", "折柳送行客，栽松遇賞音。", "尊前强歌笑，兩鬢雪霜深。"]'),
('0614e2d5-faa1-443a-a208-dd9a6cb6dfe0','謝蕭和伯見訪','戴復古','宋','宋诗','song-poetry','','[]','定交雖日淺，老眼見君深。',48,'全唐诗/poet.song.182000.json','["定交雖日淺，老眼見君深。", "急誼真如渴，能詩不肯吟。", "江湖尊白髮，土苴視黄金。", "野客無邊幅，相看話此心。"]'),
('829a8b7b-439c-4e0f-a78f-699331e52566','廬陵城外','戴復古','宋','宋诗','song-poetry','','[]','郭外人烟好，行行過北阡。',48,'全唐诗/poet.song.182000.json','["郭外人烟好，行行過北阡。", "迎船分社肉，汲井種春田。", "綠樹前村路，黄梅細雨天。", "客游鄉土別，景物只同然。"]'),
('429cb945-8328-44da-b276-c767ec310b63','董侍郎蒙泉書院','戴復古','宋','宋诗','song-poetry','','[]','一室可忘老，四窗宜讀書。',48,'全唐诗/poet.song.182000.json','["一室可忘老，四窗宜讀書。", "但教樽有酒，莫問食無魚。", "客子家何在，明朝歲又除。", "思歸徒自苦，安處即吾廬。"]'),
('40b3d862-e6eb-4f1f-9942-8802284eacec','董叔震書堂','戴復古','宋','宋诗','song-poetry','','[]','數椽深巷底，朝夕自委蛇。',48,'全唐诗/poet.song.182000.json','["數椽深巷底，朝夕自委蛇。", "勳業時看劍，詩書日下帷。", "古碑遮素壁，破硯浴清池。", "燈火伊吾夜，猶如未第時。"]'),
('d8c6a587-9501-44c5-8b0c-d8c86fe3af29','別董叔宏兄弟','戴復古','宋','宋诗','song-poetry','','[]','年老思家切，交深話別難。',48,'全唐诗/poet.song.182000.json','["年老思家切，交深話別難。", "扁舟行且止，尊酒强相寬。", "客路歸來晚，人情去後看。", "西風吹過鴈，千萬寄平安。"]'),
('343eb004-adc3-46a2-aac6-658bf567e3e8','聞邊事','戴復古','宋','宋诗','song-poetry','','[]','昨日聞邊報，持杯不忍斟。',48,'全唐诗/poet.song.182000.json','["昨日聞邊報，持杯不忍斟。", "壯懷看寶劍，孤憤裂寒衾。", "風雨愁人夜，草茅憂國心。", "因思古豪傑，韓信在淮陰。"]'),
('b7cf26eb-492b-46dd-9d5a-70cc1048abeb','宜春東湖呈趙使君','戴復古','宋','宋诗','song-poetry','','[]','東園有佳趣，五馬共登臨。',48,'全唐诗/poet.song.182000.json','["東園有佳趣，五馬共登臨。", "介石見古意，月臺延賞心。", "雖然近城郭，元不遠山林。", "能使一州潤，秀江秋水深。"]'),
('a4ed4269-9efc-4ffe-b74c-2c9da16bd645','次韵董叔宏山中有感','戴復古','宋','宋诗','song-poetry','','[]','山中行樂處，百感上心來。',48,'全唐诗/poet.song.182000.json','["山中行樂處，百感上心來。", "宿霧掃不去，好風吹自開。", "巖花新得句，野水莫添杯。", "不盡登臨興，扁舟棹月回。"]'),
('4c11f29c-b18d-4f69-b0d6-67c2e5e45b9d','訪蒼山曾子實','戴復古','宋','宋诗','song-poetry','','[]','故人子曾子，居處近金精。',48,'全唐诗/poet.song.182000.json','["故人子曾子，居處近金精。", "福地佳山水，詩家老弟兄。", "十年重會面，一笑最關情。", "萬象亭前月，今宵爲我明。"]'),
('5dee0296-a081-4742-ad34-e5d3e1c57d39','事機','戴復古','宋','宋诗','song-poetry','','[]','天下事機別，朝廷局面新。',48,'全唐诗/poet.song.182000.json','["天下事機別，朝廷局面新。", "臺官遷不定，年號改何頻。", "黜陟由明主，安危仗老臣。", "祖宗成憲在，即此是經綸。"]'),
('8e309e03-3a4f-498e-8967-1d35dcf66eff','所聞二首  其一','戴復古','宋','宋诗','song-poetry','','[]','屢遣和戎使，三邊未解兵。',48,'全唐诗/poet.song.182000.json','["屢遣和戎使，三邊未解兵。", "武夫權漸重，□□望何輕。", "天下思豪傑，君王用老成。", "時無渭濱叟，白首致功名。"]'),
('78d024b7-ff63-4df2-ad65-477b6f319717','所聞二首  其二','戴復古','宋','宋诗','song-poetry','','[]','右席須賢久，丹書幾度催。',48,'全唐诗/poet.song.182000.json','["右席須賢久，丹書幾度催。", "賊驚中使轉，人望相公來。", "問政曲江宅，調羹庾嶺梅。", "莫因多病後，虛出應三台。"]'),
('dbb57f33-3c40-4c66-97a0-ef93e59eb982','歸舟已具李憲樓倉有約盜賊梗道見避亂者可憐  其一','戴復古','宋','宋诗','song-poetry','','[]','歲律又云莫，臨風詠式微。',48,'全唐诗/poet.song.182000.json','["歲律又云莫，臨風詠式微。", "兩臺方有約，一棹未成歸。", "夜宿三家市，天寒百衲衣。", "豺狼當道路，鷗鷺亦驚飛。"]'),
('5c991e1a-e887-4498-aab1-988ee5e00e7e','歸舟已具李憲樓倉有約盜賊梗道見避亂者可憐  其二','戴復古','宋','宋诗','song-poetry','','[]','倉猝拋家舍，遑遑走道塗。',48,'全唐诗/poet.song.182000.json','["倉猝拋家舍，遑遑走道塗。", "依山結茅广，摘草當園蔬。", "老稚朝朝哭，生涯物物無。", "避軍兼避寇，何日得安居。"]'),
('1cc9a8e4-2aef-40a4-8047-8bee1a080d0d','張端義應詔上書謫曲江正月一日贛州相遇  其一','戴復古','宋','宋诗','song-poetry','','[]','憂世心何切，謀身計甚疎。',48,'全唐诗/poet.song.182000.json','["憂世心何切，謀身計甚疎。", "樽前話不盡，天下事何如。", "漢武求言詔，賈生流涕書。", "龍顔那可犯，謫向曲江居。"]'),
('b07f0321-c3d0-422a-9065-e0b4d2c2e6d7','張端義應詔上書謫曲江正月一日贛州相遇  其二','戴復古','宋','宋诗','song-poetry','','[]','正朝送遷客，好去看梅花。',48,'全唐诗/poet.song.182000.json','["正朝送遷客，好去看梅花。", "此嶺幾人過，念君雙鬢華。", "直言知爲國，遠地莫思家。", "韶石叫虞舜，傷哉古道賒。"]'),
('010102a5-8126-472d-9ff6-e70588fec3d0','聞杜儀甫出臺','戴復古','宋','宋诗','song-poetry','','[]','臺官關係重，用捨一何輕。',48,'全唐诗/poet.song.182000.json','["臺官關係重，用捨一何輕。", "諸老多慚德，斯人有直聲。", "儻來視軒冕，歸去即功名。", "莫拜寬堂墓，傷心隔死生。"]'),
('d7caa98b-cb73-4c13-b1ae-edd840832145','揚州道宮安下制幹朱行甫撫幹方巨山連騎相訪','戴復古','宋','宋诗','song-poetry','','[]','道院群僊集，高軒二妙來。',48,'全唐诗/poet.song.182000.json','["道院群僊集，高軒二妙來。", "文章清氣足，談笑老懷開。", "落木三秋晚，黄花九日催。", "何當陪勝踐，共把蟹螯杯。"]'),
('92400b49-cc4c-421b-9309-fd82b89bcf28','朱行甫和前韵送別烹鹿薦酒','戴復古','宋','宋诗','song-poetry','','[]','此別真成別，從今去不來。',48,'全唐诗/poet.song.182000.json','["此別真成別，從今去不來。", "佳人難再得，惡抱向誰開。", "客路一歸晚，家書幾度催。", "慇懃見君意，烹鹿薦離杯。"]'),
('54132f69-2622-4862-a735-889dead6247f','題宋安撫月中香','戴復古','宋','宋诗','song-poetry','','[]','移根廣寒殿，栽近讀書堂。',48,'全唐诗/poet.song.182000.json','["移根廣寒殿，栽近讀書堂。", "良夜月中影，秋風天上香。", "此花真異種，萬木莫同芳。", "他日五枝秀，何慚竇十郎。"]'),
('493ad64f-ac62-488a-8949-317a22162c98','訪方子萬使君宅有園林之勝','戴復古','宋','宋诗','song-poetry','','[]','使君居處好，在郭却如村。',48,'全唐诗/poet.song.182000.json','["使君居處好，在郭却如村。", "屋带園林勝，門無市井喧。", "蟄龍將變化，雛鳳亦騰鶱。", "客裏苦無暇，相從聽雅言。"]'),
('4876de7a-a58e-467f-84d2-11068a21f0d1','諸詩人會于吳門翁際可通判席上高菊磵有詩僕有客星聚吳會詩派落松江之句方子萬使君喜之遂足成篇','戴復古','宋','宋诗','song-poetry','','[]','客星聚吳會，詩派落松江。',48,'全唐诗/poet.song.182000.json','["客星聚吳會，詩派落松江。", "老眼洞千古，曠懷開八窗。", "風流談奪席，歌笑酒盈缸。", "楊陸不再作，何人可受降。"]'),
('dcb1f031-3903-41eb-882c-7b2686686f61','別邵武諸故人','戴復古','宋','宋诗','song-poetry','','[]','白髮亂紛紛，鄉心逐海雲。',48,'全唐诗/poet.song.182000.json','["白髮亂紛紛，鄉心逐海雲。", "此行堪一哭，無復見諸君。", "老馬尋歸路，孤鴻戀舊群。", "酒闌何處笛，今夜不堪聞。"]'),
('abfe8eaa-b789-48f5-a4f7-21349a36b309','一老儒爲貴人燒丹丹垂成而走因此失所','戴復古','宋','宋诗','song-poetry','','[]','道途多險阻，此老欲何之。',48,'全唐诗/poet.song.182000.json','["道途多險阻，此老欲何之。", "命薄丹砂走，天寒白髮悲。", "從教達官駡，忍受小兒欺。", "月夜雙烏鵲，飛鳴繞樹枝。"]'),
('0866b01f-db94-4a0e-adaa-858fb4dd17d6','江上夜坐懷嚴儀卿李友山','戴復古','宋','宋诗','song-poetry','','[]','江清天影動，樓近角聲雄。',48,'全唐诗/poet.song.182000.json','["江清天影動，樓近角聲雄。", "楊柳枝枝月，芭蕉葉葉風。", "佳人難再得，良夜與誰同。", "別後知何處，吟詩句句工。"]'),
('f3e0690c-2f72-4aeb-ba12-39ec55cdfdb1','江上','戴復古','宋','宋诗','song-poetry','','[]','扁舟泊江渚，喜近酒家門。',48,'全唐诗/poet.song.182000.json','["扁舟泊江渚，喜近酒家門。", "出網魚蝦活，投林鳥雀喧。", "無橋通竹處，有路到桃源。", "一見南塘字，凄然憶故園。"]'),
('9a763e57-2c90-4dcd-a47f-1fa8496db235','簡曾才叔','戴復古','宋','宋诗','song-poetry','','[]','虛庭貯明月，酒醒獨登樓。',48,'全唐诗/poet.song.182000.json','["虛庭貯明月，酒醒獨登樓。", "偶逐一笑樂，遂成三夕留。", "烏鴉工報曉，蟋蟀早吟秋。", "欲赴東溪約，煩君具小舟。"]'),
('d82c4fd0-2c6b-454b-b332-ebe9e8bc8995','舟中','戴復古','宋','宋诗','song-poetry','','[]','扁舟何處泊，沙渚夕陽邊。',48,'全唐诗/poet.song.182000.json','["扁舟何處泊，沙渚夕陽邊。", "遠浦橫魚網，高山起燒烟。", "客行今老矣，秋思日凄然。", "且復開懷抱，囊中有酒錢。"]'),
('975f3663-9a67-485c-8f53-f2a33a722b22','史賢良入蜀有錦江詩卷陳誼甚高','戴復古','宋','宋诗','song-poetry','','[]','學道世情薄，論交誼氣深。',48,'全唐诗/poet.song.182000.json','["學道世情薄，論交誼氣深。", "謾懷三獻玉，肯受四知金。", "萬里銅梁道，千篇錦水吟。", "一芹供匕筯，聊寓野人心。"]'),
('d51ec2a1-1df0-414b-b309-25e6abd6df55','賢良一和五篇不可及','戴復古','宋','宋诗','song-poetry','','[]','世路從他險，輸君酒盞深。',48,'全唐诗/poet.song.182000.json','["世路從他險，輸君酒盞深。", "立談雙白璧，一諾百黄金。", "志大不少屈，詩工非苦吟。", "相隨萬里去，老鶴豈無心。"]'),
('4c20e0d3-6e4d-4551-9702-85363f28c858','永新彭時甫館僕于玉峰樓龍子崇來話舊','戴復古','宋','宋诗','song-poetry','','[]','暫艤溪頭棹，來敲月下門。',48,'全唐诗/poet.song.182000.json','["暫艤溪頭棹，來敲月下門。", "江湖十年別，故舊幾人存。", "聽雨夜同榻，論心酒一罇。", "不須談世事，萬慮滿乾坤。"]'),
('cd6275ca-07a0-4290-b683-ce01551d5d5a','所聞','戴復古','宋','宋诗','song-poetry','','[]','北風如許急，亦使客心寒。',48,'全唐诗/poet.song.182000.json','["北風如許急，亦使客心寒。", "近得襄陽報，仍聞蜀道難。", "三杯中夜酒，一枕幾時安。", "江上兩都督，何人上將壇。"]'),
('ca648203-b448-4f2d-8c4a-4a0c7801aea0','訪徐益夫','戴復古','宋','宋诗','song-poetry','','[]','仲蔚蓬蒿宅，終朝只閉關。',48,'全唐诗/poet.song.182000.json','["仲蔚蓬蒿宅，終朝只閉關。", "無心與時競，未老得身閑。", "綠繞巡除水，青橫隔岸山。", "客來新酒熟，相對一酡顔。"]'),
('fda550eb-1e15-4e69-bf18-ce3b46eb60d5','渝江綠陰亭九日燕集  其一','戴復古','宋','宋诗','song-poetry','','[]','佳節重有感，人間行道難。',48,'全唐诗/poet.song.182000.json','["佳節重有感，人間行道難。", "登高苦無地，把酒一凭欄。", "山迥暮烟合，江空秋水寒。", "沙頭有鸂鶒，莫作鴛鴦看。"]'),
('81bb7770-b4ff-4c4c-a9dc-d6d074936be8','渝江綠陰亭九日燕集  其二','戴復古','宋','宋诗','song-poetry','','[]','九日江亭上，誰憐老孟嘉。',48,'全唐诗/poet.song.182000.json','["九日江亭上，誰憐老孟嘉。", "要人看白髮，不用整烏紗。", "寄興題桐葉，長歌醉菊花。", "歸心徒自苦，猶在楚天涯。"]'),
('82132b04-df49-454f-a614-9c1366733138','題渝江蕭氏園亭  其一','戴復古','宋','宋诗','song-poetry','','[]','相識雖云晚，相知蓋有年。',48,'全唐诗/poet.song.182000.json','["相識雖云晚，相知蓋有年。", "同門好兄弟，華屋带林泉。", "笑傲一樽酒，登臨九月天。", "客懷秋思豁，萬象在吟邊。"]'),
('724336a3-5538-4d5d-a26e-e54c37d862b4','題渝江蕭氏園亭  其二','戴復古','宋','宋诗','song-poetry','','[]','三逕逐高低，旁通桃李蹊。',48,'全唐诗/poet.song.182000.json','["三逕逐高低，旁通桃李蹊。", "凉臺無六月，釣石俯雙溪。", "醉欲眠花下，吟來過竹西。", "風流黄太史，古壁有留題。"]'),
('482883d7-b8ec-4734-a87f-71c68409284e','題渝江蕭氏園亭  其三','戴復古','宋','宋诗','song-poetry','','[]','近市囂塵遠，幽居古意存。',48,'全唐诗/poet.song.182000.json','["近市囂塵遠，幽居古意存。", "詩人常下榻，俗子莫登門。", "日坐圖書府，時開風月樽。", "野夫因到此，忘却海雲村。"]'),
('424330d5-4611-493f-a9a0-5a7bb5ed5bea','新朝士多故人愁吟寄之','戴復古','宋','宋诗','song-poetry','','[]','野鹿自由性，孤鴻不就群。',48,'全唐诗/poet.song.182000.json','["野鹿自由性，孤鴻不就群。", "飄零生白髮，故舊半青雲。", "憂國家何有，愁吟天不聞。", "北風吹漢水，胡騎政紛紛。"]'),
('ec8490a2-6161-4c57-a194-cced501d7f57','題新塗何宏甫江村','戴復古','宋','宋诗','song-poetry','','[]','近郭畏囂塵，移居在水濱。',48,'全唐诗/poet.song.182000.json','["近郭畏囂塵，移居在水濱。", "江山千古意，松竹四時春。", "賓客門無禁，詩書筆有神。", "何郎好心事，鷗鷺亦相親。"]'),
('102cc5bb-21c4-4b71-a5cd-1a438ffe7f72','夜吟呈趙東巖','戴復古','宋','宋诗','song-poetry','','[]','汲井漱殘酒，行吟到夜分。',48,'全唐诗/poet.song.182000.json','["汲井漱殘酒，行吟到夜分。", "一軒清似洗，萬籟寂無聞。", "風送迎秋雨，天收翳月雲。", "鷄鳴庭戶白，人事又紛紛。"]'),
('61291b73-b68c-4956-ab5d-0f7bf7ca1181','吾鄉陳萬卿儒者能醫見宜春趙守盛稱其醫藥之妙著本草折衷可傳','戴復古','宋','宋诗','song-poetry','','[]','本草有折衷，儒醫功用深。',48,'全唐诗/poet.song.182000.json','["本草有折衷，儒醫功用深。", "何須九折臂，費盡一生心。", "藥物辨真僞，方書通古今。", "有時能起虢，一劑直千金。"]'),
('3593583d-630a-4f0d-8471-7960b31cfe4c','九月七日江上阻風','戴復古','宋','宋诗','song-poetry','','[]','艤棹依喬木，扶筇涉淺沙。',48,'全唐诗/poet.song.182000.json','["艤棹依喬木，扶筇涉淺沙。", "雲山多態度，水月兩光華。", "白首吟詩客，青帘賣酒家。", "明朝風不定，來此醉黄花。"]'),
('32334489-5a6b-40fc-80a5-7e3ba021909e','自和前詩鄰舟皆鹽商','戴復古','宋','宋诗','song-poetry','','[]','總被利名役，機心欲算沙。',48,'全唐诗/poet.song.182000.json','["總被利名役，機心欲算沙。", "舟行阻風色，客夢負年華。", "洲渚四五曲，漁樵八九家。", "江村無限好，滿眼是蘆花。"]'),
('e1ed23c6-7110-4986-8441-4c6433233365','有感','戴復古','宋','宋诗','song-poetry','','[]','皺眉觀世事，把酒讀離騷。',48,'全唐诗/poet.song.182000.json','["皺眉觀世事，把酒讀離騷。", "天下無公論，胸中有古刀。", "徒然成耿耿，何以制滔滔。", "不逐群飛轉，孤鴻畢竟高。"]'),
('66ac5b33-3755-45fe-b92b-3793392282cf','舂陵山中作寫寄孔海翁','戴復古','宋','宋诗','song-poetry','','[]','昨日分携後，回頭望竹關。',48,'全唐诗/poet.song.182000.json','["昨日分携後，回頭望竹關。", "相親唯白水，所見但青山。", "雲近人家遠，苔生石徑斑。", "聞鐘知有寺，又在渺茫間。"]'),
('a00c19e5-748b-4fcc-bfe8-922825ad687c','夏日雨後登樓','戴復古','宋','宋诗','song-poetry','','[]','夏日不苦熱，病軀能少康。',48,'全唐诗/poet.song.182000.json','["夏日不苦熱，病軀能少康。", "數峰樓上景，六月雨餘凉。", "今古兩虛器，乾坤百戲場。", "人生如寄爾，聊以醉爲鄉。"]'),
('1b0d9b8a-d4bc-4a9a-bc86-172a4ce05fba','偶見飛蝶追思舊遊錄之','戴復古','宋','宋诗','song-poetry','','[]','早被春情誤，渾身著粉衣。',48,'全唐诗/poet.song.182000.json','["早被春情誤，渾身著粉衣。", "最宜花上見，解向夢中飛。", "蜂媵爲游伴，蛛絲設禍機。", "滕王小圖畫，一一造精微。"]'),
('85f12179-5cf7-4f88-8cbd-b65731274691','寄永嘉太守趙茂實  其一','戴復古','宋','宋诗','song-poetry','','[]','龔黄古賢牧，政事見於今。',48,'全唐诗/poet.song.182000.json','["龔黄古賢牧，政事見於今。", "疾惡風霜手，活人天地心。", "躬行循吏傳，時作謝池吟。", "我欲依劉表，常憂老病侵。"]'),
('69ba25d5-096b-43c3-a86f-d0e7418dcaac','寄永嘉太守趙茂實  其二','戴復古','宋','宋诗','song-poetry','','[]','身爲吟詩瘦，家因好誼貧。',48,'全唐诗/poet.song.182000.json','["身爲吟詩瘦，家因好誼貧。", "如何賢太守，不念可憐人。", "橘井誰知處，桃源莫問津。", "秋風吹白髮，滄海老垂綸。"]'),
('2533f450-26e7-41bd-9b12-e07b1a635a5c','王應求出示蜀中山水障氣勢甚雄偉李巽巖題其後論其畫筆之源流二百餘字','戴復古','宋','宋诗','song-poetry','','[]','妙甚丹青手，能移造化功。',48,'全唐诗/poet.song.182000.json','["妙甚丹青手，能移造化功。", "三川山水國，半幅畫圖中。", "玉局人何在，銅梁路可通。", "巽巖扛鼎筆，文與畫爭雄。"]'),
('d10e1ca9-52e6-48a4-b006-604def21ffce','萬杉長老秀癡翁見示五言次韵','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','了得宗門事，何憂常住貧。',48,'全唐诗/poet.song.182000.json','["了得宗門事，何憂常住貧。", "聽師林下話，是我眼中人。", "星渚三秋月，廬山萬古春。", "昭陵御書在，歲久莫生塵。"]'),
('65349056-0b3f-4680-8011-71a3b4fba38b','借韵書懷','戴復古','宋','宋诗','song-poetry','','[]','虛氣撐枯腹，長身到老貧。',48,'全唐诗/poet.song.182000.json','["虛氣撐枯腹，長身到老貧。", "高吟常駭俗，爛醉若驕人。", "京洛繁華夢，江湖浩蕩春。", "布衣如雪白，不受庾公塵。"]'),
('ecc3049f-0d73-43ea-9ec6-08125e58e2c9','飲蕭和伯家醉登快閣和楊伯子題分明觀韵','戴復古','宋','宋诗','song-poetry','','[]','醉歸蕭史宅，快閣倚西東。',48,'全唐诗/poet.song.182000.json','["醉歸蕭史宅，快閣倚西東。", "山歛過雲雨，江無起浪風。", "月行銀漢上，人在玉壺中。", "天眼照塵世，應憐鶴髮翁。"]'),
('ef72caaf-d402-4159-b7f3-68e8156558d7','客中歲晚呈何宏甫','戴復古','宋','宋诗','song-poetry','','[]','歲事費料理，三杯意適然。',48,'全唐诗/poet.song.182000.json','["歲事費料理，三杯意適然。", "與其愁度日，曷若醉忘年。", "桑落冬前酒，梅花雪後天。", "不知身是客，多謝主人賢。"]'),
('19ad3ab9-d87b-46f4-8686-17a5b2a56b83','先人東皋子小園七言人多喜之浼秋房樓大卿作大字刻石','戴復古','宋','宋诗','song-poetry','','[]','父歿名隨泯，詩存世莫傳。',48,'全唐诗/poet.song.182000.json','["父歿名隨泯，詩存世莫傳。", "敢求大手筆，爲寫小園篇。", "詞翰成雙美，光華照九泉。", "托公垂不朽，鎸刻到千年。"]'),
('93c07cdf-229c-4f45-a3bf-29807b15555b','淮岸阻風','戴復古','宋','宋诗','song-poetry','','[]','艤棹楓林外，平沙步晚晴。',48,'全唐诗/poet.song.182000.json','["艤棹楓林外，平沙步晚晴。", "秋深紅鶴至，波動白鷗驚。", "荻浦留三日，江州計幾程。", "夜來風色好，行不待天明。"]'),
('886cfe9a-6098-47b9-8962-c99dd13d9731','蘄春李丈解后游江上園勸游人不可折花木禁漁弋者不捕禽魚酒邊談論可聽乃中洲先生之後葉水心嘗與往來','戴復古','宋','宋诗','song-poetry','','[]','坐斷此江干，池亭百烽寬。',48,'全唐诗/poet.song.182000.json','["坐斷此江干，池亭百烽寬。", "禽魚全性命，花竹報平安。", "有道行其志，非時做甚官。", "丰神更閒雅，野服竹皮冠。"]'),
('0c765c2a-e63d-412f-8a02-e1829eedd33f','南康縣劉隠居','戴復古','宋','宋诗','song-poetry','','[]','秋風送紈扇，終日御瑶琴。',48,'全唐诗/poet.song.182000.json','["秋風送紈扇，終日御瑶琴。", "祇可自爲樂，不求人賞音。", "無心問軒冕，此地即山林。", "堪笑紅塵客，飄零雪滿簪。"]'),
('b5c149e7-fcb0-46d2-98cd-8cfb063ba6d7','江皋','戴復古','宋','宋诗','song-poetry','','[]','江皋有閑客，獨立對秋風。',48,'全唐诗/poet.song.182000.json','["江皋有閑客，獨立對秋風。", "白鳥來無數，青林望不窮。", "斜陽方照晚，新月早騰空。", "得句從誰語，傾心酒椀中。"]'),
('4dd98b9f-51aa-4a49-aa19-094daaeb59fc','都下書懷','戴復古','宋','宋诗','song-poetry','','[]','半月不把鏡，羞看兩鬢塵。',48,'全唐诗/poet.song.182000.json','["半月不把鏡，羞看兩鬢塵。", "讀書增意氣，携刺減精神。", "道路誰推轂，江湖賦采蘋。", "從來麋鹿性，那作帝鄉人。"]'),
('1e15d010-f275-400d-93b2-9681db120677','艤舟登滕王閣','戴復古','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','散步登城郭，維舟古樹傍。',48,'全唐诗/poet.song.182000.json','["散步登城郭，維舟古樹傍。", "澄江浮野色，虛閣貯秋光。", "却酒淋衣濕，搓橙滿袖香。", "西風吹白髮，猶逐少年狂。"]'),
('e80dcc2b-b002-4e67-a23a-f7ca9d121dad','湖口','戴復古','宋','宋诗','song-poetry','','[]','水落山增峻，江空石出奇。',48,'全唐诗/poet.song.182000.json','["水落山增峻，江空石出奇。", "倚篷看不足，解纜放教遲。", "沙上鴈初到，樽前蟹可持。", "中秋能幾日，又是菊花時。"]'),
('5cdaeade-9e9c-4f5b-88ef-7f384b75d74b','夏日從子淵姪借茉莉一盆','戴復古','宋','宋诗','song-poetry','','[]','舉眼驚如許，衰懷强自安。',48,'全唐诗/poet.song.182000.json','["舉眼驚如許，衰懷强自安。", "愛凉臨水坐，遣病借花看。", "物物同天地，人人各肺肝。", "從來涇與渭，混作一流難。"]'),
('e24d4e12-58c1-4da3-8032-849d243cc46c','吳門訪舊夫侍郎有藏春園','戴復古','宋','宋诗','song-poetry','','[]','去此十三秋，重來雪滿頭。',48,'全唐诗/poet.song.182000.json','["去此十三秋，重來雪滿頭。", "鏡顔加老醜，詩骨带窮愁。", "鳥語新晴樹，人尋舊倚樓。", "藏春門下客，一半落山丘。"]'),
('e8006606-6b27-423c-a4ed-a91ffb187050','哭澗泉韓仲止二首  其一','戴復古','宋','宋诗','song-poetry','','[]','雅志不同俗，休官二十年。',48,'全唐诗/poet.song.182000.json','["雅志不同俗，休官二十年。", "隠居溪上宅，清酌澗中泉。", "慷慨傷時事，凄凉絕筆篇。", "三篇遣稿在，當並史書傳。"]'),
('e99e5d6b-8f11-4a60-9513-d4db8713d196','哭澗泉韓仲止二首  其二','戴復古','宋','宋诗','song-poetry','','[]','忍貧長傲世，風節似君稀。',48,'全唐诗/poet.song.182000.json','["忍貧長傲世，風節似君稀。", "死後女方嫁，峽中兒未歸。", "門人集詩藁，故卒服麻衣。", "澗上梅花發，吟魂何處飛。"]'),
('638395ed-b75f-4f56-a20e-03e30f654d84','瑯琊山中廢寺','戴復古','宋','宋诗','song-poetry','','[]','欲訪山中寺，沿堤石甃長。',48,'全唐诗/poet.song.182000.json','["欲訪山中寺，沿堤石甃長。", "寶坊兵後廢，御帖窖中藏。", "故址生秋草，寒窗带夕陽。", "孤僧出迎客，滿口話凄凉。"]'),
('eff7271c-f549-439b-81b5-32cc43e0d970','鄂州戎治靜憩亭','戴復古','宋','宋诗','song-poetry','','[]','幽亭何處尋，巖樹碧森森。',48,'全唐诗/poet.song.182000.json','["幽亭何處尋，巖樹碧森森。", "獨坐生雲石，少安經世心。", "伴人雙鶴立，多事一蟬吟。", "提劍翻然起，中原秋草深。"]'),
('49356c63-9d30-40cd-9624-14c783ffe8d6','江上','戴復古','宋','宋诗','song-poetry','','[]','江上維舟穩，人間行路難。',48,'全唐诗/poet.song.182000.json','["江上維舟穩，人間行路難。", "數朝花雨細，一夜社風寒。", "燕語能留客，蛙鳴豈爲官。", "苦吟成底事，贏得瘦團欒。"]'),
('41d328bd-c4d3-4c85-9df0-7e9a9922606a','趙端行杜子野游虎丘有詩僕因思舊與趙子野同宿唱和留題','戴復古','宋','宋诗','song-poetry','','[]','出城十里許，有此一山門。',48,'全唐诗/poet.song.182000.json','["出城十里許，有此一山門。", "丘在虎無迹，池清劍有痕。", "孤松冠巖頂，萬竹繞雲根。", "借問東軒壁，舊題存不存。"]'),
('3d7d57a8-7261-4dbb-b265-42b092241f9d','海陵光孝長老驥無稱山谷後也共談時事且說黄巖柑橘之美','戴復古','宋','宋诗','song-poetry','','[]','俗子避形影，僧家共往還。',48,'全唐诗/poet.song.182000.json','["俗子避形影，僧家共往還。", "高談犯時忌，妙語發天慳。", "霜後思新橘，夢中歸故山。", "何時免奔走，終老白雲關。"]'),
('1efbda26-8e73-4007-9dbb-8b69c4f8008a','杜仲高高九萬相會','戴復古','宋','宋诗','song-poetry','','[]','杜癖詩無敵，高髯畫絕倫。',48,'全唐诗/poet.song.182000.json','["杜癖詩無敵，高髯畫絕倫。", "笑談能不朽，富貴或成塵。", "今古多奇事，乾坤幾怪民。", "相逢不容易，一醉楚江濱。"]'),
('0ca15dc6-b74f-4ec1-9ea4-57871ae428a8','衡陽寫懷簡王景大趙俊卿','戴復古','宋','宋诗','song-poetry','','[]','夢覺他鄉枕，寒生半夜衾。',48,'全唐诗/poet.song.182000.json','["夢覺他鄉枕，寒生半夜衾。", "客程湖外遠，秋意雨中深。", "老馬尋歸路，羈鴉憶故林。", "家書連數紙，難寫此時心。"]'),
('14324084-a5e1-4e10-8449-3d4f3cf64ed5','懷趙德行','戴復古','宋','宋诗','song-poetry','','[]','所學源流遠，澹交滋味長。',48,'全唐诗/poet.song.182000.json','["所學源流遠，澹交滋味長。", "看來渾易與，別去自難忘。", "獨客夢千里，佳人天一方。", "細觀賓退錄，亦足慰凄凉。"]'),
('ea3f5ef6-dd6b-4288-ac98-119db27cbc9a','上封','戴復古','宋','宋诗','song-poetry','','[]','樓臺逼霄漢，窗戶納雲霓。',48,'全唐诗/poet.song.182000.json','["樓臺逼霄漢，窗戶納雲霓。", "回顧千巖路，如登萬仞梯。", "泉從山頂出，雪壓樹頭低。", "高絕無人境，非僧不可棲。"]'),
('9a299c9d-6eb4-4cca-861a-45e3e63f5be3','九日','戴復古','宋','宋诗','song-poetry','','[]','今日知何日，他鄉憶故鄉。',48,'全唐诗/poet.song.182000.json','["今日知何日，他鄉憶故鄉。", "黄花一杯酒，白髮幾重陽。", "日晚鴉爭宿，天寒鴈叫霜。", "客中無此醉，何以敵凄凉。"]'),
('99bb02e2-f03f-4bf8-a29a-965b75f01a62','舂陵道上','戴復古','宋','宋诗','song-poetry','','[]','雲際尋行路，時逢一兩家。',48,'全唐诗/poet.song.182000.json','["雲際尋行路，時逢一兩家。", "山川閑世界，耕釣小生涯。", "病竹長新笋，寒芒摇落花。", "溪翁解延客，連煮數杯茶。"]'),
('1b2a3ed7-4a73-40e7-820f-39f518e01e7a','化成巖','戴復古','宋','宋诗','song-poetry','','[]','城郭囂塵外，江山勝概中。',48,'全唐诗/poet.song.182000.json','["城郭囂塵外，江山勝概中。", "鏗然一灘水，和以萬松風。", "夾徑森奇石，危亭納太空。", "蒼巖不能語，曾識贊皇公。"]'),
('f694fef4-a3bf-44f7-a1b3-fc1b1652edb4','喜聞平峒寇','戴復古','宋','宋诗','song-poetry','','[]','峒寇都平了，官軍奏凱歌。',48,'全唐诗/poet.song.182000.json','["峒寇都平了，官軍奏凱歌。", "千山通道路，一雨洗干戈。", "天地和風轉，江湖春水多。", "蜀中無近報，西賊定如何。"]'),
('d3794a9f-8a55-4c6d-b419-a73e356cff22','郭伯秀約聯騎春游不去有詩','戴復古','宋','宋诗','song-poetry','','[]','心老尋春懶，年衰跨馬難。',48,'全唐诗/poet.song.182000.json','["心老尋春懶，年衰跨馬難。", "便能相强去，未必有真歡。", "獨酌三杯妙，高眠一枕安。", "好花如可折，覓取數枝看。"]'),
('039cc8c0-e24b-43ee-854a-0b6a9a5f3c19','訪陳復齋寺丞于私第','戴復古','宋','宋诗','song-poetry','','[]','以時爲出處，真有古人風。',48,'全唐诗/poet.song.182000.json','["以時爲出處，真有古人風。", "奉母易爲孝，事君難盡忠。", "閒居非傲世，直氣尚摩空。", "語及朝廷事，乾坤萬感中。"]'),
('05ef8707-50b2-47b0-ab35-d9559688b993','泉南','戴復古','宋','宋诗','song-poetry','','[]','南地無冰雪，常疑暖作災。',48,'全唐诗/poet.song.182000.json','["南地無冰雪，常疑暖作災。", "晝昏山霧合，寒變海風來。", "壠麥銜芒早，梅花带葉開。", "客中歸未得，歲事漸相催。"]'),
('dd6ce00d-8097-4dc0-a012-6671b5f8ebef','代人送別','戴復古','宋','宋诗','song-poetry','','[]','南浦春波碧，東風送客船。',48,'全唐诗/poet.song.182000.json','["南浦春波碧，東風送客船。", "別君楊柳外，揮淚杏花前。", "粉壁題詩句，金釵當酒錢。", "一聲離岸櫓，心碎楚江邊。"]'),
('68452d87-6264-4bf4-adaf-90d711a212eb','度淮','戴復古','宋','宋诗','song-poetry','','[]','一雨足秋意，孤吟寫客懷。',48,'全唐诗/poet.song.182000.json','["一雨足秋意，孤吟寫客懷。", "人情容易變，身事苦難諧。", "每日思歸浙，今朝却度淮。", "此生煩造物，畧畧爲安排。"]'),
('8a878153-6daa-4038-8b6c-8aa6512cc37c','蘄州厲使君七夕祈雨','戴復古','宋','宋诗','song-poetry','','[]','樽俎忘佳節，衣冠肅廣庭。',48,'全唐诗/poet.song.182000.json','["樽俎忘佳節，衣冠肅廣庭。", "爲民祈一雨，何暇賞雙星。", "五馬無慙德，三龍合效靈。", "前山好雲氣，早已動雷霆。"]'),
('65de549a-68f4-4a23-930e-6f870e07fd53','廬州界上寄豐帥','戴復古','宋','宋诗','song-poetry','','[]','身健心先老，時危事愈乖。',48,'全唐诗/poet.song.182000.json','["身健心先老，時危事愈乖。", "無成携短劍，有恨滿長淮。", "村酒時時醉，山肴日日齋。", "功名非我有，何處問生涯。"]'),
('b992316d-59cf-433e-a284-1ccf09eeb2a6','贈孤峰長老','戴復古','宋','宋诗','song-poetry','','[]','孤峰何處住，惠遠舊林泉。',48,'全唐诗/poet.song.182000.json','["孤峰何處住，惠遠舊林泉。", "日用無非道，心安即是禪。", "幽棲雲壑底，夢寐雪蓬邊。", "何日山陰道，同尋訪戴船。"]'),
('453376b6-5518-41d7-ac5f-269778ae34f5','吳子似','戴復古','宋','宋诗','song-poetry','','[]','載酒櫻桃熟，隈亭柳樹陰。',48,'全唐诗/poet.song.182000.json','["載酒櫻桃熟，隈亭柳樹陰。", "青山去人遠，黄鳥話春深。", "薄俗非吾道，虛名愧此心。", "休言今不古，又恐不如今。"]'),
('461f0efb-e01e-424d-bbfa-591ed84c1eb4','世事','戴復古','宋','宋诗','song-poetry','','[]','世事真如夢，人生不肯閑。',48,'全唐诗/poet.song.182000.json','["世事真如夢，人生不肯閑。", "利名雙轉轂，今古一凭欄。", "春水渡傍渡，夕陽山外山。", "吟邊思小范，共把此詩看。"]'),
('4f9153e9-481d-4be6-a176-f3bc204a0b1f','冬日移舟入峽避風','戴復古','宋','宋诗','song-poetry','','[]','棹入黄蘆浦，驚飛白鷺群。',48,'全唐诗/poet.song.182000.json','["棹入黄蘆浦，驚飛白鷺群。", "霜華濃似雪，水氣盛於雲。", "市遠炭增價，天寒酒策勳。", "同舟有佳士，擁被共論文。"]'),
('dadbe927-6b8e-4097-a849-87519a99d6f0','湖上','戴復古','宋','宋诗','song-poetry','','[]','久住人情熟，湖邊酒可賒。',48,'全唐诗/poet.song.182000.json','["久住人情熟，湖邊酒可賒。", "來時飛柳絮，今日見梅花。", "十載身爲客，幾封書到家。", "斜陽照林屋，獨立數棲鴉。"]'),
('56a645b0-c14c-43ed-8bfa-3f9c86aa681e','讀改元詔口號  其一','戴復古','宋','宋诗','song-poetry','','[]','伏讀改元詔，仍觀拜相麻。',48,'全唐诗/poet.song.182000.json','["伏讀改元詔，仍觀拜相麻。", "競傳新政事，方見好官家。", "雪作豐年瑞，梅開近臘花。", "路逢江上客，立馬問京華。"]'),
('013865c0-ae09-4c24-a6d8-03d33bf6bc6a','讀改元詔口號  其二','戴復古','宋','宋诗','song-poetry','','[]','喜見新除目，焚香洗眼看。',48,'全唐诗/poet.song.182000.json','["喜見新除目，焚香洗眼看。", "老儒居翰苑，正士作臺官。", "有道爲時用，非才處位難。", "寄聲崔與李，催促到長安。"]'),
('3dd4e51d-7845-4377-8d70-f7731570eb81','讀改元詔口號  其三','戴復古','宋','宋诗','song-poetry','','[]','國以人爲重，人惟德可招。',48,'全唐诗/poet.song.182000.json','["國以人爲重，人惟德可招。", "九重方厲政，諸老盡歸朝。", "盛事追三代，清風動百僚。", "切聞天上語，歡喜到漁樵。"]'),
('54b51ad9-2c55-4d57-b294-c160448cf51e','罪言','戴復古','宋','宋诗','song-poetry','','[]','盜賊干戈後，安知有太平。',48,'全唐诗/poet.song.182000.json','["盜賊干戈後，安知有太平。", "衆人皆競利，百姓不聊生。", "國用何能足，官曹未易清。", "漢家政虛耗，第一莫言兵。"]'),
('1ee94343-4b4e-4737-8350-b9c4006d9d43','李深道得蘇養直所寫深字韵詩','戴復古','宋','宋诗','song-poetry','','[]','表出塵埃外，濃薰蘭蕙香。',48,'全唐诗/poet.song.182000.json','["表出塵埃外，濃薰蘭蕙香。", "風流晉人物，高古漢文章。", "老眼不多見，前程豈易量。", "三杯話胸臆，一笑對雲驤。"]'),
('bde6eac6-c4e8-44fc-a3d0-e9e432a57c2b','秋興有感','戴復古','宋','宋诗','song-poetry','','[]','客游江海上，幾度見秋風。',48,'全唐诗/poet.song.182000.json','["客游江海上，幾度見秋風。", "遠浦蘆花白，疎林秋實紅。", "人情朝暮變，景物古今同。", "老眼猶明在，從教兩耳聾。"]'),
('1d53a71b-c79c-4d30-8c2f-6fa42d1fe86e','謝王使君送旅費','戴復古','宋','宋诗','song-poetry','','[]','風撼梅花雨，霧籠楊柳烟。',48,'全唐诗/poet.song.182000.json','["風撼梅花雨，霧籠楊柳烟。", "如何殘臘月，已似半春天。", "歲裏無多日，閩中過一年。", "黄堂解留客，時送賣詩錢。"]'),
('3949e77f-4e3c-4816-9e3b-139877790c95','舟中小酌','戴復古','宋','宋诗','song-poetry','','[]','獨立秋風裏，悵然思故鄉。',48,'全唐诗/poet.song.182000.json','["獨立秋風裏，悵然思故鄉。", "渚頭沽美酒，船上作重陽。", "籬菊一枝瘦，溪魚三寸長。", "客中聊爾耳，亦可慰凄凉。"]'),
('ee8ca471-a8a1-49d1-ab8f-e17a934c45ad','塗中見人家賣酒','戴復古','宋','宋诗','song-poetry','','[]','連歲遭饑饉，人無糴米錢。',48,'全唐诗/poet.song.182000.json','["連歲遭饑饉，人無糴米錢。", "今秋好行路，到處說豐年。", "村酒新篘濁，溪魚出網鮮。", "黄花留客醉，况近竹林邊。"]'),
('499b6d09-35f6-4f34-884a-23b652ad81e7','長汀寄李使君','戴復古','宋','宋诗','song-poetry','','[]','在處晚禾熟，經今瘴霧消。',48,'全唐诗/poet.song.182000.json','["在處晚禾熟，經今瘴霧消。", "山林無盜賊，道路有歌謠。", "人喜逢豐歲，誰知感聖朝。", "溪橋閑寓目，魚鳥亦逍遥。"]'),
('7535e8ed-10a2-4f9e-908e-6615b91622d9','光澤溪上','戴復古','宋','宋诗','song-poetry','','[]','艤棹西巖下，舟人語夜闌。',48,'全唐诗/poet.song.182000.json','["艤棹西巖下，舟人語夜闌。", "風林無鳥宿，石窟有龍蟠。", "月色連沙白，灘聲入夢寒。", "曉來新得句，寄與故人看。"]'),
('01794082-0b27-416a-b893-aa5f571761b5','約游曾參政西墅病不能去','戴復古','宋','宋诗','song-poetry','','[]','骨肉去家遠，異鄉童僕親。',48,'全唐诗/poet.song.182000.json','["骨肉去家遠，異鄉童僕親。", "老身渾頼汝，久病亦愁人。", "無暇遊西墅，尋醫訪北辰。", "主翁翻作使，奔走莫勞神。"]'),
('f47cc6d8-ae9f-4c6d-bf41-31011a0faaa3','趙敬賢送荔枝','戴復古','宋','宋诗','song-poetry','','[]','荔子固多種，色香俱不同。',48,'全唐诗/poet.song.182000.json','["荔子固多種，色香俱不同。", "新來嘗小綠，又勝擘輕紅。", "大嚼思千樹，分甘僅一籠。", "嘗觀蔡公譜，夢想到莆中。"]'),
('cb1c3370-70a4-4c66-94fb-0f46cd280f8f','自漳州回泉南主僕俱病','戴復古','宋','宋诗','song-poetry','','[]','雅興難忘酒，羈懷不耐秋。',48,'全唐诗/poet.song.182000.json','["雅興難忘酒，羈懷不耐秋。", "坐窮思賣劍，扶病强登樓。", "適有坐中客，來從邊上州。", "所談驚老耳，身世併成憂。"]'),
('9f70d681-0af1-4bbf-90e3-7d8435530e97','寄趙漳州話病','戴復古','宋','宋诗','song-poetry','','[]','聽雨無聊頼，高眠獨掩扉。',48,'全唐诗/poet.song.182000.json','["聽雨無聊頼，高眠獨掩扉。", "塞鴻書不到，海燕約同歸。", "吾道關通塞，人情有是非。", "荆州相別後，王粲更誰依。"]'),
('b52b6b73-a41a-4f2b-a2f3-b43e0533164e','客自邵武來言王野使君平寇  其一','戴復古','宋','宋诗','song-poetry','','[]','聞說賊來日，君能判死生。',48,'全唐诗/poet.song.182000.json','["聞說賊來日，君能判死生。", "扁舟載母去，倚劍到天明。", "百姓各逃命，四旁無援兵。", "王尊豈非勇，獨自守孤城。"]'),
('2a5fe60a-22ef-462b-9719-e0d813d5f4e2','客自邵武來言王野使君平寇  其二','戴復古','宋','宋诗','song-poetry','','[]','太守自監軍，片膽大如身。',48,'全唐诗/poet.song.182000.json','["太守自監軍，片膽大如身。", "立馬斬數賊，犒軍捐萬緡。", "威行千里外，手活一城民。", "孰謂書生怯，書生中有人。"]'),
('f493280f-dd02-43f0-b7b1-0d4aff44e296','新年自唱自和  其一','戴復古','宋','宋诗','song-poetry','','[]','聖朝開寶曆，淳祐四年春。',48,'全唐诗/poet.song.182000.json','["聖朝開寶曆，淳祐四年春。", "生自前丁亥，今逢兩甲辰。", "黄粱一夢覺，青鏡二毛新。", "七十八歲叟，乾坤有幾人。"]'),
('1730fc28-2d42-4a9f-9ca1-2fb12db7f421','新年自唱自和  其二','戴復古','宋','宋诗','song-poetry','','[]','死灰無復暖，槁木不逢春。',48,'全唐诗/poet.song.182000.json','["死灰無復暖，槁木不逢春。", "近日愁多病，今年歲在辰。", "處喧如處寂，求舊不求新。", "笑問長河水，誰爲不老人。"]'),
('ed20d0ca-be63-4075-aec0-d3821f8bdc68','新年自唱自和  其三','戴復古','宋','宋诗','song-poetry','','[]','江山一夜雨，花柳九州春。',48,'全唐诗/poet.song.182000.json','["江山一夜雨，花柳九州春。", "過節喜無事，謀懽要及辰。", "年年仍歲歲，故故復新新。", "把酒有餘恨，無從見古人。"]'),
('6b85cfd1-5b9b-45a8-bd38-9c289fbdc2d7','聞嚴坦叔入朝再用前韵  其一','戴復古','宋','宋诗','song-poetry','','[]','凄凉風雨日，强把甕頭春。',48,'全唐诗/poet.song.182000.json','["凄凉風雨日，强把甕頭春。", "獨守空虛室，那逢耗磨辰。", "詩家青眼舊，世路白頭新。", "每誦梅花句，一心思故人。"]'),
('df01d914-412f-48d9-bb64-e17fe4dc5fb5','聞嚴坦叔入朝再用前韵  其二','戴復古','宋','宋诗','song-poetry','','[]','我本江湖客，歸來二月春。',48,'全唐诗/poet.song.182000.json','["我本江湖客，歸來二月春。", "居多閉門日，未卜賞花辰。", "繞樹鵲聲喜，隔簾鶑語新。", "可憐垂白叟，却羨踏青人。"]'),
('715d7d3f-1c64-48ae-abf2-d3db0503720b','吾族兩派而下吾之一派衰落殆盡諸孫一兩人而已其勢不絕如綫彼之一派富盛一日出門有感','戴復古','宋','宋诗','song-poetry','','[]','門外長河水，有時鳴不平。',48,'全唐诗/poet.song.182000.json','["門外長河水，有時鳴不平。", "河邊古樟樹，亦各有枯榮。", "人事關時數，春風莫世情。", "賢哉滄海月，夜夜一般明。"]'),
('be041e79-034c-454e-ad93-666303714113','王深道奏名而歸','戴復古','宋','宋诗','song-poetry','','[]','忠言犯時忌，决不中高科。',48,'全唐诗/poet.song.182000.json','["忠言犯時忌，决不中高科。", "一日成名了，諸公屬望多。", "還家寧久住，經世欲如何。", "西澗一泓水，行通滄海波。"]'),
('0407929b-c9ff-4971-b5b7-51f0e351c311','朱仲寔少府到官無幾日即入僉幕官滿送行二首  其一','戴復古','宋','宋诗','song-poetry','','[]','才智人難及，上官能用賢。',48,'全唐诗/poet.song.182000.json','["才智人難及，上官能用賢。", "梅仙無一事，蓮幕坐三年。", "政譽傾千里，歸途仰二天。", "辟書聞早上，松菊莫留連。"]'),
('f3be4060-fac3-46a1-a7c6-2608a337d8f5','朱仲寔少府到官無幾日即入僉幕官滿送行二首  其二','戴復古','宋','宋诗','song-poetry','','[]','孝友平生事，守廉天下難。',48,'全唐诗/poet.song.182000.json','["孝友平生事，守廉天下難。", "居官一日俸，闔室幾人餐。", "病骨何妨瘦，吟肩不肯寒。", "功名未須問，且奉版輿安。"]'),
('bc4ebe1a-2982-4b60-bcbf-ea54fb0e6eaf','次韵旴江李君昉見寄二首時李在包守郡齋  其一','戴復古','宋','宋诗','song-poetry','','[]','久作丹丘客，疑君去復來。',48,'全唐诗/poet.song.182000.json','["久作丹丘客，疑君去復來。", "高吟闖風雅，妙句斲瓊瑰。", "道誼心千古，文章水一杯。", "荷花時話別，別後又梅開。"]'),
('3d131f01-555d-491b-a8de-bb52d769ca41','次韵旴江李君昉見寄二首時李在包守郡齋  其二','戴復古','宋','宋诗','song-poetry','','[]','共醉荆溪酒，不論杯淺深。',48,'全唐诗/poet.song.182000.json','["共醉荆溪酒，不論杯淺深。", "定交從此日，識面早知心。", "久缺寒溫問，忽聞長短吟。", "玉霄亭下路，幾夜夢相尋。"]'),
('fe39a487-5f38-43cd-a068-eed8fde953e4','感寓三首  其一','戴復古','宋','宋诗','song-poetry','','[]','古今通一理，趨鄉自多門。',48,'全唐诗/poet.song.182000.json','["古今通一理，趨鄉自多門。", "賢士玉成美，貪夫金注昏。", "誰知身是患，人以道爲尊。", "前輩□□死，姓名千載存。"]'),
('580b1bb2-198f-44a2-b076-2532fc7317eb','感寓三首  其二','戴復古','宋','宋诗','song-poetry','','[]','誼利不同道，盛衰何用疑。',48,'全唐诗/poet.song.182000.json','["誼利不同道，盛衰何用疑。", "布衣甘寂寞，紈袴自矜持。", "勿謂人爲巧，待觀天定時。", "銅山或餓死，富貴五羊皮。"]'),
('3f424b95-82a9-4d81-83a7-3af3024673fb','感寓三首  其三','戴復古','宋','宋诗','song-poetry','','[]','自覺心無愧，何須座右銘。',48,'全唐诗/poet.song.182000.json','["自覺心無愧，何須座右銘。", "人將金作塢，吾以石爲屏。", "年老醫難療，天寒酒易醒。", "菊花香到死，不肯就飄零。"]'),
('c46d199c-2c4e-4b08-a965-aae0659dd351','新歲書懷四首  其一','戴復古','宋','宋诗','song-poetry','','[]','衰年百病身，淳祐五年春。',48,'全唐诗/poet.song.182000.json','["衰年百病身，淳祐五年春。", "塵世自多事，風光又一新。", "鄉人方拜相，野客自垂綸。", "說與烟波侶，海濱非渭濱。"]'),
('01b330bd-2349-4604-b5e5-b3f80af7f85c','新歲書懷四首  其二','戴復古','宋','宋诗','song-poetry','','[]','七十九歲叟，時吟感寓詩。',48,'全唐诗/poet.song.182000.json','["七十九歲叟，時吟感寓詩。", "年高胡不死，身健欲何爲。", "細柳綠垂地，小桃紅滿枝。", "春風不到處，枯蔓掛疎籬。"]'),
('06163c04-dd7c-4360-920c-6bc935e321de','新歲書懷四首  其三','戴復古','宋','宋诗','song-poetry','','[]','老病從人笑，兒童識我誰。',48,'全唐诗/poet.song.182000.json','["老病從人笑，兒童識我誰。", "窮愁無地著，心事有天知。", "鵲噪緣何喜，蛙鳴豈爲私。", "如何得懷抱，長似醉眠時。"]'),
('041d7cde-6b91-4ec5-8c1c-53068c9857aa','新歲書懷四首  其四','戴復古','宋','宋诗','song-poetry','','[]','正月復二月，百年如一年。',48,'全唐诗/poet.song.182000.json','["正月復二月，百年如一年。", "世間人易老，天下事難全。", "生計麥十斛，傳家詩幾篇。", "眼前雖不足，心地自超然。"]'),
('92cc845a-3684-4b0c-b417-73fffeb3392a','小園','戴復古','宋','宋诗','song-poetry','','[]','小園春欲半，老子作兒嬉。',48,'全唐诗/poet.song.182000.json','["小園春欲半，老子作兒嬉。", "政喜花開蚤，還愁客到遲。", "詩當得意處，酒到半酣時。", "蜂蝶來無數，無知却有知。"]'),
('f385721a-aef4-465c-b08d-05dd6fab2902','爲石雲悼鶴','戴復古','宋','宋诗','song-poetry','','[]','瘞鶴有故事，花邊結小塋。',48,'全唐诗/poet.song.182000.json','["瘞鶴有故事，花邊結小塋。", "不登千歲壽，無復九皋鳴。", "問汝緣何死，主翁無限情。", "最令人憶處，側耳聽松聲。"]'),
('5aa16848-a8f2-4ee3-86af-957a7b9a5d72','挽立齋杜丞相','戴復古','宋','宋诗','song-poetry','','[]','邪正不兩立，國家當再興。',48,'全唐诗/poet.song.182000.json','["邪正不兩立，國家當再興。", "有時須有命，稱德不稱能。", "方喜千年遇，如何一旦薨。", "世間無哭處，吾欲哭昭陵。"]'),
('5f4614f8-862f-497e-8bbc-0dd6b6468c3e','蕭飛卿將使赴湖北戎幕詩送其行兼簡秋壑賈總侍二首  其一','戴復古','宋','宋诗','song-poetry','','[]','文章蕭頴士，一劍去從軍。',48,'全唐诗/poet.song.182000.json','["文章蕭頴士，一劍去從軍。", "遠望西關路，愁看兩浦雲。", "九霄騰意氣，萬里取功勳。", "馬上一杯酒，須斟滿十分。"]'),
('1a2fbdc5-a54e-4335-8593-e01f882e9b88','蕭飛卿將使赴湖北戎幕詩送其行兼簡秋壑賈總侍二首  其二','戴復古','宋','宋诗','song-poetry','','[]','鄂渚三千里，遥遥望使星。',48,'全唐诗/poet.song.182000.json','["鄂渚三千里，遥遥望使星。", "江湖今寂寞，桃李半凋零。", "世有一秋壑，時無兩石屏。", "平生不相遇，老眼向誰青。"]'),
('513c11e2-8b9b-41d2-9bbf-36eb156865e7','晚望懷長沙故人','戴復古','宋','宋诗','song-poetry','','[]','却扇清風起，樓頭坐晚凉。',48,'全唐诗/poet.song.182000.json','["却扇清風起，樓頭坐晚凉。", "青山連遠水，綠樹带斜陽。", "客路傷離別，人情果在亡。", "定應今夜夢，隨月到瀟湘。"]'),
('22dacd12-946a-41dd-ba08-a3a285a1ff3f','寄虛齋趙侍郎  其一','戴復古','宋','宋诗','song-poetry','','[]','老眼開還闔，愁懷醉不醒。',48,'全唐诗/poet.song.182000.json','["老眼開還闔，愁懷醉不醒。", "乾坤多變故，人物曉天星。", "藥石匡時切，蓍龜見事靈。", "得公十數輩，亦足壯朝廷。"]'),
('832b727f-21eb-4645-824d-f85dffb24091','寄虛齋趙侍郎  其二','戴復古','宋','宋诗','song-poetry','','[]','災異天垂戒，安危事可知。',48,'全唐诗/poet.song.182000.json','["災異天垂戒，安危事可知。", "試將黄雨證，請問白雲司。", "對客論孤憤，傷時賦五噫。", "醉中忘萬慮，安得酒如池。"]'),
('c9b57b52-7073-47d8-b188-e2d7b288d5e8','斗山子王深父作石屏記爲老夫書其文甚佳采記中語作五詩致謝  其一','戴復古','宋','宋诗','song-poetry','','[]','細讀石屏記，臨風覺厚顔。',48,'全唐诗/poet.song.182000.json','["細讀石屏記，臨風覺厚顔。", "如何一片石，欲比衆名山。", "浪迹江湖上，歸身巖壑間。", "漁樵爭半席，人笑老癡頑。"]'),
('c215f4f3-4873-4193-a78d-7af20f7451d7','斗山子王深父作石屏記爲老夫書其文甚佳采記中語作五詩致謝  其二','戴復古','宋','宋诗','song-poetry','','[]','細讀石屏記，誠然愧我心。',48,'全唐诗/poet.song.182000.json','["細讀石屏記，誠然愧我心。", "蘭蓀借芳馥，金石假聲音。", "俗子方騰謗，朋儔合獻箴。", "分爲無用物，白髮委山林。"]'),
('faa028a9-7dcd-4e96-95b2-282f4c888874','斗山子王深父作石屏記爲老夫書其文甚佳采記中語作五詩致謝  其三','戴復古','宋','宋诗','song-poetry','','[]','細讀石屏記，尋幽到水涯。',48,'全唐诗/poet.song.182000.json','["細讀石屏記，尋幽到水涯。", "老人相問答，屬意在巖花。", "江海浮天闊，山林去國賒。", "草茅最深處，認作野人家。"]'),
('20d723b8-87cb-4a7a-bfc9-d38f8b55daac','斗山子王深父作石屏記爲老夫書其文甚佳采記中語作五詩致謝  其四','戴復古','宋','宋诗','song-poetry','','[]','細讀石屏記，堪嗟老病身。',48,'全唐诗/poet.song.182000.json','["細讀石屏記，堪嗟老病身。", "誰知饑欲死，曷取壽長貧。", "雪片豐年瑞，梅花臘月春。", "今朝一杯酒，誰道是生辰。"]'),
('592fca24-6b11-4eb7-b993-bb2a039bb903','斗山子王深父作石屏記爲老夫書其文甚佳采記中語作五詩致謝  其五','戴復古','宋','宋诗','song-poetry','','[]','細讀石屏記，多君才思清。',48,'全唐诗/poet.song.182000.json','["細讀石屏記，多君才思清。", "南山數峰碧，北斗七星明。", "風土鍾奇秀，文章到老成。", "待看黄鵠舉，唾手取功名。"]'),
('ddc0bb36-6761-495c-8fa0-5b76c97530dc','寄建康留守制使趙用父都丞侍郎  其一','戴復古','宋','宋诗','song-poetry','','[]','蠻貊聞名姓，當今有此人。',48,'全唐诗/poet.song.182000.json','["蠻貊聞名姓，當今有此人。", "片心天共廣，一笑物爲春。", "花滿金陵路，風清玉塞塵。", "九重方簡注，四海望經綸。"]'),
('daeed91a-8939-48c3-90cd-1d3b09a8b82d','寄建康留守制使趙用父都丞侍郎  其二','戴復古','宋','宋诗','song-poetry','','[]','燕許文章筆，片言輕萬金。',48,'全唐诗/poet.song.182000.json','["燕許文章筆，片言輕萬金。", "先人十詩序，孝子一生心。", "入手方爲寶，三年等到今。", "九泉應有望，取璧照山林。"]'),
('d5b1e44f-96a7-4a2f-bb10-b8541cfa6c23','姪孫亦龍作亭于小山之上□余以野亭名之得詩五首  其一','戴復古','宋','宋诗','song-poetry','','[]','平地變丘壑，安排若自然。',48,'全唐诗/poet.song.182000.json','["平地變丘壑，安排若自然。", "爲山移白石，鑿沼貯清泉。", "栗里有松竹，蘭亭無管絃。", "軒裳非我事，在野不妨賢。"]'),
('33d2ec5e-dc2a-4f8e-b9db-eb8d5fc92889','姪孫亦龍作亭于小山之上□余以野亭名之得詩五首  其二','戴復古','宋','宋诗','song-poetry','','[]','蔡外有餘地，登臨作此亭。',48,'全唐诗/poet.song.182000.json','["蔡外有餘地，登臨作此亭。", "心如喬木古，眼共遠山清。", "社酒誰同醉，村歌自可聽。", "有時來夜坐，收拾讀書螢。"]'),
('e8f705a2-8246-4051-a0dc-8a1e52667ce4','姪孫亦龍作亭于小山之上□余以野亭名之得詩五首  其三','戴復古','宋','宋诗','song-poetry','','[]','詩禮家聲重，田園活計饒。',48,'全唐诗/poet.song.182000.json','["詩禮家聲重，田園活計饒。", "自甘爲野客，不願仕王朝。", "時爲花開眼，誰因米折腰。", "此心安出處，何日不逍遥。"]'),
('d0a2da19-129d-49e7-a144-c29508306316','姪孫亦龍作亭于小山之上□余以野亭名之得詩五首  其四','戴復古','宋','宋诗','song-poetry','','[]','勿謂此亭水，巋然氣不群。',48,'全唐诗/poet.song.182000.json','["勿謂此亭水，巋然氣不群。", "靜中觀變化，閑處立功勳。", "水細通巖竇，亭高壓海雲。", "隠居行素志，不負聖明君。"]'),
('62101743-95fe-4e8f-b0f6-0dab30f593ab','姪孫亦龍作亭于小山之上□余以野亭名之得詩五首  其五','戴復古','宋','宋诗','song-poetry','','[]','田間四五月，此景看來稀。',48,'全唐诗/poet.song.182000.json','["田間四五月，此景看來稀。", "翼翼青苗上，雙雙白鳥飛。", "茅茨林下住，簑笠雨中歸。", "拍岸瓜藤水，不須憂歲饑。"]'),
('16325830-2b25-4f67-b4ad-d366940a3b2b','寄鎮江王子文總卿','戴復古','宋','宋诗','song-poetry','','[]','一代文章手，官如水樣清。',48,'全唐诗/poet.song.182000.json','["一代文章手，官如水樣清。", "三軍皆飽德，諸將共談兵。", "鐵甕橫天立，金山壓浪平。", "北人向南望，□□月分明。"]'),
('ea766ad0-8ef8-45e6-b7f7-29be3cc310d4','又送行二首  其一','戴復古','宋','宋诗','song-poetry','','[]','荏苒歲云暮，雪霜天正寒。',48,'全唐诗/poet.song.182000.json','["荏苒歲云暮，雪霜天正寒。", "取程毋太急，御下放教寬。", "朝夕去家遠，關山行路難。", "邊頭辦功業，恐不在儒冠。"]'),
('c03fa935-8b2f-4eb2-86da-77f609e50113','又送行二首  其二','戴復古','宋','宋诗','song-poetry','','[]','荆門在何許，鄂渚小躊躇。',48,'全唐诗/poet.song.182000.json','["荆門在何許，鄂渚小躊躇。", "宿處好看劍，客中宜讀書。", "交遊天作合，江漢景何如。", "窗戶半天上，南樓好寓居。"]'),
('d7abc90a-fab3-4801-a3ba-13ada7afa318','送包使君入朝除左曹郎二首  其一','戴復古','宋','宋诗','song-poetry','','[]','宏齋儒者政，賞罰自宜民。',48,'全唐诗/poet.song.182000.json','["宏齋儒者政，賞罰自宜民。", "世欲無公論，天知有正人。", "側身觀宇宙，平步履星辰。", "試把安危事，從頭問化鈞。"]'),
('cb8170ed-dc36-4c49-90ae-eaa518c6cdda','送包使君入朝除左曹郎二首  其二','戴復古','宋','宋诗','song-poetry','','[]','金門行入奏，何以告君王。',48,'全唐诗/poet.song.182000.json','["金門行入奏，何以告君王。", "請下求賢詔，兼陳活國方。", "解紛□□□，救弊細思量。", "若見高常簿，言予病在床。"]'),
('91310336-d611-40e4-9776-af1efacfa10e','送季明府赴太平倅  其一','戴復古','宋','宋诗','song-poetry','','[]','黄巖號難治，能者治何難。',48,'全唐诗/poet.song.182000.json','["黄巖號難治，能者治何難。", "桃李民心悅，風霜吏膽寒。", "公行無不可，私請莫相干。", "三尺兒童輩，皆知好長官。"]'),
('ad22297f-ce1f-4567-a866-5a1e92aa401d','送季明府赴太平倅  其二','戴復古','宋','宋诗','song-poetry','','[]','人說陳胡蔡，合君爲四賢。',48,'全唐诗/poet.song.182000.json','["人說陳胡蔡，合君爲四賢。", "一廉官似水，三載吏無權。", "政自詩書出，民從教化遷。", "神明判事筆，一出萬人傳。"]'),
('4e9a4af3-bb02-49c6-98a4-72da91837a9d','送季明府赴太平倅  其三','戴復古','宋','宋诗','song-poetry','','[]','庭闈定省外，都是坐廳時。',48,'全唐诗/poet.song.182000.json','["庭闈定省外，都是坐廳時。", "盡日身無倦，對天心不欺。", "縣花潘岳賦，池草惠連詩。", "磨取九峰石，刊成德政碑。"]'),
('8f7bd5fe-e6be-4212-bd15-799064c8d160','送季明府赴太平倅  其四','戴復古','宋','宋诗','song-poetry','','[]','通守太平州，金陵在上頭。',48,'全唐诗/poet.song.182000.json','["通守太平州，金陵在上頭。", "風寒當一面，江□□千艘。", "此日要人物，九天寬顧憂。", "詩書用處別，澼絖換封侯。"]'),
('196f67ba-c86d-44dc-8aee-65f6e03b85ca','得古梅兩枝','戴復古','宋','宋诗','song-poetry','','[]','老幹百年久，從教花事遲。',48,'全唐诗/poet.song.182000.json','["老幹百年久，從教花事遲。", "似枯元不死，因病反成奇。", "玉破稀疎蕊，苔封古怪枝。", "誰能知我意，相對歲寒時。"]'),
('00c9ec9e-48fe-46af-8673-4d197b3c0988','貧作負恩人爲何宏甫作','戴復古','宋','宋诗','song-poetry','','[]','九陌塵中事，三生石上身。',48,'全唐诗/poet.song.182000.json','["九陌塵中事，三生石上身。", "狂爲好詩客，貧作負恩人。", "十載江村別，扁舟淦水濱。", "音書久不至，得夢往來頻。"]'),
('7be28fbb-7347-4d9a-b2a6-6b8ffe649a20','題徐子英小園','戴復古','宋','宋诗','song-poetry','','[]','奉親營小圃，僻在水之湄。',48,'全唐诗/poet.song.182000.json','["奉親營小圃，僻在水之湄。", "霜露蔡公賦，假山慈竹詩。", "人皆稱壽母，我獨喜佳兒。", "八行家風在，三遷憶舊時。"]'),
('0e854560-13a3-48d1-ad04-b21ee3461806','登祝融','戴復古','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋風吹拄杖，直到祝融顛。',48,'全唐诗/poet.song.182000.json','["秋風吹拄杖，直到祝融顛。", "目擊三千界，肩摩尺五天。", "扶桑暘谷畔，青草洞庭邊。", "雲氣無遮障，分明在眼前。"]'),
('8d562027-1bb3-40ab-945d-e3f0146e269a','長沙有感','戴復古','宋','宋诗','song-poetry','','[]','自飲長沙酒，春風幾醉醒。',48,'全唐诗/poet.song.182000.json','["自飲長沙酒，春風幾醉醒。", "江波隨意綠，山色爲誰青。", "鳥好因人好，龜靈不己靈。", "江蘺與杜若，何幸入騷經。"]'),
('9bbd5b34-871e-4192-9870-2b5b2ab8b743','山中少憩','戴復古','宋','宋诗','song-poetry','','[]','地僻人稀到，山寒水欲冰。',48,'全唐诗/poet.song.182000.json','["地僻人稀到，山寒水欲冰。", "聞鐘知有寺，見犬不逢僧。", "斷壠森喬木，頹簷掛古藤。", "斜陽照孤影，詩骨瘦崚嶒。"]'),
('6033b3dd-bb24-4348-ab2c-22b446291ba0','真州上官漕勸農','戴復古','宋','宋诗','song-poetry','','[]','小隊出行春，旌旗带野雲。',48,'全唐诗/poet.song.182000.json','["小隊出行春，旌旗带野雲。", "草成平寇檄，翻作勸農文。", "幕府多奇士，詩書策異勳。", "請將邊上事，一一奏明君。"]'),
('e8f92597-a755-4ffa-ae9e-c093e4175221','豫章東湖避暑  其一','戴復古','宋','宋诗','song-poetry','','[]','行坐自徜徉，吟聲遶屋梁。',48,'全唐诗/poet.song.182000.json','["行坐自徜徉，吟聲遶屋梁。", "曉烟滋柳色，晨露發荷香。", "以我一心靜，參他六月凉。", "淵明知此意，高卧到羲皇。"]'),
('6e5b6472-706d-41a3-8604-bd96ffb0ad1d','豫章東湖避暑  其二','戴復古','宋','宋诗','song-poetry','','[]','徧訪諸亭舘，蒼苔掩舊蹤。',48,'全唐诗/poet.song.182000.json','["徧訪諸亭舘，蒼苔掩舊蹤。", "十年如昨日，萬象又秋容。", "閲世存喬木，沿堤倚瘦筇。", "何人殺風景，斫盡木芙蓉。"]'),
('ba3b5310-7bd8-4636-a163-e43cde742fb4','見江東繡衣袁廣微','戴復古','宋','宋诗','song-poetry','','[]','宇宙歸微數，安危委大臣。',48,'全唐诗/poet.song.182000.json','["宇宙歸微數，安危委大臣。", "金門一回首，玉節久臨民。", "雅志思行古，清風不受塵。", "潔齋家學舊，用處日如新。"]'),
('a8466e86-2634-4109-8733-88272c9e2cbf','洪子中大卿同登遠碧樓歸來有詩','戴復古','宋','宋诗','song-poetry','','[]','角巾華屋下，丘壑在其旁。',48,'全唐诗/poet.song.182000.json','["角巾華屋下，丘壑在其旁。", "寄興青山遠，憂時白髮長。", "無心當世用，袖手看人忙。", "善自爲身計，須傳活國方。"]'),
('b04eb766-63d3-40ea-9e63-57cd4a094ecb','濠州春日呈趙教授','戴復古','宋','宋诗','song-poetry','','[]','柳似眠初起，梅雖老可觀。',48,'全唐诗/poet.song.182000.json','["柳似眠初起，梅雖老可觀。", "冰開春水活，風暖雪泥乾。", "得酒忘爲客，談詩不論官。", "無人知此意，一笑對黄冠。"]'),
('fd60caa8-ee73-420f-beb4-586bf6778249','訪古田劉無競','戴復古','宋','宋诗','song-poetry','','[]','前說建陽宰，古田今似之。',48,'全唐诗/poet.song.182000.json','["前說建陽宰，古田今似之。", "難兄與難弟，能政更能詩。", "文字定交久，江湖識面遲。", "人傳花萼集，俱受水心知。"]'),
('be75b570-7fad-47ff-93bd-b49bdfaabfc2','淮上回九江','戴復古','宋','宋诗','song-poetry','','[]','江水接淮水，扁舟去復回。',48,'全唐诗/poet.song.182000.json','["江水接淮水，扁舟去復回。", "客程官路柳，心事故園梅。", "活計魚千里，空言水一杯。", "石屏有茅屋，朝夕望歸來。"]'),
('2a14f99a-8121-4d30-abde-729f420a2f3a','送陳幼度運幹  其一','戴復古','宋','宋诗','song-poetry','','[]','臺幕三年最，雲霄萬里程。',48,'全唐诗/poet.song.182000.json','["臺幕三年最，雲霄萬里程。", "西山餞行色，南浦棹新晴。", "骨秀荆山璞，胸涵元氣英。", "更携扛鼎筆，祇合上蓬瀛。"]'),
('1abf5e4b-c7ca-46f0-b3a4-755fa9102ea6','送陳幼度運幹  其二','戴復古','宋','宋诗','song-poetry','','[]','君是青雲料，吾當白髮年。',48,'全唐诗/poet.song.182000.json','["君是青雲料，吾當白髮年。", "駑駘傍騏驥，魚鳥各天淵。", "他日難忘處，寒宵不忍眠。", "挑燈雪窗下，共讀鴈奴篇。"]'),
('11511d83-7c3f-4032-bb84-3bb75196aa9b','燕','戴復古','宋','宋诗','song-poetry','','[]','聞說烏衣國，低連海上村。',48,'全唐诗/poet.song.182000.json','["聞說烏衣國，低連海上村。", "春來避霜雪，秋去長兒孫。", "華屋語如訴，故巢多不存。", "雙飛惱幽獨，紅袖有啼痕。"]'),
('035e80fd-80bc-41f9-a8ce-53e6bf03e759','蘄口阻風務官點稅','戴復古','宋','宋诗','song-poetry','','[]','江漲行無路，西風又打頭。',24,'全唐诗/poet.song.182000.json','["江漲行無路，西風又打頭。", "頗聞商婦怨，自作賈胡愁。"]'),
('07bce176-9601-473f-8e8b-6bd6e21a0519','郭外翁','戴復古','宋','宋诗','song-poetry','','[]','郭外生涯少，城中糴米歸。',48,'全唐诗/poet.song.182000.json','["郭外生涯少，城中糴米歸。", "種花無處賣，挑菜入籃稀。", "風撼傾欹屋，寒生藍縷衣。", "此翁何所樂，談笑傲輕肥。"]'),
('5624b4a9-7566-438d-a1e5-5e82d07a9af3','鄭南夫雲林隠居','戴復古','宋','宋诗','song-poetry','','[]','一來陪勝踐，再到惜蹉跎。',48,'全唐诗/poet.song.182000.json','["一來陪勝踐，再到惜蹉跎。", "記得山中景，行尋竹外坡。", "天寒梅信早，海近鴈聲多。", "烟渚蒲洲外，時聞欵乃歌。"]'),
('bd21134a-228f-4c6b-8458-8c0e77db7db5','夢與趙用父王子文陳叔方相會甚款','戴復古','宋','宋诗','song-poetry','','[]','鼎足當州縣，別來音問稀。',48,'全唐诗/poet.song.182000.json','["鼎足當州縣，別來音問稀。", "故人俱顯達，吾道亦光輝。", "三鳳夢中見，孤鴻天外飛。", "應憐江海客，白首未成歸。"]'),
('291b7d27-3300-47cd-bfec-4e1eced29c37','戲呈趙明府','戴復古','宋','宋诗','song-poetry','','[]','堂堂附郭縣，深遠半如村。',48,'全唐诗/poet.song.182000.json','["堂堂附郭縣，深遠半如村。", "能共斯民樂，渾忘太守尊。", "梅花高可折，橫浦撓無渾。", "欠與詩狂者，清談共一樽。"]'),
('272ccfa1-7d6e-4c67-a703-7654f0aff7d5','訪曾雲巢','戴復古','宋','宋诗','song-poetry','','[]','一老今無恙，諸公昔與儔。',48,'全唐诗/poet.song.182000.json','["一老今無恙，諸公昔與儔。", "隨時難苟合，懷道早歸休。", "苦似陶元亮，全如秦少游。", "筆端鋒銳別，有待續春秋。"]'),
('29cd2088-9409-44ba-98d2-29528ccdb2b0','冬暖','戴復古','宋','宋诗','song-poetry','','[]','天不雨霜雪，朝曦與暮霞。',48,'全唐诗/poet.song.182000.json','["天不雨霜雪，朝曦與暮霞。", "江梅遲臘蕊，巖桂更冬花。", "地暖宜爲客，時難重憶家。", "楚山當晚眺，歸興逐棲鴉。"]'),
('5a493016-1b60-4f91-9986-afc0ffa0e88a','許提幹湖上下築','戴復古','宋','宋诗','song-poetry','','[]','才氣有如許，功名不可無。',48,'全唐诗/poet.song.182000.json','["才氣有如許，功名不可無。", "樂從閑歲月，養就大規模。", "雅志難諧俗，幽居喜並湖。", "君看蓮下藕，不與葉同枯。"]'),
('bde92f2f-9c0a-4a5b-a5e5-7e2546dd8be2','見名園荒廢有感','戴復古','宋','宋诗','song-poetry','','[]','喬木無留影，殘花尚假妍。',48,'全唐诗/poet.song.182000.json','["喬木無留影，殘花尚假妍。", "荒池蛙叫噪，破屋燕周旋。", "富貴偏多事，風流得幾年。", "牆東有寒士，書種世相傳。"]'),
('177c1d8d-5d31-456e-8758-615e2018e5c5','題黄仲文雙清亭','戴復古','宋','宋诗','song-poetry','','[]','亭下新池好，亭中古意存。',48,'全唐诗/poet.song.182000.json','["亭下新池好，亭中古意存。", "欲通溪上路，遂闢竹邊門。", "自昔好賓客，相傳到子孫。", "會看司命鶴，時到種瓜園。"]'),
('8a7f343e-8834-48f3-9e14-01c189889eab','靜寄孟運管招客皆藏春侍郎故人因與花翁孫季蕃話舊有感','戴復古','宋','宋诗','song-poetry','','[]','來訪藏春宅，因登靜寄堂。',48,'全唐诗/poet.song.182000.json','["來訪藏春宅，因登靜寄堂。", "異香薰寶鼎，清樂送瑶觴。", "穿竹過花所，尋梅見海棠。", "白頭思往事，無語立斜陽。"]'),
('bd8f3d9f-0900-44b2-aad5-8739c95be282','莆中遇方□□邀出城買蠣而飲一僧同行','戴復古','宋','宋诗','song-poetry','','[]','出郭斷虹雨，倚樓新鴈天。',48,'全唐诗/poet.song.182000.json','["出郭斷虹雨，倚樓新鴈天。", "三盃古榕下，一笑菊花前。", "入市子魚貴，堆盤牡蠣鮮。", "山僧慣蔬食，清坐莫流涎。"]'),
('8f2fc235-f21b-411f-82ac-435a71dcd1c4','天竺訪明上座','戴復古','宋','宋诗','song-poetry','','[]','顧影良堪笑，胡爲八尺長。',48,'全唐诗/poet.song.182000.json','["顧影良堪笑，胡爲八尺長。", "蒼顔抗塵土，餓喙說興亡。", "竹雨先秋爽，松風生夜凉。", "愛尋湖上寺，留宿贊公房。"]'),
('4a586205-db46-4332-aab2-7e1a67c34220','隆興度夏借東湖驛安下','戴復古','宋','宋诗','song-poetry','','[]','面對一池荷，四旁楊柳坡。',48,'全唐诗/poet.song.182000.json','["面對一池荷，四旁楊柳坡。", "樹陰遮日少，屋敞受風多。", "疑是清凉國，暫爲安樂窩。", "人人爭避暑，老子自婆娑。"]'),
('67bf6018-192d-44bd-9053-026995daa556','挽趙縣尉','戴復古','宋','宋诗','song-poetry','','[]','十竹相依住，一官真漫爲。',48,'全唐诗/poet.song.182000.json','["十竹相依住，一官真漫爲。", "狂來裂軒冕，窮不顧妻兒。", "疾世吟孤憤，傷時賦五噫。", "高名應不朽，自作墓中碑。"]'),
('4f2976ab-958a-4132-be74-53dcb3683d70','張統制之子爲父求詩蘄州城破匹馬打圍而出能知數謂時不可爲','戴復古','宋','宋诗','song-poetry','','[]','夜半金城破，身隨鐵馬飛。',48,'全唐诗/poet.song.182000.json','["夜半金城破，身隨鐵馬飛。", "橫揮三尺劍，突出萬人圍。", "勇銳資神力，功名與願違。", "自能占氣數，終老著農衣。"]'),
('f3f58c22-dbf6-4443-81d9-0fea512e7a15','挽趙縣丞','戴復古','宋','宋诗','song-poetry','','[]','雅志思行古，幽居不愛官。',48,'全唐诗/poet.song.182000.json','["雅志思行古，幽居不愛官。", "傾家爲義舉，竭力奉親歡。", "閲世開天鏡，藏身作瓦棺。", "聞知捐舘日，有夢跨金鞍。"]'),
('775fdd6a-af65-4935-a327-e27b2f4bc794','挽沙溪項公苔湖居士  其一','戴復古','宋','宋诗','song-poetry','','[]','讀書不成事，何恨老山林。',48,'全唐诗/poet.song.182000.json','["讀書不成事，何恨老山林。", "處世有容德，與人無諍心。", "友于兄弟樂，惠彼里閭深。", "細把豐碑讀，懷賢淚滿襟。"]'),
('7be362a7-ac30-4b68-b9e2-ee9b666e61dc','挽沙溪項公苔湖居士  其二','戴復古','宋','宋诗','song-poetry','','[]','一曲苔湖上，深居萬竹間。',50,'全唐诗/poet.song.182000.json','["一曲苔湖上，深居萬竹間。", "自尋三徑樂，早得一身閑。", "异常异常循除水，林林夾屋山。", "傷心白雲際，遺跡尚班班。"]'),
('eb97494f-d171-41bb-b9a4-2137c44b91b6','挽大溪姚祥叔即南','戴復古','宋','宋诗','song-poetry','','[]','慶門今獨盛，舊族有光華。',48,'全唐诗/poet.song.182000.json','["慶門今獨盛，舊族有光華。", "日坐不欺室，天興積善家。", "山林娛晚境，書史是生涯。", "手種堂前桂，君看身後花。"]'),
('81ba8c5b-9bc7-46e3-b2c0-285920ef569c','挽唐吉林詠道','戴復古','宋','宋诗','song-poetry','','[]','博雅林夫子，隠居城市中。',48,'全唐诗/poet.song.182000.json','["博雅林夫子，隠居城市中。", "家貧書甚富，學苦字尤工。", "四海交名勝，諸文辨異同。", "阿戎談更好，端不負家風。"]'),
('31e18f6a-c74a-4fe8-8aca-bbbbe1c33d5c','黎明府見示令叔顯謨開國墓誌求詩爲賦三首  其一','戴復古','宋','宋诗','song-poetry','','[]','巴蜀何多事，賢能見一時。',48,'全唐诗/poet.song.182000.json','["巴蜀何多事，賢能見一時。", "纔爲花縣宰，早受菊坡知。", "關外科民急，興元易帥遲。", "預曾陳利病，人不信蓍龜。"]'),
('a7e76859-a624-4d82-a020-040dd05378e0','黎明府見示令叔顯謨開國墓誌求詩爲賦三首  其二','戴復古','宋','宋诗','song-poetry','','[]','虜橫干戈密，官清財賦强。',48,'全唐诗/poet.song.182000.json','["虜橫干戈密，官清財賦强。", "饑年無餓莩，亂後有金湯。", "五郡樹佳政，諸公交薦章。", "忠言動天聽，惜去把麾忙。"]'),
('7a0c62aa-85f0-4901-9baf-a4b0460dbce8','黎明府見示令叔顯謨開國墓誌求詩爲賦三首  其三','戴復古','宋','宋诗','song-poetry','','[]','寄家苕霅上，萬里故鄉愁。',48,'全唐诗/poet.song.182000.json','["寄家苕霅上，萬里故鄉愁。", "未入金門奏，還爲玉局遊。", "孤忠徒耿耿，一病竟休休。", "爲國惜人物，凄然老淚流。"]'),
('2092f489-7a6c-4030-9a03-66f118ed0dde','族姪孫子榮之子神童顔老不幸短命而死哭之不足三詩以悼之  其一','戴復古','宋','宋诗','song-poetry','','[]','亙古英靈在，顔回有後身。',48,'全唐诗/poet.song.182000.json','["亙古英靈在，顔回有後身。", "年纔十三歲，才過萬千人。", "學到由天悟，文高見理真。", "再生仍再夭，無路問鴻鈞。"]'),
('faff5e00-88e4-4e44-a57d-dbd38c28f29a','族姪孫子榮之子神童顔老不幸短命而死哭之不足三詩以悼之  其二','戴復古','宋','宋诗','song-poetry','','[]','昨應童科日，群兒立下風。',48,'全唐诗/poet.song.182000.json','["昨應童科日，群兒立下風。", "丰姿傾衆目，文采動諸公。", "兩耳能兼聽，六經皆暗通。", "相期到楊晏，有始柰無終。"]'),
('961818e5-afa0-43fd-bf77-c586912aed90','族姪孫子榮之子神童顔老不幸短命而死哭之不足三詩以悼之  其三','戴復古','宋','宋诗','song-poetry','','[]','汝祖積陰德，汝翁多讀書。',48,'全唐诗/poet.song.182000.json','["汝祖積陰德，汝翁多讀書。", "汝生天報施，汝死又何如。", "脩短有定數，賢愚莫問渠。", "冥官聞慟哭，還許再來無。"]'),
('0b9cf39e-e2a5-4414-bcfc-41becb7e0693','孫季蕃死諸朝士葬之於西湖之上','戴復古','宋','宋诗','song-poetry','','["\u897f\u6e56"]','卜宅西湖上，花翁死亦榮。',48,'全唐诗/poet.song.182000.json','["卜宅西湖上，花翁死亦榮。", "詼諧老方朔，曠達醉淵明。", "風月生前夢，歌詩身後名。", "風流不可見，腸斷玉簫聲。"]'),
('9b6cf936-49df-45fe-aaa3-9dd5141291d0','櫻桃','戴復古','宋','宋诗','song-poetry','','[]','綠樹带朱實，驅禽費彈丸。',48,'全唐诗/poet.song.182000.json','["綠樹带朱實，驅禽費彈丸。", "獨先諸果熟，堪奉五侯餐。", "猩肉和瓊液，蠙珠走玉盤。", "同時得同賞，芍藥滿雕欄。"]'),
('70fa953d-947e-43ed-ad86-ffb509c5278a','題清江臺','戴復古','宋','宋诗','song-poetry','','[]','秋色無邊際，酬之以醉顔。',48,'全唐诗/poet.song.182000.json','["秋色無邊際，酬之以醉顔。", "亭高俯城郭，木闕見江山。", "勝踐園林古，好詩天地慳。", "范碑生羽翼，飛上畫屏間。"]'),
('4e017eb2-9527-49c9-a14a-28a4be1594ee','江西壬辰秋大旱饑臨江守王幼學監簿極力救民癸巳夏不雨幾成荐餓監簿禱之甚切終有感於天  其一','戴復古','宋','宋诗','song-poetry','','[]','懇切金章奏，精誠玉帝知。',48,'全唐诗/poet.song.182000.json','["懇切金章奏，精誠玉帝知。", "稻粱民性命，豐歉國安危。", "苗秀方成實，雨來還及時。", "人能合天意，天亦順人爲。"]'),
('ff266396-4793-4f96-a50d-63c1432b256f','江西壬辰秋大旱饑臨江守王幼學監簿極力救民癸巳夏不雨幾成荐餓監簿禱之甚切終有感於天  其二','戴復古','宋','宋诗','song-poetry','','[]','天續饑民命，神知太守心。',48,'全唐诗/poet.song.182000.json','["天續饑民命，神知太守心。", "驕暘化霖雨，六月借春陰。", "早稻先秋熟，晚田儲水深。", "去年饑欲死，不料到于今。"]'),
('fe1e59e1-0f31-41ac-a572-d733cc04a99b','懷何宏甫','戴復古','宋','宋诗','song-poetry','','[]','何郎好兄弟，愛我往來頻。',48,'全唐诗/poet.song.182000.json','["何郎好兄弟，愛我往來頻。", "人作交游看，情如骨肉親。", "茅庵思共隠，蕙帳暖生春。", "別後長相憶，寄書無便人。"]'),
('60585e24-6702-4f04-8904-81351be2b47e','題董侍郎山園','戴復古','宋','宋诗','song-poetry','','[]','行盡芙蓉徑，尋秋扣竹關。',48,'全唐诗/poet.song.182000.json','["行盡芙蓉徑，尋秋扣竹關。", "樓高納萬象，木落見群山。", "平野水雲際，畫橋烟雨間。", "紅塵城下路，只隔一湖灣。"]'),
('034a5fd3-fc5a-4307-8063-c3a8247a05d1','蕭仲有遺經堂','戴復古','宋','宋诗','song-poetry','','[]','一經傳世寶，說與子孫知。',48,'全唐诗/poet.song.182000.json','["一經傳世寶，說與子孫知。", "欲作久長計，毋忘禮義爲。", "黄金生悔吝，白璧有瑕疵。", "兼取龐公語，圖安不遺危。"]'),
('4863ca62-77ac-4746-a0db-583cfb05757a','讀嚴粲詩風撼瀟湘覆江空雪月明以其一聯隠括爲對','戴復古','宋','宋诗','song-poetry','','[]','筆端有神助，句法自天成。',48,'全唐诗/poet.song.182000.json','["筆端有神助，句法自天成。", "風撼瀟湘覆，江空雪月明。", "苦吟非草草，妙趣若平平。", "李杜詩壇上，爲君題姓名。"]'),
('cca8999f-79e4-485c-83b9-d16faf4dfe25','舂陵山中','戴復古','宋','宋诗','song-poetry','','[]','地僻民風古，雨晴天氣新。',48,'全唐诗/poet.song.182000.json','["地僻民風古，雨晴天氣新。", "空山豎奇石，喬木墮枯薪。", "深入千崖路，多逢百歲人。", "繁華凋性命，寂寞可全真。"]'),
('5d4921ff-b9c9-45f7-bbce-4f85e9131bee','淮上寄趙茂實','戴復古','宋','宋诗','song-poetry','','[]','渺渺長淮路，秋風落木悲。',48,'全唐诗/poet.song.182000.json','["渺渺長淮路，秋風落木悲。", "乾坤限南北，胡虜迭興衰。", "志士言機會，中原入夢思。", "江湖好山色，都在夕陽時。"]'),
('2be73a0e-72e5-4c63-8919-bc7ff628e61f','金山','戴復古','宋','宋诗','song-poetry','','[]','水湧孤峰出，波深日夜聞。',48,'全唐诗/poet.song.182000.json','["水湧孤峰出，波深日夜聞。", "重巖戍鐵屋，雙塔礙行雲。", "天地八窗迥，江淮兩岸分。", "登臨多感慨，北鴈又成群。"]'),
('7ba2fb74-eec9-446d-8442-bb02ffb25720','焦山','戴復古','宋','宋诗','song-poetry','','[]','江接海冥冥，山連島樹青。',48,'全唐诗/poet.song.182000.json','["江接海冥冥，山連島樹青。", "似非人境界，宜有佛宮庭。", "藏壓蟠龍宅，潮渰瘞鶴銘。", "西巖更清絕，心與酒俱醒。"]'),
('230e9b05-9df0-4557-8046-6659f307abe6','梅花','戴復古','宋','宋诗','song-poetry','','[]','細把南枝看，百花無此奇。',48,'全唐诗/poet.song.182000.json','["細把南枝看，百花無此奇。", "夜深鍾月魄，□□□□□。", "古樹龍其似，寒香蝶不知。", "幽蘭開亦早，二妙喜同時。"]'),
('b4aa9280-fcd0-435e-917c-e61c563eeded','赤壁','戴復古','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','千載周公瑾，如其在目前。',48,'全唐诗/poet.song.182000.json','["千載周公瑾，如其在目前。", "英風揮羽扇，烈火破樓船。", "白鳥滄波上，黄州赤壁邊。", "長江酹明月，更憶老坡仙。"]'),
('2182e80c-8297-4b99-bbb7-5dfe8e989381','曾雲巢年八十聰明不衰小楷寫六經家有小樓日登覽不倦諸監司嘗薦遺逸','戴復古','宋','宋诗','song-poetry','','[]','八十雲巢老，諸公舊典刑。',48,'全唐诗/poet.song.182000.json','["八十雲巢老，諸公舊典刑。", "心情古井水，輩行曉天星。", "身健登高閣，眼明書六經。", "嘗聞薦遺逸，何以報朝廷。"]'),
('b1b964df-e217-4ad1-8e4a-476cd2d9b8c5','醉吟','戴復古','宋','宋诗','song-poetry','','[]','一狂兼一懶，窮到白頭年。',48,'全唐诗/poet.song.182000.json','["一狂兼一懶，窮到白頭年。", "客路偏躭酒，詩囊不貯錢。", "吟邊忘世故，醉裏樂吾天。", "不答諸公問，何如孟浩然。"]'),
('af764e34-726e-45e5-88f5-128460ec35f0','次韵胡公權','戴復古','宋','宋诗','song-poetry','','[]','日用無非道，人心實在平。',48,'全唐诗/poet.song.182000.json','["日用無非道，人心實在平。", "果能行實學，何必問虛名。", "草木隨時態，江山無世情。", "晚來溪雨歇，一段夕陽明。"]'),
('b141683c-f873-4b65-bde8-caed2023143e','同安子順訪茅庵道人鳳凰麒麟不可見道人語也','戴復古','宋','宋诗','song-poetry','','[]','道者日高卧，清風隔世塵。',48,'全唐诗/poet.song.182000.json','["道者日高卧，清風隔世塵。", "鳳麟不可見，猿鳥自相親。", "山木輪囷古，茶花冷淡春。", "草荒門外路，常怕有來人。"]'),
('77dbb2e5-590c-4321-a9cf-5abe0e44d76c','法曹羅立之酒邊舉數首皆僕故人爲我寄聲','戴復古','宋','宋诗','song-poetry','','[]','佳士欣相識，吟邊問姓名。',48,'全唐诗/poet.song.182000.json','["佳士欣相識，吟邊問姓名。", "官爲三語掾，詩到五言城。", "野客可憐我，故人煩寄聲。", "白頭歸故隠，秋後會群英。"]'),
('27c04bef-220c-4963-be32-647491e72815','爲客','戴復古','宋','宋诗','song-poetry','','[]','琴劍長爲客，詩書欠策勳。',48,'全唐诗/poet.song.182000.json','["琴劍長爲客，詩書欠策勳。", "老來臨鏡懶，愁裏把盃勤。", "北鴈寒離塞，秋鷹健拂雲。", "物情能奮發，人不解超群。"]'),
('b4afba19-a0c7-4907-877f-1b873db03695','彭繡使平叛卒後除經略小詩陳利害  其一','戴復古','宋','宋诗','song-poetry','','[]','廣東經略使，今古幾人賢。',48,'全唐诗/poet.song.182000.json','["廣東經略使，今古幾人賢。", "陛下用一士，民間有二天。", "清風排瘴雨，廉德照貪泉。", "龍節生光彩，鸞車奏凱旋。"]'),
('d59be7a4-e693-4196-85d9-c47c60fa6ec4','彭繡使平叛卒後除經略小詩陳利害  其二','戴復古','宋','宋诗','song-poetry','','[]','斬蛟移鰐後，近水有驚鱗。',48,'全唐诗/poet.song.182000.json','["斬蛟移鰐後，近水有驚鱗。", "閫外尚多事，幕中無一人。", "佩韋防狷急，强飯養精神。", "羅致賢能士，仍須藻鑑真。"]'),
('77f3a71c-f50b-4c1a-b297-1d2384de66dc','彭繡使平叛卒後除經略小詩陳利害  其三','戴復古','宋','宋诗','song-poetry','','[]','乳虎戀巢穴，窮猿失木悲。',48,'全唐诗/poet.song.182000.json','["乳虎戀巢穴，窮猿失木悲。", "早須思一著，先要釋群疑。", "豪傑通心腹，人民無怨咨。", "御軍明紀律，威愛貴兼施。"]'),
('13a22bee-fc80-4fa4-bdf3-f3ef3f6314cf','會李擇之其父名丙字南仲著丁未錄丙申錄','戴復古','宋','宋诗','song-poetry','','[]','吟邊逢李白，談笑亦風流。',48,'全唐诗/poet.song.182000.json','["吟邊逢李白，談笑亦風流。", "相對各青眼，安知有白頭。", "兩家窮活計，四海老交游。", "不負雲山約，同登百尺樓。"]'),
('2efd4535-b7f6-41ab-9d5b-31296123a301','道傍館','戴復古','宋','宋诗','song-poetry','','[]','道傍誰氏舘，□我坐開樽。',48,'全唐诗/poet.song.182000.json','["道傍誰氏舘，□我坐開樽。", "翁嫗出迎客，兒童爲掃門。", "好花生竹所，流水浸雲根。", "儻遂卜隣約，爲農老此村。"]'),
('7e6a4741-5a31-47e2-9961-06ac3b2c52b0','山中夜歸','戴復古','宋','宋诗','song-poetry','','[]','落盡一林月，山中夜半歸。',48,'全唐诗/poet.song.182000.json','["落盡一林月，山中夜半歸。", "驚行群犬吠，破暗一螢飛。", "舉我赤藤杖，敲君白板扉。", "興來眠不得，吟到曉星稀。"]'),
('89206120-fe2d-48ee-93b3-4ecaa20321c1','題春山李基道小園','戴復古','宋','宋诗','song-poetry','','[]','瀟灑數椽屋，旋營花竹坡。',48,'全唐诗/poet.song.182000.json','["瀟灑數椽屋，旋營花竹坡。", "心寬忘地窄，亭小得山多。", "共賞春晴好，其如客醉何。", "棲鸞將遠舉，寧久盼庭柯。"]'),
('8ecc124f-7de8-40c3-a5ee-cb5c3844372d','東軒','戴復古','宋','宋诗','song-poetry','','[]','東軒亦瀟灑，春晚雨晴時。',48,'全唐诗/poet.song.182000.json','["東軒亦瀟灑，春晚雨晴時。", "喜鵲立門限，飛花落硯池。", "青山解留客，綠竹遍題詩。", "一點歸心動，夜來聞子規。"]'),
('6a497bfc-534d-43db-a705-8a33f7d8d83e','宿農家','戴復古','宋','宋诗','song-poetry','','[]','宿此屋頭閣，瓦窗通月明。',48,'全唐诗/poet.song.182000.json','["宿此屋頭閣，瓦窗通月明。", "夜深鸜鵒噪，人靜桔槔聲。", "村落有古意，田園關客情。", "儒衣成底事，所得是虛名。"]'),
('59958bf2-227f-40b6-948e-5d24f386b953','寄耒陽令嚴坦叔','戴復古','宋','宋诗','song-poetry','','[]','士元堂上坐，千載仰清規。',48,'全唐诗/poet.song.182000.json','["士元堂上坐，千載仰清規。", "百里宜民政，數篇懷古詩。", "江連杜甫墓，水落蔡倫池。", "公暇登臨處，寧無憶我時。"]'),
('b0e8bb00-b6c8-469f-a935-adaa87945ac2','所聞','戴復古','宋','宋诗','song-poetry','','[]','今虜既亡後，中間消息稀。',48,'全唐诗/poet.song.182000.json','["今虜既亡後，中間消息稀。", "山河誰是主，豪傑故乘機。", "喜報三京復，旋聞二趙歸。", "此行關大義，天意忍相違。"]'),
('f2f43eaa-b56e-4599-90c6-888eec7c9030','胡倅送羊烹以會客','戴復古','宋','宋诗','song-poetry','','[]','烹羶會賓客，花酒一時來。',48,'全唐诗/poet.song.182000.json','["烹羶會賓客，花酒一時來。", "愁逐歌聲散，心隨笑口開。", "飲疑金盞漏，醉到玉山頹。", "借問歡娛地，相逢能幾回。"]'),
('594724f4-8066-43d2-ae59-5f1346af678e','寄清流王令君','戴復古','宋','宋诗','song-poetry','','[]','朴直存吾道，一心唯向公。',48,'全唐诗/poet.song.182000.json','["朴直存吾道，一心唯向公。", "知非巧宦者，直有古人風。", "行志非爲矯，潔身能固窮。", "如何有廉吏，不入薦書中。"]'),
('5a924b58-106e-4791-b6c1-d3b6c8a4ca1b','生朝對雪張子善有詞爲壽','戴復古','宋','宋诗','song-poetry','','[]','焚香拜天貺，滿眼是瑰琦。',48,'全唐诗/poet.song.182000.json','["焚香拜天貺，滿眼是瑰琦。", "臘月雪三尺，春風梅數枝。", "登樓忘老態，對酒展秋眉。", "爭唱陽春曲，山翁醉不知。"]'),
('82ce9ce7-c53e-4a2c-b6b2-a6e8f5d7db33','江濱曉步','戴復古','宋','宋诗','song-poetry','','[]','津頭曉步落潮痕，行盡蒲根到柳根。',64,'全唐诗/poet.song.182000.json','["津頭曉步落潮痕，行盡蒲根到柳根。", "鴈影參差半江月，鷄聲咿喔數家村。", "求魚看下連筒釣，乞火聽敲隣舍門。", "料得錦城無此景，欲將圖畫寄王孫。"]'),
('8b124a56-8c33-4b02-90df-8b9be5e27c13','鄂渚烟波亭','戴復古','宋','宋诗','song-poetry','','[]','倚遍南樓更鶴樓，小亭瀟洒最宜秋。',64,'全唐诗/poet.song.182000.json','["倚遍南樓更鶴樓，小亭瀟洒最宜秋。", "接天烟浪來三峽，隔岸樓臺又一州。", "豪傑不生機事息，古今無盡大江流。", "凭欄日暮懷鄉國，崔顥詩中舊日愁。"]'),
('a36ed6ec-d4b8-4d7e-8d72-b9908bda424b','寄尋梅','戴復古','宋','宋诗','song-poetry','','[]','寄聲說與尋梅者，不在山邊即水涯。',64,'全唐诗/poet.song.182000.json','["寄聲說與尋梅者，不在山邊即水涯。", "又恐好枝爲雪壓，或生幽處被雲遮。", "蜂黄塗額半含蕊，鶴膝翹空疎带花。", "此是尋梅端的處，折來須付與詩家。"]'),
('8a80f17e-5f99-442c-989a-ef46c2db6261','辛未元日上樓參政攻媿齋先生','戴復古','宋','宋诗','song-poetry','','[]','東風入仗慶雲翔，百辟朝元奉玉皇。',64,'全唐诗/poet.song.182000.json','["東風入仗慶雲翔，百辟朝元奉玉皇。", "一代安危寄黄髮，群生枯瘁轉青陽。", "梅花結果調勳鼎，柏葉宜年上壽觴。", "宰相黑頭天子聖，頼公同與措時康。"]'),
('8f39e023-7b97-499a-9c73-3b47f11e78cb','春日二首呈黄子邁大卿  其一','戴復古','宋','宋诗','song-poetry','','[]','野人何得以詩鳴，落魄騎馿走帝京。',64,'全唐诗/poet.song.182000.json','["野人何得以詩鳴，落魄騎馿走帝京。", "白髮半頭驚歲月，虛名一日動公卿。", "頗思湖上春風約，不柰樓頭夜雨聲。", "柳外斷雲篩日影，試聽幽鳥話新晴。"]'),
('8d47373b-b348-467d-9abe-3452171ec011','春日二首呈黄子邁大卿  其二','戴復古','宋','宋诗','song-poetry','','["\u897f\u6e56"]','帝里風光二月新，西湖幾隊踏青人。',64,'全唐诗/poet.song.182000.json','["帝里風光二月新，西湖幾隊踏青人。", "杏花時節偏饒雨，楊柳門牆易得春。", "或是或非塵裏事，無窮無達醉中身。", "五陵年少誇豪舉，寂寞詩家戴叔倫。"]'),
('8aaa3b86-da0f-4e26-ac56-903710dcdc55','釣臺','戴復古','宋','宋诗','song-poetry','','[]','赤符新領舊乾坤，多謝君王問故人。',64,'全唐诗/poet.song.182000.json','["赤符新領舊乾坤，多謝君王問故人。", "暫作客星侵帝座，終爲漁父老江濱。", "層臺不啻幾千仞，直釣何曾挂一鱗。", "莫道羊裘欠圖畫，丹青難寫子陵真。"]'),
('0c931bb4-1e41-435c-bb94-61e2655c788d','寄湖州楊伯子監丞','戴復古','宋','宋诗','song-poetry','','[]','宛如公幹卧漳濱，枕上窮吟過一春。',64,'全唐诗/poet.song.182000.json','["宛如公幹卧漳濱，枕上窮吟過一春。", "遣病每懷詩眷屬，訪醫因問藥君臣。", "鑽龜小卜占災數，覽鏡羸形類別人。", "寄語霅川賢太守，新詩莫厭話愁頻。"]'),
('36e9733f-49eb-4d53-b101-64db5ccccfd0','飲中達觀','戴復古','宋','宋诗','song-poetry','','[]','人生安分即逍遥，莫向明時歎不遭。',64,'全唐诗/poet.song.182000.json','["人生安分即逍遥，莫向明時歎不遭。", "赫赫幾時還寂寂，閑閑到底勝勞勞。", "一心似水惟平好，萬事如棋不著高。", "王謝功名有遺恨，爭如劉阮醉陶陶。"]'),
('87eb1f97-87bd-4b4d-8f68-2ccc41af6dcf','梅','戴復古','宋','宋诗','song-poetry','','[]','孤標粲粲壓群葩，獨占春風管歲華。',64,'全唐诗/poet.song.182000.json','["孤標粲粲壓群葩，獨占春風管歲華。", "幾樹參差江上路，數枝裝點野人家。", "冰池照影何須月，雪岸聞香不見花。", "絕似林間隠君子，自從幽處作生涯。"]'),
('e054bfcc-58e4-48f5-9590-0b573ef4f86e','清凉寺有懷真翰林運使之來','戴復古','宋','宋诗','song-poetry','','[]','不特來觀德慶碑，江山勝槩六朝遺。',64,'全唐诗/poet.song.182000.json','["不特來觀德慶碑，江山勝槩六朝遺。", "興亡了不關吾事，登覽胡爲作許悲。", "梅爲有香奇似雪，酒能無悶妙於詩。", "蕭蕭綠竹無人愛，留取雲稍待鳳來。"]'),
('fa90b5b1-ea9c-4db3-9811-f698c534d08f','覺慈寺','戴復古','宋','宋诗','song-poetry','','[]','踏破白雲登上方，自嫌塵土涴禪床。',64,'全唐诗/poet.song.182000.json','["踏破白雲登上方，自嫌塵土涴禪床。", "千山月色令人醉，半夜梅花入夢香。", "深谷不妨春到早，老僧殊爲客來忙。", "山童懶慣勞呼喚，自拗枯松煮朮湯。"]'),
('8eb5bd80-8e96-4893-b06b-d1d7f2c79af5','寄復齋陳寺丞二首  其一','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','豈說從來用處難，出乘五馬看廬山。',64,'全唐诗/poet.song.182000.json','["豈說從來用處難，出乘五馬看廬山。", "鳳凰覽德下千仞，虎豹憎人上九關。", "持論太高天動色，憂時未老鬢先斑。", "平生風節誰其似，汲黯朱雲伯仲間。"]'),
('00561de8-da09-48c1-a3a1-acce9aa02dfe','寄復齋陳寺丞二首  其二','戴復古','宋','宋诗','song-poetry','','[]','長憶西灣繫小舟，野人曾伴使君游。',64,'全唐诗/poet.song.182000.json','["長憶西灣繫小舟，野人曾伴使君游。", "夜浮星子邀明月，雨對廬君說好秋。", "坐擁紅粧磨寶硯，醉歌赤壁寫銀鈎。", "當時一段風流事，翻作相思一段愁。"]'),
('12aef7a1-c429-4a89-836e-f14e4bd1eda6','黄州偶成','戴復古','宋','宋诗','song-poetry','','[]','鴈叫淮南欲雪天，倚樓無味抱愁眠。',64,'全唐诗/poet.song.182000.json','["鴈叫淮南欲雪天，倚樓無味抱愁眠。", "算從滄海白雲際，行到黄州赤壁邊。", "萬事忌於懷壯志，一生窮爲聳吟肩。", "鬢間白者休教鑷，要使天知老可憐。"]'),
('f95a3e74-00bd-49fe-ac89-a9ee6ed5dbdd','題泉州王梅溪先生祠堂徐竹隠直院謂梅溪古之遺直渡江以來一人而已','戴復古','宋','宋诗','song-poetry','','[]','堂堂大節在朝廷，名重當時太華輕。',64,'全唐诗/poet.song.182000.json','["堂堂大節在朝廷，名重當時太華輕。", "乾道君臣千載遇，先生議論九重驚。", "人歌黄霸思遺愛，我頌朱雲有直聲。", "一瓣清香拜圖像，英風凜凜尚如生。"]'),
('fd1514f3-1b78-4929-bf82-2486f09418b0','無爲山中鄭老家','戴復古','宋','宋诗','song-poetry','','[]','高談可聽用心幽，灼見此翁非俗流。',64,'全唐诗/poet.song.182000.json','["高談可聽用心幽，灼見此翁非俗流。", "鞍馬破家還避世，田園得地肯封侯。", "開窗脩竹無由俗，繞屋青山總是秋。", "門外短籬看亦好，黄金菊間碧牽牛。"]'),
('ee3e08af-4018-40fb-bb3d-ee085c73387b','南康縣用東坡留題韵','戴復古','宋','宋诗','song-poetry','','[]','鏡中雙鬢已非鴉，身在江湖心在家。',64,'全唐诗/poet.song.182000.json','["鏡中雙鬢已非鴉，身在江湖心在家。", "道路飄零如柳絮，山川迤邐近梅花。", "客行有債頻沽酒，老怕無眠戒飲茶。", "昨夜夢歸滄海上，釣竿橫插鴈邊沙。"]'),
('01346466-fe7c-4668-b7aa-cc3f95440a83','李季允侍郎舟中','戴復古','宋','宋诗','song-poetry','','["\u592a\u6e56"]','憶昨楓橋既語離，何期千里又相隨。',64,'全唐诗/poet.song.182000.json','["憶昨楓橋既語離，何期千里又相隨。", "太湖不見鴟夷子，秋浦同尋杜牧之。", "燈火船窗深夜話，江山客路早冬詩。", "人間草木空無數，除却梅花莫我知。"]'),
('03985419-344c-4fed-b81f-5f24e65b3a40','湖南見真帥','戴復古','宋','宋诗','song-poetry','','[]','致身雖自文章選，經世尤高政事科。',64,'全唐诗/poet.song.182000.json','["致身雖自文章選，經世尤高政事科。", "以若所爲即伊呂，使其不遇亦丘軻。", "長沙地窄儒衣闊，明月池乾春水多。", "天以一賢私一路，其如四海九州何。"]'),
('3afd41d4-95af-4459-8981-41cb648316af','永新宰潘仁叔再約觀梅','戴復古','宋','宋诗','song-poetry','','[]','去年憶訪潘懷縣，樽俎風流主意饒。',64,'全唐诗/poet.song.182000.json','["去年憶訪潘懷縣，樽俎風流主意饒。", "爆竹聲中度殘歲，華燈影裏醉元宵。", "春風又起觀梅興，野客仍煩折簡招。", "預想張園尋故事，插花秉燭過溪橋。"]'),
('b77fc150-2edf-4346-825d-071968c2afa2','廬山  其一','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山靈未許到天池，又作西林一宿期。',64,'全唐诗/poet.song.182000.json','["山靈未許到天池，又作西林一宿期。", "寺是晉時陶侃宅，記傳隋代率更碑。", "山椒雲氣易爲雨，客子情懷多費詩。", "暫借蒲團學禪寂，茶烟飛繞鬢邊絲。"]'),
('95078829-ea9d-4280-9e4e-34d55f605b9e','廬山  其二','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','道人問我看廬山，地上爭如閣上看。',64,'全唐诗/poet.song.182000.json','["道人問我看廬山，地上爭如閣上看。", "呈露千峰秋落木，雕鎪萬象客凭欄。", "靜中見得天機妙，閑裏回觀世路難。", "管領風光有微憾，桂花香裏酒瓶乾。"]'),
('398a2321-522c-4edd-bfb8-511fb8ec04e9','廬山  其三','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','擁鼻行吟上下廊，今宵又宿贊公房。',64,'全唐诗/poet.song.182000.json','["擁鼻行吟上下廊，今宵又宿贊公房。", "松摇半夜風聲壯，桂染中秋月色香。", "白石清泉聞笑語，名山大澤出文章。", "老夫甘作無名者，不逐紛紛舉子忙。"]'),
('b5a1469e-9ace-44c5-a258-d4d0c1a69a73','廬山  其四','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','乘鸞不見李騰空，試與尋真訪故宮。',64,'全唐诗/poet.song.182000.json','["乘鸞不見李騰空，試與尋真訪故宮。", "黄葉堆邊覓行路，紫烟深處望仙蹤。", "眼高天近千山上，身共雲棲一壑中。", "九疊屏風三疊水，更無詩句可形容。"]'),
('a5c6821b-75ad-48e9-884e-56c3e957fd40','豫章東湖感舊','戴復古','宋','宋诗','song-poetry','','[]','憶見堤邊種柳初，重來高樹滿東湖。',64,'全唐诗/poet.song.182000.json','["憶見堤邊種柳初，重來高樹滿東湖。", "交游太半入鬼錄，歌醉一時逢酒徒。", "夜雨總成流水去，春風能免落花無。", "經行孺子亭邊路，猶有沙鷗識老夫。"]'),
('ac72fb90-6269-44fe-b9c1-850d32392585','僮約','戴復古','宋','宋诗','song-poetry','','[]','汝在何鄉何姓名，路途凡百愛惺惺。',64,'全唐诗/poet.song.182000.json','["汝在何鄉何姓名，路途凡百愛惺惺。", "衣裳脫著勤收管，飲食烹炰貴潔馨。", "每遇歇時尋竹所，須教宿處近旗亭。", "吾家僮約無多事，辦取小心供使令。"]'),
('160a4f01-2e1b-49d6-8564-7b8e9f604951','同鄭子野訪王隠居','戴復古','宋','宋诗','song-poetry','','[]','聯騎來尋失馬翁，相期投宿此山中。',64,'全唐诗/poet.song.182000.json','["聯騎來尋失馬翁，相期投宿此山中。", "一庭花影三更月，萬壑松聲半夜風。", "共把酒杯眠不得，劇談世事恨無窮。", "明朝莫使兒童見，倘有江船吾欲東。"]'),
('607ca7e5-8670-4961-ad7a-2966de92eebd','夜宿田家','戴復古','宋','宋诗','song-poetry','','[]','簦笠相隨走路岐，一春不換舊征衣。',64,'全唐诗/poet.song.182000.json','["簦笠相隨走路岐，一春不換舊征衣。", "雨行山崦黄泥坂，夜扣田家白板扉。", "身在亂蛙聲裏睡，心從化蝶夢中歸。", "鄉書十寄九不達，天北天南鴈自飛。"]'),
('b010a68b-7740-4b39-9fe2-c24d6b7999d3','送蒙齋兄長游天台二首  其一','戴復古','宋','宋诗','song-poetry','','[]','方丈蓬萊去渺茫，天台祇在白雲傍。',64,'全唐诗/poet.song.182000.json','["方丈蓬萊去渺茫，天台祇在白雲傍。", "羽衣金策群仙過，珠閣瓊樓八桂香。", "采藥有時逢道侶，挑包遇夜宿僧房。", "寒山拾得如相見，指點人間笑幾場。"]'),
('42323cb1-23ed-4289-9044-02b5708995af','送蒙齋兄長游天台二首  其二','戴復古','宋','宋诗','song-poetry','','[]','山林勝處說天台，仙佛多從此地棲。',64,'全唐诗/poet.song.182000.json','["山林勝處說天台，仙佛多從此地棲。", "司馬八篇通道妙，豐干一語指人迷。", "時逢好酒從容飲，莫把新詩取次題。", "白日看雲思我否，惠連無分共攀躋。"]'),
('275b13c4-a8b5-4e22-a66f-44150d8bab99','豫章巨浸呈陳幼度提幹','戴復古','宋','宋诗','song-poetry','','[]','乞得新晴賦晚霞，出門無路欲乘槎。',64,'全唐诗/poet.song.182000.json','["乞得新晴賦晚霞，出門無路欲乘槎。", "憂風憂雨動經月，足食足衣能幾家。", "一飯共君烹瓠葉，三杯無處看荷花。", "自成鼓吹喧朝夕，輸與東湖兩部蛙。"]'),
('3833a19a-546b-43fb-bc28-68e91966363a','訪趙東野','戴復古','宋','宋诗','song-poetry','','[]','朅來問訊病維摩，花滿溪堂竹滿坡。',64,'全唐诗/poet.song.182000.json','["朅來問訊病維摩，花滿溪堂竹滿坡。", "髮禿齒危俱老矣，人高詩苦柰窮何。", "四山便是清凉國，一室可爲安樂窩。", "猶有憂時兩行淚，臨風揮灑濕藤蘿。"]'),
('7bbeabe1-a1e0-4577-b18a-92af715eeaea','方孚若真□宅堂前池上作淮南小山題詠者甚多見其詩軸次韵','戴復古','宋','宋诗','song-poetry','','[]','妙手能移造化功，壺中幻出九華峰。',64,'全唐诗/poet.song.182000.json','["妙手能移造化功，壺中幻出九華峰。", "山雖云小能棲鳳，水不求深貴有龍。", "事紀淮南千古勝，記成嘉泰八年冬。", "先生不用賦招隠，辦了功名訪赤松。"]'),
('46c4b098-ed2a-4daf-9809-2788e2755301','江州德化縣漪嵐堂盡得廬山之勝醉中作此呈趙明府','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不羨君爲花縣宰，羨君日坐漪嵐堂。',64,'全唐诗/poet.song.182000.json','["不羨君爲花縣宰，羨君日坐漪嵐堂。", "有時酒興兼詩興，無限山光與水光。", "百姓熙熙知教化，群胥凜凜對風霜。", "公餘置酒看桃李，醉倒花前客自狂。"]'),
('d8a2eb7a-fd91-4de9-96c5-0e3fea53d1ca','廬州帥李仲詩春風亭會客有塵字韵詩和者甚多韵拘無好語','戴復古','宋','宋诗','song-poetry','','[]','玉關人老鬢絲新，千里長城在一身。',64,'全唐诗/poet.song.182000.json','["玉關人老鬢絲新，千里長城在一身。", "氣使黄金結豪傑，手揮白羽靜風塵。", "山河四望亭中景，桃李一開天下春。", "鄉日滿城騎戰馬，而今四野盡耕民。"]'),
('5e8b0b16-48fb-4024-8556-51e1f3c583fd','送滕審言歸長沙別無聊','戴復古','宋','宋诗','song-poetry','','[]','折柳亭前送故人，平沙留得馬蹄痕。',64,'全唐诗/poet.song.182000.json','["折柳亭前送故人，平沙留得馬蹄痕。", "雲生渡北迷行路，烟起江南認別村。", "恨不與君同上道，歸來無伴自開樽。", "西樓獨倚黄昏月，欲倩飛鴻寄斷魂。"]'),
('985f4b18-72e9-41cf-ae62-e1d2e2cfb73a','張仁仲提幹衡陽冰壺亭燕客','戴復古','宋','宋诗','song-poetry','','[]','大抵吾曹臭味同，留歡卜夜莫匆匆。',64,'全唐诗/poet.song.182000.json','["大抵吾曹臭味同，留歡卜夜莫匆匆。", "一亭景物冰壺上，萬里乾坤玉鏡中。", "疎柳無心挂明月，敗荷有恨倚西風。", "吟家舊日張公子，千首詩成句句工。"]'),
('061a02c8-945b-4144-b7ef-9a71bdfd45e8','別後舟中用前韵','戴復古','宋','宋诗','song-poetry','','[]','出郭風光便不同，轉頭猶恨去匆匆。',64,'全唐诗/poet.song.182000.json','["出郭風光便不同，轉頭猶恨去匆匆。", "維舟別岸鴉啼後，倚柂澄江鴈影中。", "向老客懷驚歲月，乍寒天氣轉霜風。", "冰壺亭上人如玉，謾寄篇詩不暇工。"]'),
('06c08ecf-2da3-43f5-900e-b89236c7b9b7','海月星天之觀','戴復古','宋','宋诗','song-poetry','','[]','巍然華屋似凌歊，下際滄溟上九霄。',64,'全唐诗/poet.song.182000.json','["巍然華屋似凌歊，下際滄溟上九霄。", "萬頃波濤浴蟾兔，一天星斗轉魁杓。", "征鴻有感人飄泊，宿鶴無聲夜寂寥。", "誰似風流楊叔子，登臨□□□□□。"]'),
('a3487f4b-e74e-4e62-aeb3-17f05264a3c4','杜子野主簿約客賦一詩爲贈與僕一聯云生就石橋羅漢面吟成雪屋閬仙詩','戴復古','宋','宋诗','song-poetry','','[]','杜陵之後有孫耒，自守詩家法度嚴。',64,'全唐诗/poet.song.182000.json','["杜陵之後有孫耒，自守詩家法度嚴。", "秀骨可仙官况薄，高情追古俗人嫌。", "起看星斗夜推枕，爲愛江山寒捲簾。", "飽喫梅花吟更好，錦囊雖富不傷廉。"]'),
('f4d472c3-3847-43a2-b248-d283b6949d72','楊伯子監丞霅川久雨得晴爲喜','戴復古','宋','宋诗','song-poetry','','[]','村南村北晒簑衣，好是雲開日出時。',64,'全唐诗/poet.song.182000.json','["村南村北晒簑衣，好是雲開日出時。", "太守少寬憂世志，野人爲賦喜晴詩。", "兩岐瑞麥黄金實，八繭吳蠶白雪絲。", "政事端知合天意，雨暘還亦順人爲。"]'),
('91743552-eb96-4b9e-b237-719ea5b4ce61','提刑彭仲節平叛卒','戴復古','宋','宋诗','song-poetry','','[]','千兵喝賞黄金盡，六月臨戎白刃寒。',64,'全唐诗/poet.song.182000.json','["千兵喝賞黄金盡，六月臨戎白刃寒。", "慷慨丈夫爲事別，太平人物濟時難。", "誰言江左無王謝，今喜軍中有范韓。", "漢節梅花留不住，借君一劍斬樓蘭。"]'),
('75f2c5d0-516e-4874-9a93-7d8cf7a25d6b','中秋李漕冰壺燕集','戴復古','宋','宋诗','song-poetry','','[]','諸亭環立一湖灣，區界無多眼界寬。',64,'全唐诗/poet.song.182000.json','["諸亭環立一湖灣，區界無多眼界寬。", "蒼石傳爲僞劉物，綠波曾浴葛仙丹。", "兩邊堤樹四時碧，一片冰壺六月寒。", "咫尺雲烟接滄海，須知此地有龍蟠。"]'),
('f4c0d530-0aeb-4360-94ed-40008c735022','李計使領客游白雲景泰','戴復古','宋','宋诗','song-poetry','','[]','天近剛風吹面寒，繡衣玉立白雲間。',64,'全唐诗/poet.song.182000.json','["天近剛風吹面寒，繡衣玉立白雲間。", "滄波萬頃海南海，翠碧幾重山外山。", "自覺登臨無限意，誰思富貴不如閑。", "前峰若箇神仙宅，指點烟霞見一斑。"]'),
('e2226240-c363-410c-8626-da1839dbeb85','菊坡崔參政說平叛卒不得已拜經略之命豈敢言功','戴復古','宋','宋诗','song-poetry','','[]','角巾私第自逍遥，諸老之中此老高。',64,'全唐诗/poet.song.182000.json','["角巾私第自逍遥，諸老之中此老高。", "無可柰何懷印綬，甚非得已用弓刀。", "風生玉帳千兵肅，天落金牌一札褒。", "緩急經心護鄉井，生憎兒輩說功勞。"]'),
('c0c8f5aa-3ff5-4707-84e9-b2223b652268','題處士黄公山居','戴復古','宋','宋诗','song-poetry','','[]','行盡松坡與竹坡，沿溪窈窕上巖阿。',64,'全唐诗/poet.song.182000.json','["行盡松坡與竹坡，沿溪窈窕上巖阿。", "山深每恨客來少，寺近莫教僧到多。", "但覺洞中人不老，不知雲外事如何。", "邊頭又報真消息，靼使來朝乞講和。"]'),
('32cbab66-c598-4d55-a718-253311befd47','題何季湧江亭','戴復古','宋','宋诗','song-poetry','','[]','勝概何妨近市廛，紅塵疎處著三椽。',64,'全唐诗/poet.song.182000.json','["勝概何妨近市廛，紅塵疎處著三椽。", "數重青嶂橫天末，一道澄江在眼前。", "海浪浴紅朝出日，樹林堆碧晚生烟。", "請君分付堤邊石，莫使漁翁來繫船。"]'),
('8339e647-1bb2-44f2-b7f9-9f94a8c4d8eb','別鍾子洪','戴復古','宋','宋诗','song-poetry','','[]','識得潮陽鍾子洪，今人可想古人風。',64,'全唐诗/poet.song.182000.json','["識得潮陽鍾子洪，今人可想古人風。", "文章有氣吞餘子，天地無情負此翁。", "問舍求田非細事，參禪學佛見新功。", "欲知別後真消息，莫惜頻書寄海鴻。"]'),
('4c319958-3bed-4286-a329-0cf5154d0161','再賦惜別呈李實夫運使','戴復古','宋','宋诗','song-poetry','','[]','一生飄泊老江湖，今日別公歸故廬。',64,'全唐诗/poet.song.182000.json','["一生飄泊老江湖，今日別公歸故廬。", "此去怕無相見日，因風或有寄來書。", "雲烟過眼時時變，草樹驚秋夜夜疎。", "人物似公能幾輩，不知天下竟何如。"]'),
('480596a4-341d-4cf9-80c5-4948fbcff5cb','蕭學易何季皋和作別詩佳甚再用前韵','戴復古','宋','宋诗','song-poetry','','[]','少年行脚白頭歸，不負平生汗漫期。',64,'全唐诗/poet.song.182000.json','["少年行脚白頭歸，不負平生汗漫期。", "望斷海山雲漠漠，愁生江路草離離。", "一篇王粲登樓賦，幾首巴陵送別詩。", "獨倚篷窗無意緒，瓦盆傾酒憶金巵。"]'),
('cd692250-b03c-4348-b22a-d5053a0ab2e2','靈洲','戴復古','宋','宋诗','song-poetry','','[]','一臺中立鬰蒼蒼，四面山光接水光。',64,'全唐诗/poet.song.182000.json','["一臺中立鬰蒼蒼，四面山光接水光。", "潮信往來知氣候，黿精出沒兆災祥。", "烟生茶竈僧留款，風展蒲帆客去忙。", "白髮東坡在何許，兩行遺墨照琳琅。"]'),
('74ebf635-4b18-453f-bf75-69be277fab13','和韶州許使君令子送別之韵','戴復古','宋','宋诗','song-poetry','','[]','詩瘦吾非沈隠侯，五窮相值結爲讐。',64,'全唐诗/poet.song.182000.json','["詩瘦吾非沈隠侯，五窮相值結爲讐。", "方愁度嶺無相識，却喜聞韶到此州。", "世道從來三不合，客行何止七宜休。", "故人知我平生事，肯笑蘇秦著弊裘。"]'),
('870c43c6-1dfa-486a-9b6e-331a4f7888d4','南安王使君領客湛泉流觴曲水','戴復古','宋','宋诗','song-poetry','','[]','橫浦堂前舉一巵，古榕陰下坐多時。',64,'全唐诗/poet.song.182000.json','["橫浦堂前舉一巵，古榕陰下坐多時。", "連朝好雨千山潤，昨夜新秋一葉知。", "梅嶺鄉來逢行者，蘭亭今日又羲之。", "家聲不墜風流在，如見初寮說好詩。"]'),
('0365705c-2445-4caa-8e2a-b7861712b405','題鄒震甫江山偉觀','戴復古','宋','宋诗','song-poetry','','[]','八境橫陳淦水濱，異鄉誰識倚樓人。',64,'全唐诗/poet.song.182000.json','["八境橫陳淦水濱，異鄉誰識倚樓人。", "江山不越乾坤大，烟雨翻成風月新。", "十載經營梅屋趣，三間突兀草堂隣。", "題詩未得驚人句，從此登臨莫厭頻。"]'),
('8acccf20-8762-48a4-8a83-47569cdcfa88','去年訪曾幼卿通判携歌舞者同游鳳山僕有歌舞不容人不醉樽前方見董嬌嬈之句今歲到鳳山又闢西隅築堤種柳新作數亭且欲建藏書閣後堂佳麗皆屏去之矣僕嘉其志又有數語併錄之  其一','戴復古','宋','宋诗','song-poetry','','[]','一丘一壑自逍遥，莫怪山人索價高。',64,'全唐诗/poet.song.182000.json','["一丘一壑自逍遥，莫怪山人索價高。", "是處園林可行樂，同來賓客不須招。", "臨風桃李花狼藉，照水樓臺影動摇。", "歌舞不容人不醉，樽前方見董嬌嬈。"]'),
('fa542ef6-e0ff-4808-9fc9-fc10b2a66fb0','去年訪曾幼卿通判携歌舞者同游鳳山僕有歌舞不容人不醉樽前方見董嬌嬈之句今歲到鳳山又闢西隅築堤種柳新作數亭且欲建藏書閣後堂佳麗皆屏去之矣僕嘉其志又有數語併錄之  其二','戴復古','宋','宋诗','song-poetry','','[]','別駕常懷物外心，黄金屢費買山林。',64,'全唐诗/poet.song.182000.json','["別駕常懷物外心，黄金屢費買山林。", "後堂不肯著歌舞，高閣唯思貯古今。", "幾處亭臺新結束，一春風雨阻登臨。", "野夫昨日閑乘興，著屐尋詩到柳陰。"]'),
('7e9be5f6-625c-4e3c-8b20-c47193a4a33e','撫州謝樓宗丞見訪','戴復古','宋','宋诗','song-poetry','','[]','客裏門庭可設羅，使君千騎肯相過。',64,'全唐诗/poet.song.182000.json','["客裏門庭可設羅，使君千騎肯相過。", "心忘貴賤交游重，論及興衰感慨多。", "諸老逢時起巖壑，二邊何日罷干戈。", "老夫何預人間事，歸去滄江理釣簑。"]'),
('9a8bb0c1-9c2c-4b90-809e-c3fcc8be9bcc','平江呈毅夫侍郎','戴復古','宋','宋诗','song-poetry','','[]','龍墀射策三千字，未抵胸中十萬兵。',64,'全唐诗/poet.song.182000.json','["龍墀射策三千字，未抵胸中十萬兵。", "遠大無過爲將相，文章爭似立功名。", "當今天下幾豪傑，獨數君家兩弟兄。", "世事從橫人事左，未知何以措昇平。"]'),
('c0fea566-eecf-45b8-855b-34d80e122c11','見淮東制帥趙南仲侍郎相待厚甚特送買山錢又欲刊石屏詩置于揚州郡齋話別敘謝','戴復古','宋','宋诗','song-poetry','','[]','如公當向古人求，識面何須萬戶侯。',64,'全唐诗/poet.song.182000.json','["如公當向古人求，識面何須萬戶侯。", "浪說釣鰲游瀚海，真成騎鶴上揚州。", "受恩多處難爲別，宿酒醒時始覺愁。", "回首平山堂下路，不堪風雨送歸舟。"]'),
('b859adf9-3d7d-4520-af5b-29b0a205ae2a','鎮江別總領吳道夫侍郎時愚子琦來迎侍朝夕催歸甚切','戴復古','宋','宋诗','song-poetry','','[]','落魄江湖四十年，白頭方辦買山錢。',64,'全唐诗/poet.song.182000.json','["落魄江湖四十年，白頭方辦買山錢。", "老妻懸望占烏鵲，愚子催歸若杜鵑。", "濟世功名付豪傑，野人事業在林泉。", "難禁別後相思意，或有封書寄鴈邊。"]'),
('e41e86c6-eadc-42d2-9ced-64a63dc53097','董侍郎山園燕樓宗丞','戴復古','宋','宋诗','song-poetry','','[]','旌旗千騎擁春華，傾動臨川十萬家。',64,'全唐诗/poet.song.182000.json','["旌旗千騎擁春華，傾動臨川十萬家。", "皂蓋出郊因問柳，紫荷領客共看花。", "罇前人唱鶑隨唱，堂下吏衙蜂亦衙。", "寄語風流賢太守，好留醉墨伴烟霞。"]'),
('b41ba5ad-c98a-4395-b649-aa84f7c7cc6d','聶侍郎領客觀園林之勝飲中出示名賢書畫','戴復古','宋','宋诗','song-poetry','','[]','烈士家風從橐尊，時容野客上朱門。',64,'全唐诗/poet.song.182000.json','["烈士家風從橐尊，時容野客上朱門。", "如登東觀圖書府，又似西巖水竹村。", "自以一閑銷日月，誰知萬慮滿乾坤。", "諸公衮衮成何事，不若花前對酒罇。"]'),
('25331933-844c-4f80-91d8-789acdc1a131','思歸二首  其一','戴復古','宋','宋诗','song-poetry','','[]','吟詩不換校書郎，但欲封侯管醉鄉。',64,'全唐诗/poet.song.182000.json','["吟詩不換校書郎，但欲封侯管醉鄉。", "疎懶無成嵇叔夜，清狂似達賀知章。", "安貧不怕黄金盡，既老從教白髮長。", "百計不如歸去好，子孫相對說農桑。"]'),
('359b0506-5c9f-4b90-8e74-f2ed354f75fb','思歸二首  其二','戴復古','宋','宋诗','song-poetry','','[]','老矣歸歟東海村，長裾不復上王門。',64,'全唐诗/poet.song.182000.json','["老矣歸歟東海村，長裾不復上王門。", "肉糜豈勝魚羹飯，紈袴何如犢鼻禈。", "是處江山如送客，故園桐竹已生孫。", "分無功業書青史，或有詩名身後存。"]'),
('83300279-d342-4301-a882-a107601d51d9','趙用甫提舉夢中得片雲不隔梅花月之句時被命入朝雪中送別用其一句補以成章','戴復古','宋','宋诗','song-poetry','','[]','一時議論動諸公，有詔西來玉節東。',64,'全唐诗/poet.song.182000.json','["一時議論動諸公，有詔西來玉節東。", "又見清朝更大化，好趨丹陛奏孤忠。", "片雲不隔梅花月，一雪翻成柳絮風。", "把酒莫辭今夕醉，明朝車馬去匆匆。"]'),
('b85c92a9-344d-4444-be2f-3f12e57b40fe','長沙呈趙東巖運使併簡幕中楊唯叔通判諸丈','戴復古','宋','宋诗','song-poetry','','[]','日莫遠塗行未休，白頭又作長沙遊。',64,'全唐诗/poet.song.182000.json','["日莫遠塗行未休，白頭又作長沙遊。", "湘江一點不容俗，岳麓四時皆是秋。", "香草汀洲付騷客，紅蓮幕府聚名流。", "吟邊萬象寫不得，上有風流趙倚樓。"]'),
('dbf85d1e-31ea-4060-a3d7-63152625756b','山中見梅寄曾無疑','戴復古','宋','宋诗','song-poetry','','[]','香動寒山寂寞濱，直從空谷見佳人。',64,'全唐诗/poet.song.182000.json','["香動寒山寂寞濱，直從空谷見佳人。", "樹頭樹底參差雪，枝北枝南次第春。", "有此瑰琦在巖壑，其他草樹亦精神。", "移根上苑誰云晚，桃李依然在後陳。"]'),
('db945f98-ab82-4759-985c-7db1d955abad','余惠叔訪舊','戴復古','宋','宋诗','song-poetry','','[]','扁舟訪舊入橫塘，新柳今如舊柳長。',64,'全唐诗/poet.song.182000.json','["扁舟訪舊入橫塘，新柳今如舊柳長。", "室邇人遥春寂寂，風流雲散事茫茫。", "縱題紅葉隨流水，誰弄青梅出短牆。", "政是沈郎愁絕處，杜鵑不斷叫斜陽。"]'),
('418e7d44-7c24-407b-af33-9fbfa0febc16','兩山趙仁甫宰臨安有武學生張丈相訪酒邊弄刀舞劍甚可觀因成七言縣乃錢王故宮九龍十錦皆其地','戴復古','宋','宋诗','song-poetry','','[]','風流晉宋時人物，花縣鳴琴調甚新。',64,'全唐诗/poet.song.182000.json','["風流晉宋時人物，花縣鳴琴調甚新。", "不厭開樽留劍客，仍能下榻待詩人。", "九龍池舘空陳迹，十錦山川自好春。", "但見清吟度白日，不知佳政最宜民。"]'),
('fc7ca4f9-5a1d-4f93-b720-c323cfddbdbe','友人朱淵出示廷對策不顧忌諱讀之使人凜凜受淮東制置辟','戴復古','宋','宋诗','song-poetry','','[]','龍墀射策對明君，憂國忠言駭見聞。',64,'全唐诗/poet.song.182000.json','["龍墀射策對明君，憂國忠言駭見聞。", "皎皎一心如白日，寥寥千古再朱雲。", "時危諸老皆求去，兵滿三邊未解紛。", "要使文臣知武事，不妨王粲且從軍。"]'),
('2a8b8116-c1f3-439a-9d36-d73901456a95','裘司直見訪留款','戴復古','宋','宋诗','song-poetry','','[]','清風爲我拂塵襟，坐聽先生說古今。',64,'全唐诗/poet.song.182000.json','["清風爲我拂塵襟，坐聽先生說古今。", "道誼欲灰傷世變，利名如海溺人深。", "一言可重輕雙璧，片善相資直萬金。", "聞道門牆不多遠，明朝修敬到山陰。"]'),
('1b481e4e-80e3-4573-8f92-706848102e83','訪張元德','戴復古','宋','宋诗','song-poetry','','[]','今宵何幸宿書林，議論從橫感慨深。',64,'全唐诗/poet.song.182000.json','["今宵何幸宿書林，議論從橫感慨深。", "黄卷具傳千古意，青燈照破幾人心。", "狂夫嗜飲夜偷酒，汙吏容私晝攫金。", "堯舜君民舊風俗，凡經幾變到于今。"]'),
('064c9433-8987-43dd-ab7a-43c4b87cd118','滕審言相遇話舊','戴復古','宋','宋诗','song-poetry','','[]','憶昨同君訪月林，幾年相別到于今。',64,'全唐诗/poet.song.182000.json','["憶昨同君訪月林，幾年相別到于今。", "江山花草生詩夢，風雨憂愁長道心。", "久矣無波觀古井，悠然得趣聽鳴琴。", "一生奔走成何事，塵滿征衫雪滿簪。"]'),
('1ffcb521-5021-4f2b-bed9-7187fc0e442a','陳孟參陳明子同游麻姑山','戴復古','宋','宋诗','song-poetry','','[]','麻姑壇上共登臨，野客悠然起道心。',64,'全唐诗/poet.song.182000.json','["麻姑壇上共登臨，野客悠然起道心。", "丹井汲泉深百尺，星杉聳壑到千尋。", "青蓮花白僊蹤遠，烏桕葉紅秋意深。", "何用金槃擘麟脯，山肴濁酒可同斟。"]'),
('958caba0-4590-4559-9db4-9377e9e2a48e','興國軍晚春簡吳提幹','戴復古','宋','宋诗','song-poetry','','[]','幾夜林間哭杜鵑，東風又作落花天。',64,'全唐诗/poet.song.182000.json','["幾夜林間哭杜鵑，東風又作落花天。", "青春不覺過三月，白髮誰能滿百年。", "日射江波光閃閃，天連烟草碧芊芊。", "異鄉欲作登樓賦，心逐歸鴻到海邊。"]'),
('8901a37c-0d20-4cea-bd50-7eda255eb9b5','朱子昂司戶登滕王閣','戴復古','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','笑傲不禁秋興長，登臨誰復問滕王。',64,'全唐诗/poet.song.182000.json','["笑傲不禁秋興長，登臨誰復問滕王。", "江湖周折地襟带，雲霞粲爛天文章。", "人如野鶴何飄逸，目送飛鴻去渺茫。", "安得雪醅三百斗，發君豪氣對吾狂。"]'),
('57011e39-6258-46eb-be2a-cab084c645ee','汪給事守鄂渚元宵代江夏宰吳熙仲獻燈  其一','戴復古','宋','宋诗','song-poetry','','[]','鄂州新得主人翁，今歲元宵便不同。',64,'全唐诗/poet.song.182000.json','["鄂州新得主人翁，今歲元宵便不同。", "燈火夜深回晝日，管絃聲動起春風。", "遼天月借三秋白，陸地蓮開十丈紅。", "妙手信能移造化，速宜歸去補蒼穹。"]'),
('e108bbfd-f566-40e3-9826-dcdb48736618','汪給事守鄂渚元宵代江夏宰吳熙仲獻燈  其二','戴復古','宋','宋诗','song-poetry','','[]','一晴收盡四山雲，天與黄堂作好春。',64,'全唐诗/poet.song.182000.json','["一晴收盡四山雲，天與黄堂作好春。", "西楚東吳獻風月，南樓北榭擁星辰。", "扶持入郭觀燈叟，歌舞攔街醉酒人。", "此是太平真氣象，今年第一箇良辰。"]'),
('55a03d10-fdc0-4c7a-8c10-69510ab5c9e4','袁州化成巖李衛公謫居之地','戴復古','宋','宋诗','song-poetry','','[]','一巖端坐挹千峰，三兩亭臺勝概中。',64,'全唐诗/poet.song.182000.json','["一巖端坐挹千峰，三兩亭臺勝概中。", "江水驟生連夜雨，松聲吹下半天風。", "因思世故吾頭白，獨步林皋夕照紅。", "欲吐草茅憂國志，誰能喚起贊皇公。"]'),
('02440c2a-8681-4443-b338-8f9c0bf5cf02','友松亭代松語','戴復古','宋','宋诗','song-poetry','','[]','從來巖壑守孤蹤，豈料移歸寶籞中。',64,'全唐诗/poet.song.182000.json','["從來巖壑守孤蹤，豈料移歸寶籞中。", "幸在交游一人數，願勤培植百年功。", "朱門縱有三千客，青眼毋忘十八公。", "根本既深枝葉茂，相期直上碧霄中。"]'),
('bb5f290e-402f-4c6c-ab70-b40e18a4e7a2','京口別石龜翁際可','戴復古','宋','宋诗','song-poetry','','[]','把劍樽前砍地歌，有何留戀此蹉跎。',64,'全唐诗/poet.song.182000.json','["把劍樽前砍地歌，有何留戀此蹉跎。", "心期難與俗子道，世事不如人意多。", "蓮葉已空猶有藕，菊花雖老不成莎。", "扁舟四海五湖上，何處不堪披釣簑。"]'),
('8f4fbc5e-3040-4353-b581-b2afc7592996','讀放翁先生劍南詩草','戴復古','宋','宋诗','song-poetry','','[]','茶山衣鉢放翁詩，南渡百年無此奇。',64,'全唐诗/poet.song.182000.json','["茶山衣鉢放翁詩，南渡百年無此奇。", "入妙文章本平澹，等閑言語變瑰琦。", "三春花柳天裁剪，歷代興衰世轉移。", "李杜陳黄題不盡，先生模寫一無遺。"]'),
('7f6b8418-8bfb-4bf1-9ef2-17c2cd9a8365','古田縣行覽呈劉無競','戴復古','宋','宋诗','song-poetry','','[]','客游花縣自逍遥，百里風光在兩橋。',64,'全唐诗/poet.song.182000.json','["客游花縣自逍遥，百里風光在兩橋。", "語出桑陰鳩婦喜，身穿麥秀雉雛嬌。", "青山一任雲來去，綠水多爲風動摇。", "上下相安長官好，野亭閑坐聽民謠。"]'),
('c90a99de-2e7b-47e5-a507-adf9bdb49f4f','諸葛仁叟縣丞極貧能保風節有權貴招之不屑其行','戴復古','宋','宋诗','song-poetry','','[]','時人誰識老聾丞，滿口常談杜少陵。',64,'全唐诗/poet.song.182000.json','["時人誰識老聾丞，滿口常談杜少陵。", "俗輩衆多吾輩少，素交零落利交興。", "權門炙手炎如火，詩社投身冷似冰。", "堪笑皇天無老眼，相知頼有竹林僧。"]'),
('afb47e7e-3b5a-49e9-bc5f-1e0bcbced75a','萬安江上','戴復古','宋','宋诗','song-poetry','','[]','不能成佛不能僊，虛度人間六十年。',64,'全唐诗/poet.song.182000.json','["不能成佛不能僊，虛度人間六十年。", "鏡裏姿容雖老矣，酒邊意氣尚飄然。", "安排玉白花紅句，趁辦橙黄橘綠天。", "無柰秋風動歸興，明朝問訊下江船。"]'),
('db7ca74b-0248-4d89-9f42-860bb4ca0d35','過昭武訪李友山詩社諸人','戴復古','宋','宋诗','song-poetry','','[]','吟過長亭復短亭，喜於溪上訪詩朋。',64,'全唐诗/poet.song.182000.json','["吟過長亭復短亭，喜於溪上訪詩朋。", "雕鎪已被天公怒，狂狷仍遭俗子憎。", "故故愁人長夜雨，明明照我短檠燈。", "休思京口相逢日，喜雨樓中賦大鵬。"]'),
('141daed9-349a-4ac4-b114-eb4f35c9b3d2','李友山諸丈甚喜得朋留連日久月洲乃友山道號','戴復古','宋','宋诗','song-poetry','','[]','此身到處自悠悠，一笑非爲越女留。',64,'全唐诗/poet.song.182000.json','["此身到處自悠悠，一笑非爲越女留。", "風雨不妨雞戒曉，江湖又見鴈橫秋。", "途中有客居巖谷，天下何人似月洲。", "頗欲相從溪上住，諸君許我卜隣否。"]'),
('c0fe9ace-04e6-4cba-aa46-a47c2c079767','飲中','戴復古','宋','宋诗','song-poetry','','[]','布衣不換錦宮袍，刺骨清寒氣自豪。',64,'全唐诗/poet.song.182000.json','["布衣不換錦宮袍，刺骨清寒氣自豪。", "腹有別腸能貯酒，天生左手慣持螯。", "蠅隨驥尾宜千里，鶴在鷄群亦九皋。", "賢似屈平因獨醒，不禁顦顇賦離騷。"]'),
('23410b25-a255-435e-a1c5-142200d2695e','陪徐淵子使君登白雪樓約各賦一詩必以宋玉石對莫愁村','戴復古','宋','宋诗','song-poetry','','[]','樓名白雪因詞勝，千古江山春雨餘。',64,'全唐诗/poet.song.182000.json','["樓名白雪因詞勝，千古江山春雨餘。", "宋玉遺蹤兩蒼石，莫愁居處一荒墟。", "風橫烟艇客呼渡，水落沙洲人網魚。", "借問風流賢太守，孟亭添得野夫無。"]'),
('5c499cdc-f615-41da-8b5f-37a058cddbef','靜齋張敏則舍人贈詩因用其韵爲酬','戴復古','宋','宋诗','song-poetry','','[]','胸次詩書一派清，學如耕稼到秋成。',64,'全唐诗/poet.song.182000.json','["胸次詩書一派清，學如耕稼到秋成。", "十年閉戶存吾道，萬事無心逐世情。", "葉落花開關氣數，山長水遠是功名。", "摩挲老眼看新貴，九鼎鴻毛孰重輕。"]'),
('d081d06b-8257-488f-92dd-6e426ce6cfcb','客游','戴復古','宋','宋诗','song-poetry','','[]','不能鬰鬰窟中藏，大笑出門游四方。',64,'全唐诗/poet.song.182000.json','["不能鬰鬰窟中藏，大笑出門游四方。", "與世周旋持酒盞，觀人勝敗坐碁坊。", "倒餐甘蔗入佳境，晝著錦衣歸故鄉。", "此志十年猶未遂，倚樓心事楚天長。"]'),
('7263a106-424a-4528-85c9-34283234bb3f','都下書懷','戴復古','宋','宋诗','song-poetry','','[]','京華作夢十年餘，不道南山有弊廬。',64,'全唐诗/poet.song.182000.json','["京華作夢十年餘，不道南山有弊廬。", "白髮生來美人笑，黄金散盡故交疎。", "明知弄巧翻成拙，除却謀歸總是虛。", "出處古人都說盡，功名未必勝鱸魚。"]'),
('eff9610b-e11e-404b-b87a-1537a2bd6035','新安寒食','戴復古','宋','宋诗','song-poetry','','[]','不擬今年到歙州，要知行止豈人謀。',64,'全唐诗/poet.song.182000.json','["不擬今年到歙州，要知行止豈人謀。", "一百五日客懷惡，三十六峰春雨愁。", "老矣此身猶道路，凄其歸夢繞松楸。", "花瓢僊子無由見，千里江山負遠游。"]'),
('1f7d9468-4d2e-4c39-b9ea-398c946b0ae4','烏聊山登覽','戴復古','宋','宋诗','song-poetry','','[]','抖擻囂塵上翠微，旁溪寺上坐題詩。',64,'全唐诗/poet.song.182000.json','["抖擻囂塵上翠微，旁溪寺上坐題詩。", "忽聞啼鳥不知處，細看好山無厭時。", "風掃雲烟開遠景，人携香火謁叢祠。", "客來千里登臨意，說與時人未必知。"]'),
('bdc83ff3-4ed0-4ee3-b4ed-94a46071e485','癖習','戴復古','宋','宋诗','song-poetry','','[]','平生癖習未全除，虛事經心實事疎。',64,'全唐诗/poet.song.182000.json','["平生癖習未全除，虛事經心實事疎。", "爲惜落花慵掃地，每看脩竹欲移居。", "逢人共作亡何飲，撥冗時觀未見書。", "爭柰一貧隨我在，思量不若把犁鋤。"]'),
('737226f5-8637-4605-b2eb-1c33ed880b92','田園吟','戴復古','宋','宋诗','song-poetry','','[]','自古田園活計長，醉敲牛角取宮商。',64,'全唐诗/poet.song.182000.json','["自古田園活計長，醉敲牛角取宮商。", "催耕啼後新秧綠，鍛磨鳴時大麥黄。", "桐樹著花茶戶富，梅林無實秫田荒。", "狂夫本是農家子，拋却一犁遊四方。"]'),
('afbbcc50-7eda-4e52-b4ee-c038d8190b9f','九日登裴公亭得無災可避自登山之句何季皋滕審言爲之擊節足以成篇','戴復古','宋','宋诗','song-poetry','','[]','良辰樂事兩相關，不可不求今日閒。',64,'全唐诗/poet.song.182000.json','["良辰樂事兩相關，不可不求今日閒。", "有酒能賒堪薦菊，無災可避自登山。", "心懷屈賈千年上，身在瀟湘八景間。", "好向樽前開笑口，人生枉自作愁顔。"]'),
('28fb4ee6-59b4-4f52-aeb2-ab5f32bfeb91','趙升卿有官不肯爲里居有賢聲訪之於深巷中','戴復古','宋','宋诗','song-poetry','','[]','深居陋巷不妨幽，翠竹當門水滿溝。',64,'全唐诗/poet.song.182000.json','["深居陋巷不妨幽，翠竹當門水滿溝。", "每遇事來先覺懶，欲爲官去又還休。", "田園自樂陶元亮，鄉里多稱馬少游。", "除却讀書無所好，有時閑作北巖遊。"]'),
('37c2b011-9b01-40c9-b36d-9daf96e742ad','括蒼石門瀑布','戴復古','宋','宋诗','song-poetry','','[]','少泊石門觀瀑布，明知是水却疑非。',64,'全唐诗/poet.song.182000.json','["少泊石門觀瀑布，明知是水却疑非。", "亂拋雪玉從天下，散作雲烟到地飛。", "夜聽蕭蕭洗塵夢，風吹細細濕人衣。", "謝公蠟屐經行處，聞有留題在翠微。"]'),
('19c24dc5-7b9f-4ed1-a86c-b546b4d0a4e0','杜門自遣','戴復古','宋','宋诗','song-poetry','','[]','世事茫茫心事灰，衆人爭處我驚回。',64,'全唐诗/poet.song.182000.json','["世事茫茫心事灰，衆人爭處我驚回。", "閉門不管花開落，避俗唯通燕往來。", "富貴在天求不得，光陰轉地老相催。", "平生任達陶元亮，千載神交共一杯。"]'),
('101e0779-a2a9-4d74-a065-6f5308166c08','登快閣黄明府强使和山谷先生留題之韵','戴復古','宋','宋诗','song-poetry','','[]','未登快閣心先快，紅日半簷秋雨晴。',64,'全唐诗/poet.song.182000.json','["未登快閣心先快，紅日半簷秋雨晴。", "宇宙無邊萬山立，雲烟不動八窗明。", "飛來一鶴天相近，過盡千帆江自橫。", "借問金華老僊伯，幾人無忝入詩盟。"]'),
('55ff83c1-923d-42e9-928b-2dee7bef5afb','滕王閣次韵劉允叔','戴復古','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','消遣客懷尋勝事，酒杯詩卷得同携。',64,'全唐诗/poet.song.182000.json','["消遣客懷尋勝事，酒杯詩卷得同携。", "當年傑閣棲龍子，今日空梁落燕泥。", "斜照浴紅秋水上，好山橫碧畫欄西。", "幾人登覽皆磨滅，唯有前峰壓不低。"]'),
('d071a8f3-ab6f-4f0b-91e7-4102f95914f3','竹洲諸姪孫小集永嘉蔣子高有詩次韵','戴復古','宋','宋诗','song-poetry','','[]','美景能兼樂事難，愁來唯仗酒遮攔。',64,'全唐诗/poet.song.182000.json','["美景能兼樂事難，愁來唯仗酒遮攔。", "昂藏病骨兼詩瘦，料峭春風带臘寒。", "喬木尚疑前輩在，好花應笑老人看。", "忍拋明月先歸去，輸與諸郎徹夜歡。"]'),
('697763e7-690b-4087-95e8-2da81f8f3b6d','游雲溪與郡宴用太守韵即事二首  其一','戴復古','宋','宋诗','song-poetry','','[]','溪堂久矣無人到，千騎傳呼五馬來。',64,'全唐诗/poet.song.182000.json','["溪堂久矣無人到，千騎傳呼五馬來。", "流水奔騰砥柱立，好山呈露晚雲開。", "指揮壯士馳驍騎，管領衰翁吊古梅。", "笑問風流羊叔子，幾人登覽不塵埃。"]'),
('0cf50305-b926-4cbc-a11a-2cbdee2f6d9f','游雲溪與郡宴用太守韵即事二首  其二','戴復古','宋','宋诗','song-poetry','','[]','官府太平無一事，凝香座上著衰翁。',64,'全唐诗/poet.song.182000.json','["官府太平無一事，凝香座上著衰翁。", "飄摇短棹游方沼，縹緲高樓倚半空。", "把酒夜深霜落後，吹簫人在月明中。", "使君笑指梅花說，去歲今年事不同。"]'),
('08afc5d3-ed4a-4819-b5c3-d34110b430e1','和高與權','戴復古','宋','宋诗','song-poetry','','[]','相逢休說昧平生，高適能詩久擅名。',64,'全唐诗/poet.song.182000.json','["相逢休說昧平生，高適能詩久擅名。", "欲課荒蕪來入社，羞將老醜對傾城。", "近來客裏仍多病，强向花前舉一觥。", "樂極自傷頭白早，罇前知我孟雲卿。"]'),
('d0543c3c-27c0-4d7f-92df-0840d94a7a4a','懷雪蓬姚希聲使君  其一','戴復古','宋','宋诗','song-poetry','','[]','寒入疎蓬夜雪深，是非難辯口如瘖。',64,'全唐诗/poet.song.182000.json','["寒入疎蓬夜雪深，是非難辯口如瘖。", "一官不幸有奇禍，萬事但求無愧心。", "想像騎牛開畫卷，丁寧回鴈寄來音。", "傳家一首冰壺賦，未信橫舟竟陸沉。"]'),
('facafc4b-95cb-4a04-9e2c-ab5b33283da8','懷雪蓬姚希聲使君  其二','戴復古','宋','宋诗','song-poetry','','[]','有感中來不自禁，短長亭下短長吟。',64,'全唐诗/poet.song.182000.json','["有感中來不自禁，短長亭下短長吟。", "梅花差可强人意，竹葉安能醉我心。", "世事無憑多改變，仕途相識半昇沉。", "摩挲老眼從頭看，只有青山無古今。"]'),
('3b28b496-0a43-4e96-9073-85187f8b4092','豫章東湖宋謙甫黄存之酌別','戴復古','宋','宋诗','song-poetry','','[]','湖邊長記昔年游，生怕清波照白頭。',64,'全唐诗/poet.song.182000.json','["湖邊長記昔年游，生怕清波照白頭。", "楊柳蕭疎多困雨，芰荷顦顇早驚秋。", "無功及物談何益，有酒開懷醉即休。", "江上買舟猶未定，明朝尚可爲君留。"]'),
('59478549-5bb7-4174-adb3-c40459f58453','都中懷竹隠徐淵子直院','戴復古','宋','宋诗','song-poetry','','[]','手携漫刺訪朝官，爭似滄洲把釣竿。',64,'全唐诗/poet.song.182000.json','["手携漫刺訪朝官，爭似滄洲把釣竿。", "萬事看從今日別，九原叫起古人難。", "菊花到死猶堪惜，秋葉雖紅不耐觀。", "多謝天公憐客意，霜風未忍放深寒。"]'),
('e3939b05-d48a-4ae0-91cf-144371d3162d','人日','戴復古','宋','宋诗','song-poetry','','[]','自換端平新曆日，眼看日月倍光輝。',64,'全唐诗/poet.song.182000.json','["自換端平新曆日，眼看日月倍光輝。", "南州有雪古來少，人日不陰今見稀。", "鼓舞萬方觀德化，轉移一世屬天機。", "朝廷有道吾君聖，辦作昇平老布衣。"]'),
('88c6978d-81d1-463e-94cf-25f2b09dda06','送劉鎮叔安入京謫居三山二十餘年，真西山奏令自便，趙用父使君爲唱餞其行，坐客二十八人分韵賦詩，得君字','戴復古','宋','宋诗','song-poetry','','[]','二十餘年謫宦身，此行便可上青雲。',64,'全唐诗/poet.song.182000.json','["二十餘年謫宦身，此行便可上青雲。", "西山一手爲推轂，南浦幾人爭送君。", "橫水流傳無垢集，海神驚見老坡文。", "回頭莫有關情處，別酒須教滿十分。"]'),
('bcb75420-8a81-4ebc-acad-936b3343435b','三山林唐傑潘庭堅張農師會于丁巖仲新樓','戴復古','宋','宋诗','song-poetry','','[]','又携詩卷到南州，塵滿征衫雪滿頭。',64,'全唐诗/poet.song.182000.json','["又携詩卷到南州，塵滿征衫雪滿頭。", "桃李春風故園夢，江山落日異鄉愁。", "樽前一笑真奇事，坐上諸君盡勝流。", "政倚清談洗胸臆，莫教王粲賦登樓。"]'),
('b025d092-9715-47e4-b070-9d170c9b76d0','次韵杜運使見贈','戴復古','宋','宋诗','song-poetry','','[]','飄零敢說是詩人，故舊多居要路津。',64,'全唐诗/poet.song.182000.json','["飄零敢說是詩人，故舊多居要路津。", "窮賤交游誰復記，江湖蹤跡早成陳。", "無心涉世當歸隠，有口逢人肯說貧。", "家在翠屏山下住，茅廬雖小可容身。"]'),
('b0ae7fd6-12ef-46a6-a4cc-8d1512efd4af','訪漳州趙用父使君','戴復古','宋','宋诗','song-poetry','','[]','幸遇故人爲太守，客來不憚路程遥。',64,'全唐诗/poet.song.182000.json','["幸遇故人爲太守，客來不憚路程遥。", "九龍山水連滄海，五馬聲名動紫霄。", "一意奉行寬大詔，多君不負聖明朝。", "欲知惠愛及人處，聽取街頭賣炭謠。"]'),
('f92dcd48-9031-4d3c-9818-b9f0b50da52e','見曾提刑兼安撫','戴復古','宋','宋诗','song-poetry','','[]','傳家學術用如新，風采英英照七閩。',64,'全唐诗/poet.song.182000.json','["傳家學術用如新，風采英英照七閩。", "澄按併開都督府，平反專奉太夫人。", "關河未定心憂國，麾節相仍澤在民。", "聞說青雲多故舊，不應久作外臺臣。"]'),
('41a2f3c6-1f11-4ba8-84e0-8b27a65f215d','思歸  其一','戴復古','宋','宋诗','song-poetry','','[]','地上皇皇蟣虱臣，著衣喫飯亦君恩。',64,'全唐诗/poet.song.182000.json','["地上皇皇蟣虱臣，著衣喫飯亦君恩。", "不能待詔金鑾殿，嘗欲獻詩光範門。", "身在草茅憂社稷，恨無毫髮補乾坤。", "才疎命薄成何事，白首歸耕東海村。"]'),
('e743c828-b3d8-4dc2-9e98-1c61a86d5419','思歸  其二','戴復古','宋','宋诗','song-poetry','','[]','躬耕海上奈無田，乍可經營買釣船。',64,'全唐诗/poet.song.182000.json','["躬耕海上奈無田，乍可經營買釣船。", "未有人供令狐米，欲從鬼借尉遲錢。", "回頭歸路三千里，藉手還鄉五百篇。", "幸遇太平時節好，白雲深處了殘年。"]'),
('8fe7c2c9-d688-4818-bcc2-ab542db1d0b8','趙克勤曾橐卿景壽同登黄南恩南樓  其一','戴復古','宋','宋诗','song-poetry','','[]','欲從高處賞新秋，上盡層坡更上樓。',64,'全唐诗/poet.song.182000.json','["欲從高處賞新秋，上盡層坡更上樓。", "天地無窮吾輩老，江山有恨古人休。", "寧隨狡兔營三窟，且跨飛鴻閲九州。", "憶著當年杜陵老，一生飄泊也風流。"]'),
('95dbcc22-4bf2-4f78-b64b-24700e986948','趙克勤曾橐卿景壽同登黄南恩南樓  其二','戴復古','宋','宋诗','song-poetry','','[]','鄂州南樓不可到，到此南樓眼亦青。',64,'全唐诗/poet.song.182000.json','["鄂州南樓不可到，到此南樓眼亦青。", "乾坤日月與高致，城郭江山無遁形。", "把酒縱談心耿耿，倚欄遐眺鬢星星。", "世間萬事關愁思，莫使秋風吹酒醒。"]'),
('bce294e7-ecbe-46c3-a9a7-ef2519742933','山行遇秀癡翁','戴復古','宋','宋诗','song-poetry','','[]','新冬行樂賞新晴，幾箇江湖舊友朋。',64,'全唐诗/poet.song.182000.json','["新冬行樂賞新晴，幾箇江湖舊友朋。", "霜蟹得橙同臭味，梅花與菊作交承。", "樽前盡是論文客，林下那逢好事僧。", "機解到時言語別，李翶詩句入傳燈。"]'),
('aa6ff931-cf8c-4ece-a1a8-8497cbd5f69d','石亭野老家','戴復古','宋','宋诗','song-poetry','','[]','野老將余到石亭，先呼小豹出相迎。',64,'全唐诗/poet.song.182000.json','["野老將余到石亭，先呼小豹出相迎。", "依凭林谷住家穩，奔走兒童見客驚。", "牛豕與人爭徑路，桑麻繞屋蔽柴荆。", "溪邊不合栽桃李，猶恐春風惹世情。"]'),
('5337dc22-1e89-4277-b26b-049c82d0877a','讀王幼學上殿劄子','戴復古','宋','宋诗','song-poetry','','[]','才到朝廷被論歸，孤忠幸有九重知。',64,'全唐诗/poet.song.182000.json','["才到朝廷被論歸，孤忠幸有九重知。", "神醫能識未蘇病，國手難翻已敗碁。", "四海爭傳治安策，諸公如在太平時。", "老夫懷抱緣何事，未到秋來早自悲。"]'),
('2ffe36e2-602f-4fd1-857d-4b549c4bd13a','謝史石窗送酒并茶','戴復古','宋','宋诗','song-poetry','','[]','遣來二物應時須，客子行厨用有餘。',64,'全唐诗/poet.song.182000.json','["遣來二物應時須，客子行厨用有餘。", "午困政須茶料理，春愁全仗酒消除。", "不勝歡喜拜嘉惠，無限慇懃作謝書。", "君既有來何以報，一牀蘄簟兩淮魚。"]'),
('b9474ede-2468-4824-bba5-a58914509bfb','閲舊稿見喬丞相詩跋因成此詩','戴復古','宋','宋诗','song-poetry','','[]','三十年前舊詩冊，兩行鈞翰儼如新。',64,'全唐诗/poet.song.182000.json','["三十年前舊詩冊，兩行鈞翰儼如新。", "自甘白屋爲寒士，敢說黄扉有故人。", "五雨十風勤燮理，九州四海費經綸。", "年踰八十貂蟬貴，不負明君恐負身。"]'),
('906147a5-30c9-4274-89e9-126ca13d8ad4','衡陽度歲','戴復古','宋','宋诗','song-poetry','','[]','爲懷賈誼到長沙，又過衡雲湘水涯。',64,'全唐诗/poet.song.182000.json','["爲懷賈誼到長沙，又過衡雲湘水涯。", "詩酒放懷真是癖，江湖久客若無家。", "茫茫萬事生春夢，草草三杯度歲華。", "把定東風笑相問，忍將桃李換梅花。"]'),
('86a55d23-19ad-4e37-9575-eb23184a067c','遇張韓伯說邊事','戴復古','宋','宋诗','song-poetry','','[]','每上高樓欲斷魂，沿江市井幾家存。',64,'全唐诗/poet.song.182000.json','["每上高樓欲斷魂，沿江市井幾家存。", "飛鴻歷歷傳邊信，芳草青青補燒痕。", "北望苦無多世界，南來別是一乾坤。", "相逢莫說傷心事，且把霜螯薦酒樽。"]'),
('19864814-128f-4a09-a7d7-2c0232dd3943','有議袁蒙齋者','戴復古','宋','宋诗','song-poetry','','[]','世上苦無公是非，譏評人物信猶疑。',64,'全唐诗/poet.song.182000.json','["世上苦無公是非，譏評人物信猶疑。", "鏡中妍醜無私照，棋上高低有誤時。", "懷古尚餘喬木在，傷春唯許落花知。", "黄金可辦將何用，鑄出當年鍾子期。"]'),
('9701c7cf-d128-448b-8d1c-47c1079abec9','醉吟','戴復古','宋','宋诗','song-poetry','','[]','草茅無路謁君王，白首終爲田舍郎。',64,'全唐诗/poet.song.182000.json','["草茅無路謁君王，白首終爲田舍郎。", "近讀南華資曠達，欲師西洛愧荒唐。", "乾坤萬象供詩料，風月一樓爲醉鄉。", "日晚棲禽歸自樂，飛鳴不是怨斜陽。"]'),
('01bd40f5-2ebb-4bb8-93c6-ffc69e45a4bc','慈雲避暑','戴復古','宋','宋诗','song-poetry','','[]','相邀避暑到慈雲，細聽諸君講見聞。',64,'全唐诗/poet.song.182000.json','["相邀避暑到慈雲，細聽諸君講見聞。", "六月美宣歌北伐，五絃思舜奏南薰。", "不憂冷澹無歡伯，自致清凉有此君。", "想像當時河朔飲，樽前不用著紅裙。"]'),
('e51a4850-0ad4-41b0-baec-1fc185ce4f3e','久客還鄉','戴復古','宋','宋诗','song-poetry','','[]','短簷紗帽舊麻衣，鐵杖扶衰步履遲。',64,'全唐诗/poet.song.182000.json','["短簷紗帽舊麻衣，鐵杖扶衰步履遲。", "老去分爲無用物，客游誰道有歸時。", "豐年村落家家酒，秋日樓臺處處詩。", "生長此方真樂土，江淮百姓政流離。"]'),
('d45bbc62-0ed8-4e49-8927-c0cba5d56498','聞時事','戴復古','宋','宋诗','song-poetry','','[]','昨報西師奏凱還，近聞北顧一時寬。',64,'全唐诗/poet.song.182000.json','["昨報西師奏凱還，近聞北顧一時寬。", "淮西勳業歸裴度，江右聲名屬謝安。", "夜雨忽晴看月好，春風漸老惜花殘。", "事關氣數君知否，麥到秋時天又寒。"]'),
('3435dfea-e47e-4668-9693-06699b2df660','寄趙德行','戴復古','宋','宋诗','song-poetry','','[]','平生幸甚識諸公，未免歸爲田舍翁。',64,'全唐诗/poet.song.182000.json','["平生幸甚識諸公，未免歸爲田舍翁。", "詩稿敢求經御覽，客身自笑坐天窮。", "肯將釣手遮西日，獨聳吟肩訴北風。", "枉使西山有遺恨，不能置我玉堂中。"]'),
('4d3834f2-c5e1-469b-84ed-893008d7ee14','到鄂渚','戴復古','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','連宵歌舞醉東樓，不信樽前有別愁。',64,'全唐诗/poet.song.182000.json','["連宵歌舞醉東樓，不信樽前有別愁。", "半夜月明何處笛，長江風送故人舟。", "十年浪迹游淮甸，一枕高眠到鄂州。", "明日擬蘇堤上看，當春楊柳政風流。"]'),
('7c3fcc55-c558-435f-8c5f-f6c8270ac6ed','艤棹清江','戴復古','宋','宋诗','song-poetry','','[]','艤棹江濱訪舊游，十年重到戲漁洲。',64,'全唐诗/poet.song.182000.json','["艤棹江濱訪舊游，十年重到戲漁洲。", "不知芳樹在何許，但見落花從此流。", "我醉欲眠因假榻，客行未定且登樓。", "有錢賸買張家酒，準備明朝話別愁。"]'),
('7e08fb9a-bb12-47cb-8c71-f3c7b55961c3','萬安縣芙蓉峰','戴復古','宋','宋诗','song-poetry','','[]','凌空傑閣爲誰開，隔岸芙蓉不用栽。',64,'全唐诗/poet.song.182000.json','["凌空傑閣爲誰開，隔岸芙蓉不用栽。", "今古相傳彩雲現，江山曾識大蘇來。", "酒邊歌舞共一笑，客裏登臨能幾回。", "翠浪玉虹從此去，明朝人在鬰孤臺。"]'),
('2eb4dffa-c65a-485c-87b3-c6e31b70285a','汪見可約游青原','戴復古','宋','宋诗','song-poetry','','[]','來訪青原古釣磯，溪流衮衮濯龍奇。',64,'全唐诗/poet.song.182000.json','["來訪青原古釣磯，溪流衮衮濯龍奇。", "一茶可款從僧話，數局爭先對客碁。", "雲雨那能敗吾事，山林政喜得君詩。", "石頭路滑籃輿小，換得扁舟在水湄。"]'),
('a9d8a0df-df9c-4559-a9e7-e52c06e64a1a','除夜','戴復古','宋','宋诗','song-poetry','','["\u6625\u8282"]','掃除茅舍滌塵囂，一炷清香拜九霄。',64,'全唐诗/poet.song.183000.json','["掃除茅舍滌塵囂，一炷清香拜九霄。", "萬物迎春送殘臘，一年結局在今宵。", "生盆火烈轟鳴竹，守歲筵開聽頌椒。", "野客預知農事好，三冬瑞雪未全消。"]'),
('fd73534f-58c4-46b6-8cd9-24d819184a90','黎明府約尋梅','戴復古','宋','宋诗','song-poetry','','[]','霽雪園林粲陸離，九峰山下探梅時。',64,'全唐诗/poet.song.183000.json','["霽雪園林粲陸離，九峰山下探梅時。", "三川風月醉中見，百里襟懷琴上知。", "老樹著花春到早，長街籠燭夜歸遲。", "奚囊一路生光采，中有琴堂唱和詩。"]'),
('98a24380-952d-4644-8940-1cd0a4d0c32c','葉宗裔爲令叔求竹山詩  其一','戴復古','宋','宋诗','song-poetry','','[]','愛竹舊稱王子猷，今君異世等風流。',64,'全唐诗/poet.song.183000.json','["愛竹舊稱王子猷，今君異世等風流。", "山中便是清凉國，門下合封瀟洒侯。", "有此一堂真可隠，不妨諸姪與同游。", "吟邊想像參差綠，許我携琴一到不。"]'),
('027696de-4a5b-4bdc-bc0a-02495e995b45','葉宗裔爲令叔求竹山詩  其二','戴復古','宋','宋诗','song-poetry','','[]','一景分明似渭川，竹山堂好以人賢。',64,'全唐诗/poet.song.183000.json','["一景分明似渭川，竹山堂好以人賢。", "蘭亭價爲羲之重，峴首名因叔子傳。", "紫翠數峰長在眼，琅玕萬箇欲參天。", "老夫身墮塵埃底，遥挹清風亦洒然。"]'),
('b6003770-e8d6-4514-b9aa-998cca012f5c','春日風雨中','戴復古','宋','宋诗','song-poetry','','[]','瀟瀟風雨閉柴門，年紀衰頹病著身。',64,'全唐诗/poet.song.183000.json','["瀟瀟風雨閉柴門，年紀衰頹病著身。", "大似梁鴻居海曲，略如公幹卧漳濱。", "三春晴暖無多日，一世安閑有幾人。", "聞道明朝新醖熟，不妨祭竈請比隣。"]'),
('8e5b1229-52c6-4a84-aa71-11e9529fad3d','寄吳明輔秘丞  其一','戴復古','宋','宋诗','song-poetry','','[]','吾鄉幸有吳夫子，星斗網羅文字胸。',64,'全唐诗/poet.song.183000.json','["吾鄉幸有吳夫子，星斗網羅文字胸。", "百鳥收聲聽鳴鳳，千山落木秀孤松。", "旁通滄海江山水，高壓雲城帢幘峰。", "每見一斑三歎息，白頭未得奉從容。"]'),
('6cdd1e6d-31a0-410d-9f9d-15f8a9da8767','寄吳明輔秘丞  其二','戴復古','宋','宋诗','song-poetry','','[]','七十七翁猶眼明，三台星畔見奎星。',64,'全唐诗/poet.song.183000.json','["七十七翁猶眼明，三台星畔見奎星。", "文章有氣吞餘子，議論無差本六經。", "愧我不能攀逸駕，得君自足振頹齡。", "玉溪常與荆溪接，分得餘波到石屏。"]'),
('6646dbd9-f182-49bd-9b14-6e51e627e2c0','靈洲梅花','戴復古','宋','宋诗','song-poetry','','[]','穿林傍水幾平章，合有春風到草堂。',64,'全唐诗/poet.song.183000.json','["穿林傍水幾平章，合有春風到草堂。", "自入冬來多是暖，無尋花處却聞香。", "枝南枝北一輪月，山後山前兩履霜。", "直看過年開未了，醉吟且放老夫狂。"]'),
('1879c736-5b49-4830-8ad4-12fb925b0534','寄廣西漕陳魯叟誥院','戴復古','宋','宋诗','song-poetry','','[]','回首元龍百尺樓，一時詩酒記同遊。',64,'全唐诗/poet.song.183000.json','["回首元龍百尺樓，一時詩酒記同遊。", "好山歷歷在人眼，流水滔滔任客舟。", "歸鴈欲從何處去，落花恨不爲春留。", "錦囊佳句無人問，自別君來白盡頭。"]'),
('675775ce-8534-4151-83f8-f6b85b52f429','隨軍轉運司王宣子上巳日會客','戴復古','宋','宋诗','song-poetry','','[]','邊頭相遇若相期，又見隨軍轉運司。',64,'全唐诗/poet.song.183000.json','["邊頭相遇若相期，又見隨軍轉運司。", "憶昨醉君京口酒，傷今讀我石壕詩。", "蘭亭飲客酬佳節，淝水收功定幾時。", "準擬看花花較少，春風全在綠楊枝。"]'),
('40264d05-c2ff-448d-af55-0bf0d3098f6e','湖廣李漕革夫大卿飲客西湘','戴復古','宋','宋诗','song-poetry','','[]','管領風光此會稀，坐中賓客總能詩。',64,'全唐诗/poet.song.183000.json','["管領風光此會稀，坐中賓客總能詩。", "神仙有洞尋難見，山水當軒看轉奇。", "春不再生陶侃柏，人來多打李邕碑。", "因思屈賈傷今古，國有忠臣無用時。"]'),
('ed742cf6-fe75-4b82-bbc2-85020d5a7922','曾雲巢同相勉李玉澗不赴召','戴復古','宋','宋诗','song-poetry','','[]','詔書催赴紫宸班，九奏君王乞掛冠。',64,'全唐诗/poet.song.183000.json','["詔書催赴紫宸班，九奏君王乞掛冠。", "日暮倒行非我事，急流勇退有何難。", "地靈不隠金砂勝，秋水長流玉澗寒。", "好把山林寄圖畫，試教天下故人看。"]'),
('bb09e270-a893-469b-8e9b-f56e5d41547a','寄撫州樓使君','戴復古','宋','宋诗','song-poetry','','[]','夢上江西江上船，行隨五馬五峰前。',64,'全唐诗/poet.song.183000.json','["夢上江西江上船，行隨五馬五峰前。", "臨川太守賢無敵，攻媿先生學有傳。", "佳政可書循吏傳，斯民共樂太平年。", "不知擬峴臺前景，公暇清吟得幾篇。"]'),
('3e21197c-8391-4187-b024-115d1d2da194','江山','戴復古','宋','宋诗','song-poetry','','[]','借得茅樓一倚欄，見成詩句滿江天。',64,'全唐诗/poet.song.183000.json','["借得茅樓一倚欄，見成詩句滿江天。", "歸鴉啼處客投宿，野鴨飛邊人上船。", "老眼尚嫌隨物轉，閑心可惜被貧牽。", "平生錯做功名夢，金印何時二頃賢。"]'),
('f9d945fc-2f98-456b-9100-83649598a207','京口遇薛野鶴','戴復古','宋','宋诗','song-poetry','','[]','天下江山第一州，可能無地著詩流。',64,'全唐诗/poet.song.183000.json','["天下江山第一州，可能無地著詩流。", "黄金不愛買官職，白髮猶堪上酒樓。", "懊恨牡丹遭雨厄，叮嚀芍藥爲春留。", "狂吟有禁風騷歇，語燕啼鶑代唱酬。"]'),
('ee52ba12-f047-4c6b-9968-dbabd7f31b03','題邵武熙春臺呈王子文使君','戴復古','宋','宋诗','song-poetry','','[]','步到風烟上上頭，恍如造物與同游。',64,'全唐诗/poet.song.183000.json','["步到風烟上上頭，恍如造物與同游。", "千山表裏重圍過，一水中間自在流。", "近郭樓臺隔雲見，鄰峰鍾磬出林幽。", "風流太守詩無敵，有暇登臨共唱酬。"]'),
('e7dab08d-4b5e-476a-a27f-43f8ceff00fe','秋日病餘','戴復古','宋','宋诗','song-poetry','','[]','桂子吹香風露深，老夫吟了聽蟬吟。',64,'全唐诗/poet.song.183000.json','["桂子吹香風露深，老夫吟了聽蟬吟。", "秋來賸有行山興，病後全無涉世心。", "詩苦積成雙白髮，酒豪輕用萬黄金。", "平生意氣今如許，獨抱傳家一破琴。"]'),
('dec69ea0-8d87-4e5d-a3bf-6f326585ed78','次韵郡倅王子文小園詠春','戴復古','宋','宋诗','song-poetry','','[]','州縣徒勞喜近民，民間何事不關身。',64,'全唐诗/poet.song.183000.json','["州縣徒勞喜近民，民間何事不關身。", "誰知風月臺中客，自是絲綸閣上人。", "萬縷綠垂楊柳雨，一梢紅破海棠春。", "小園暫作風光主，朝馬行隨輦路塵。"]'),
('5c755bcf-f07c-441f-b24c-b9aaddf5ed8b','安豐倅李華被旨監軍入閩討賊華身督諸將先破賊巢穴所鄉輒勝招捕使之成功監軍之力居多守汀州四年民頼以安有應變壓難之才僕遊汀邵間實知其詳爲賦二首  其一','戴復古','宋','宋诗','song-poetry','','[]','三年壯士起淮濆，賈勇從公定七閩。',64,'全唐诗/poet.song.183000.json','["三年壯士起淮濆，賈勇從公定七閩。", "在昔猩鼯中夜嘯，而今桃李萬山春。", "臨危性命輕如葉，破敵機鋒妙若神。", "自此南人不知反，使君還亦是天人。"]'),
('6dab02f9-505d-4d5d-800e-e41b56ed867d','安豐倅李華被旨監軍入閩討賊華身督諸將先破賊巢穴所鄉輒勝招捕使之成功監軍之力居多守汀州四年民頼以安有應變壓難之才僕遊汀邵間實知其詳爲賦二首  其二','戴復古','宋','宋诗','song-poetry','','[]','英雄疎畧書生腐，守調如公天下無。',64,'全唐诗/poet.song.183000.json','["英雄疎畧書生腐，守調如公天下無。", "眼底紛紛付談笑，胸中事事有規模。", "從他要路爭馳轂，獨坐偏州再剖符。", "平寇功成在誰手，亂山深處問樵夫。"]'),
('c97d660d-3c04-4c40-9226-37ce237f350b','海上魚西寺','戴復古','宋','宋诗','song-poetry','','[]','北風三日弭行舟，登陸因爲島寺游。',64,'全唐诗/poet.song.183000.json','["北風三日弭行舟，登陸因爲島寺游。", "自笑奔馳如野馬，本無拘束似沙鷗。", "人誰與語自緘口，山有可觀頻舉頭。", "小雨疎烟晚來景，老僧相對倚鐘樓。"]'),
('11e6790f-f928-4b54-a245-99b92b907238','甘窮','戴復古','宋','宋诗','song-poetry','','[]','自甘寂寞坐詩窮，何取多牛積穀翁。',64,'全唐诗/poet.song.183000.json','["自甘寂寞坐詩窮，何取多牛積穀翁。", "痛飲不孤連夜月，浮生禁得幾秋風。", "芙蓉媚日紅相對，螃蟹著霜黄在中。", "白盡鬚毛無可老，此身未死抑愁儂。"]'),
('35281d3b-2d83-4fc3-be33-967816725bcd','詠梅投所知','戴復古','宋','宋诗','song-poetry','','[]','潔白無瑕美不嬌，烱如珠玉粲林皋。',64,'全唐诗/poet.song.183000.json','["潔白無瑕美不嬌，烱如珠玉粲林皋。", "獨開殘臘與時背，奄勝衆芳其格高。", "欲啟月宮休種桂，如何仙苑却栽桃。", "不將品質分優劣，痛飲花前讀楚騷。"]'),
('87522807-c1d7-4254-a0fa-b0471208cd8b','黄州竹樓呈謝國正','戴復古','宋','宋诗','song-poetry','','[]','每日黄堂事了時，一心惟恐上樓遲。',64,'全唐诗/poet.song.183000.json','["每日黄堂事了時，一心惟恐上樓遲。", "發揮天地讀周易，管領江山歌杜詩。", "切戒吏來呈簿曆，常邀客至共琴碁。", "風流太守誰其似，半似元之半牧之。"]'),
('a71cc833-dccb-4a94-9526-1f98277b5b38','漢陽登覽呈王中甫使君','戴復古','宋','宋诗','song-poetry','','[]','西州城郭雖然小，江漢規模壯矣哉。',64,'全唐诗/poet.song.183000.json','["西州城郭雖然小，江漢規模壯矣哉。", "大別山頭觀禹迹，楚波亭上望吳臺。", "蕭蕭修竹鳳不至，漠漠平沙鴈又來。", "五馬相邀共登覽，欲酬秋興費詩材。"]'),
('ca3e3b9e-4992-4329-b9a9-aba28833eaf0','簡陳叔方問病','戴復古','宋','宋诗','song-poetry','','[]','聞君卧病知何病，醫者難從脈上尋。',64,'全唐诗/poet.song.183000.json','["聞君卧病知何病，醫者難從脈上尋。", "自是讀書多損氣，或緣憂國重驚心。", "飽參妙理牀頭易，細寫幽懷膝上琴。", "蛇影無疑自無恙，此方何止直千金。"]'),
('7efe87a4-4e8c-47cf-ad2d-c771f2c049f3','鍾春伯園林','戴復古','宋','宋诗','song-poetry','','[]','西風吹起蓴鱸興，八座歸來有此山。',64,'全唐诗/poet.song.183000.json','["西風吹起蓴鱸興，八座歸來有此山。", "林麓兩峰亭榭外，瀟湘一片水雲間。", "天生景物四時好，人滿乾坤幾箇閑。", "語喚石屏非浪語，常思蠟屐共躋攀。"]'),
('d3074ac4-4ccc-404d-968f-9e90ea1a88c5','清明前夢得花字','戴復古','宋','宋诗','song-poetry','','[]','白頭那辦老生涯，幸有癡兒可主家。',64,'全唐诗/poet.song.183000.json','["白頭那辦老生涯，幸有癡兒可主家。", "百歲光陰一場夢，三春消息幾番花。", "掃松預造清明酒，入峽先租穀雨茶。", "隨分支吾度時節，那求不死煉丹砂。"]'),
('2475482a-6342-4f61-8800-88037ae9e263','題王制機池上千巖奇觀','戴復古','宋','宋诗','song-poetry','','[]','華堂掩映一池清，著此崔巍若化成。',64,'全唐诗/poet.song.183000.json','["華堂掩映一池清，著此崔巍若化成。", "胸次玲瓏具丘壑，世間髣髹見蓬瀛。", "碧雲堆上千峰立，綠水光中萬象生。", "欲去河陽種桃李，回頭又覺宦情輕。"]'),
('a1c9cacc-b4bc-424d-ae94-4336a5ad515e','訪慧林寺僧因有詩','戴復古','宋','宋诗','song-poetry','','[]','故人有約訪鄉僧，少坐西林待晚晴。',64,'全唐诗/poet.song.183000.json','["故人有約訪鄉僧，少坐西林待晚晴。", "雙燕護雛更出入，群鴉攫肉鬭飛鳴。", "長溪積水流無盡，古木號風訴不平。", "一段見成公案在，請君判斷要分明。"]'),
('47ccdbc1-0ba5-4d0c-87ce-ffe5380a42d8','陳漕領客西園賞海棠','戴復古','宋','宋诗','song-poetry','','[]','追隨玉節賞仙葩，滿座風流客更嘉。',64,'全唐诗/poet.song.183000.json','["追隨玉節賞仙葩，滿座風流客更嘉。", "錦綉有光摇竹影，珍珠無價買春華。", "猩紅滴滴嬌含蕊，雪白紛紛老半花。", "肯對騷壇輕著語，后山詩句已名家。"]'),
('f6748352-f6bf-4912-aff2-1d872d408c84','王和甫主簿卜地改葬雙親一夕夢到一處風水佳甚及到鴈蕩羅漢寺後山宛如夢中所見及造壙衆石之中獨有一穴僅可容雙棺孝感如此','戴復古','宋','宋诗','song-poetry','','[]','仇香竭力奉雙親，孝感於天得此墳。',64,'全唐诗/poet.song.183000.json','["仇香竭力奉雙親，孝感於天得此墳。", "衆石中藏一抔土，來山面對五峰雲。", "龜鸞遠近參差見，龍虎低昂左右分。", "早見凌雲牡丹現，他年朱紫定紛紛。"]'),
('173eb8f8-4ee1-495c-800b-d8c537cab0ab','喜梅雨既晴','戴復古','宋','宋诗','song-poetry','','[]','屋角鳴禽弄好音，樓頭夏木綠陰陰。',64,'全唐诗/poet.song.183000.json','["屋角鳴禽弄好音，樓頭夏木綠陰陰。", "鑷空白髮愁根在，熟盡黄梅雨意深。", "苔榻有泥妨客坐，稻田足水慰農心。", "老夫已作豐年想，鼓腹思爲擊壤吟。"]'),
('b9dbf59f-1f6c-417e-9623-b56e9643dc58','李司直會客吳運幹有詩次韵','戴復古','宋','宋诗','song-poetry','','[]','使君高會集群仙，也使狂夫坐細氈。',64,'全唐诗/poet.song.183000.json','["使君高會集群仙，也使狂夫坐細氈。", "白璧一雙酬議論，青春十載棹觥船。", "客愁遇酒退三舍，梅信與春開一先。", "已辦扁舟明日去，幾時重得到花前。"]'),
('2d385e8d-0181-48af-a542-07a2c012e652','一相識無辜獲罪','戴復古','宋','宋诗','song-poetry','','[]','一宿津亭睡不成，愁來物物是離情。',64,'全唐诗/poet.song.183000.json','["一宿津亭睡不成，愁來物物是離情。", "月輪高掛山河影，江浪巧爲風雨聲。", "志士失塗爲鬼笑，佳人泣血送君行。", "塞翁得馬非爲福，公論如天久自明。"]'),
('d337e6b6-22f1-420f-a7b4-7456cf070dcc','送黄教授日巖之官章貢','戴復古','宋','宋诗','song-poetry','','[]','久矣聞名不相識，江湖還有見君時。',64,'全唐诗/poet.song.183000.json','["久矣聞名不相識，江湖還有見君時。", "出人意表發高論，入我眼中多好詩。", "欲對春風開笑口，不堪世事上愁眉。", "憑誰寄語謝安石，莫爲蒼生起太遲。"]'),
('8db25f23-e58a-48f2-ade3-2cf9c0c73b67','家居復有江湖之興','戴復古','宋','宋诗','song-poetry','','[]','寒儒家舍只尋常，破紙窗邊折竹床。',64,'全唐诗/poet.song.183000.json','["寒儒家舍只尋常，破紙窗邊折竹床。", "接物罕逢人可語，尋春多被雨相妨。", "庭垂竹葉因思酒，室有蘭花不炷香。", "到底閉門非我事，白鷗心性五湖傍。"]'),
('00c5a915-e2b9-4fbd-ab55-0f8baee99570','題亡室真像','戴復古','宋','宋诗','song-poetry','','[]','求名求利兩茫茫，千里歸來賦悼亡。',64,'全唐诗/poet.song.183000.json','["求名求利兩茫茫，千里歸來賦悼亡。", "夢井詩成增悵恨，鼓盆歌罷轉凄凉。", "情鍾我輩那容忍，乳臭諸兒最可傷。", "拂拭丹青呼不醒，世間誰有返魂香。"]'),
('39f25e98-5cb8-411a-a0fb-b3bb08ba04dc','題趙忠定公雪錦樓詩','戴復古','宋','宋诗','song-poetry','','[]','九鼎重安國勢牢，功名易辦謗難逃。',64,'全唐诗/poet.song.183000.json','["九鼎重安國勢牢，功名易辦謗難逃。", "手扶日月掃雲霧，身向江湖直羽毛。", "雪錦詩成先讖兆，金縢書啟見勤勞。", "紛紛論定知忠定，不負朝廷兩字褒。"]'),
('d1354b45-99f3-4066-8b96-6e7b01cdeb4d','陪厲寺丞賞芍藥','戴復古','宋','宋诗','song-poetry','','[]','黄堂開宴領佳賓，白鷺青原景一新。',64,'全唐诗/poet.song.183000.json','["黄堂開宴領佳賓，白鷺青原景一新。", "寄興江山擅名勝，折衝樽俎靜風塵。", "酴醾壓架垂垂老，芍藥翻階楚楚春。", "從此廬陵作佳話，平分風月兩詩人。"]'),
('31e7e60f-551b-43f5-9af3-4cbf4597aea2','次王應求韵','戴復古','宋','宋诗','song-poetry','','[]','逐日輪蹄走四方，來來去去爲何忙。',64,'全唐诗/poet.song.183000.json','["逐日輪蹄走四方，來來去去爲何忙。", "無人肯問山林樂，舉世爭趨名利場。", "以道自脩身是寶，無求何用智爲囊。", "愛梅栽竹平生語，吐出清風六月凉。"]'),
('0bcb0f40-d397-46fc-bad5-6b4350f6fe1c','郡圃寒食','戴復古','宋','宋诗','song-poetry','','[]','與民同樂一開園，佳節何曾禁得烟。',64,'全唐诗/poet.song.183000.json','["與民同樂一開園，佳節何曾禁得烟。", "拍岸綠波浮舴艋，翻空紅袖打鞦韆。", "眼看花柳心如醉，身在蓬瀛我亦仙。", "明日徐翁墳上約，欲求竹帚恐無緣。"]'),
('ecaa397e-99ef-4d2f-a2ad-a6c601fc1b79','杜仲高相遇約李尉','戴復古','宋','宋诗','song-poetry','','[]','胸中無地著塵埃，有我唯堪把酒杯。',64,'全唐诗/poet.song.183000.json','["胸中無地著塵埃，有我唯堪把酒杯。", "苦恨好山移不得，生憎俗客去還來。", "秋風吹老東籬菊，春信攙開北嶺梅。", "管領風光須我輩，急吹短笛棹船回。"]'),
('42ffafeb-d8aa-420e-a980-91165f8737b8','題蕭宰十二詠堂三山兩水之亭','戴復古','宋','宋诗','song-poetry','','[]','百載園林復故廬，收功全在五車書。',64,'全唐诗/poet.song.183000.json','["百載園林復故廬，收功全在五車書。", "一翁二季蘇家樣，三水兩山喻曲居。", "十二詠成傳不朽，三千篇出又何如。", "年來事事如人意，敢請先生賦遂初。"]'),
('20e75a4a-6f34-4216-80dc-aff102d668fa','陪虞使君登岳陽樓','戴復古','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','片帆飛過洞庭來，百尺巍巍水面開。',64,'全唐诗/poet.song.183000.json','["片帆飛過洞庭來，百尺巍巍水面開。", "疑泛靈槎上河漢，如從弱水到蓬萊。", "鈞天廣樂無聞矣，袖劍仙人安在哉。", "物物盡隨波浪去，君山一點獨崔嵬。"]'),
('3b9c9acc-c55c-4ee4-aa9e-448d5abd8dba','贈洞霄道士','戴復古','宋','宋诗','song-poetry','','[]','高枕清流卧白雲，靈龜骨相鶴精神。',64,'全唐诗/poet.song.183000.json','["高枕清流卧白雲，靈龜骨相鶴精神。", "凡爲九鍊山中客，定是群仙數內人。", "馴虎巖前攀逸翠，□蚊亭下濯征塵。", "練師莫笑狂夫老，乞我金丹養病身。"]'),
('7d6d456c-dab4-40b8-a500-25ab3976198f','閲世  其一','戴復古','宋','宋诗','song-poetry','','[]','一懶一愚兼一癡，從教智士巧能爲。',64,'全唐诗/poet.song.183000.json','["一懶一愚兼一癡，從教智士巧能爲。", "坦途失脚溪山險，暗室萌心天地知。", "江水長流無盡意，夕陽雖好不多時。", "老夫閲遍人間事，欲和寒山拾得詩。"]'),
('3c9ff2f8-c62b-4e1a-88c8-3ef0fd8a85eb','閲世  其二','戴復古','宋','宋诗','song-poetry','','[]','積鏹多金生怨尤，一溫飽外更何求。',64,'全唐诗/poet.song.183000.json','["積鏹多金生怨尤，一溫飽外更何求。", "自甘韜遁陶元亮，不愛贏餘馬少游。", "何取纍纍兼若若，終成莫莫與休休。", "花前適意三杯酒，萬事忘機對白鷗。"]'),
('a0aca316-d2a4-4062-aa6f-eef3b96f754c','少算','戴復古','宋','宋诗','song-poetry','','[]','吾生落落果何爲，世事紛紛無了期。',65,'全唐诗/poet.song.183000.json','["吾生落落果何爲，世事紛紛無了期。", "少算人皆嘲我拙，多求我却笑人癡。", "庭花密密疎疎蕊，溪柳長長短短枝。", "萬事欲齊齊不得，天機政在不齊時。"]'),
('4f7c1368-f5a9-4e56-9b51-016c40621b1d','南康六老堂','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山脚下開亭舘，柰此千峰百嶂何。',64,'全唐诗/poet.song.183000.json','["廬山脚下開亭舘，柰此千峰百嶂何。", "逸少大書池上墨，少陵狂作醉時歌。", "碧荷秋老香猶在，好月夜深明更多。", "五老揖君天上笑，把杯相對酌金波。"]'),
('f9da49a4-e3cb-45f1-b145-7a19d93bcb66','韓張亭','戴復古','宋','宋诗','song-poetry','','[]','此地曾棲雙鳳凰，登高懷古北風凉。',64,'全唐诗/poet.song.183000.json','["此地曾棲雙鳳凰，登高懷古北風凉。", "忠規萬乘龍顔粲，謫遇千山鳥道荒。", "百里隣居天作合，兩賢名與日爭光。", "幾人緘口貪官職，身在朝廷志已忘。"]'),
('9fa797f4-d12a-448b-8319-c300bee35475','處世','戴復古','宋','宋诗','song-poetry','','[]','風波境界立身難，處世規模要放寬。',64,'全唐诗/poet.song.183000.json','["風波境界立身難，處世規模要放寬。", "萬事盡從忙裏錯，一心須向靜中安。", "路當平處經行穩，人有常情耐久看。", "直到始終無悔吝，旁生枝葉便多端。"]'),
('9bde8657-6eef-4678-a9bd-368c8f23a59b','送別朱兼僉','戴復古','宋','宋诗','song-poetry','','[]','恰喜相逢又語離，愁於江上送君時。',64,'全唐诗/poet.song.183000.json','["恰喜相逢又語離，愁於江上送君時。", "清談未了風吹斷，白髮可憐天不知。", "樗木自肥傷竹瘦，海棠偷放笑梅遲。", "黄堂若問癡頑老，新有登樓二十詩。"]'),
('eb401932-0664-4a72-a5fc-e49917848538','題王制機新樓','戴復古','宋','宋诗','song-poetry','','[]','綠雲圖上新輪奐，彈壓江山氣勢豪。',64,'全唐诗/poet.song.183000.json','["綠雲圖上新輪奐，彈壓江山氣勢豪。", "手拍危欄拂星斗，目窮滄海見波濤。", "人間何處望不到，天下有樓無此高。", "俯視河陽桃李巷，清風吹斷市塵囂。"]'),
('e402a56b-b820-4029-8b60-a7296441c9df','呈姚顯叔奉親送死極孝','戴復古','宋','宋诗','song-poetry','','[]','鴈去多年缺寄音，扁舟無復到山陰。',64,'全唐诗/poet.song.183000.json','["鴈去多年缺寄音，扁舟無復到山陰。", "卧牛崗上經過少，下馬陵前感慨深。", "細讀文公千字誄，足知孝子一生心。", "無才爲作招魂些，自有悲風宰樹吟。"]'),
('baad60e2-ade6-460d-9aa4-2ea1697ccbb0','題姚顯叔南嶼書院','戴復古','宋','宋诗','song-poetry','','[]','朝夕置身書卷間，紛華滿眼幾曾看。',64,'全唐诗/poet.song.183000.json','["朝夕置身書卷間，紛華滿眼幾曾看。", "山林不受塵埃涴，屋宇無多氣象寬。", "立脚怕隨流俗轉，留心學到古人難。", "漫山桃李爭春色，輸與寒梅一點酸。"]'),
('6e9de85a-2222-4678-b61e-faeb081f2c46','寄朱仲是兼僉','戴復古','宋','宋诗','song-poetry','','[]','光陰日夜催吾老，已作鷄皮鶴髮翁。',64,'全唐诗/poet.song.183000.json','["光陰日夜催吾老，已作鷄皮鶴髮翁。", "萬事裝成百年夢，五行注定一生窮。", "殘花但有凋零分，枯木難沾造化功。", "若見黄堂煩寄語，何如停我雪樓中。"]'),
('1de273e1-4d91-4034-8d5d-c6d61097fecc','寄項宜甫兼簡韓右司','戴復古','宋','宋诗','song-poetry','','[]','匆匆不暇去相違，草草吟成送別詩。',64,'全唐诗/poet.song.183000.json','["匆匆不暇去相違，草草吟成送別詩。", "千里江山客行遠，三秋風雨桂開遲。", "安居但欲無公事，舉枉終須有直時。", "若見右司煩寄語，世間公道要扶持。"]'),
('39223716-9737-4d3a-8e5a-2fa291a0a584','閲四家詩卷','戴復古','宋','宋诗','song-poetry','','[]','閲盡四家詩卷子，自然優劣在其中。',64,'全唐诗/poet.song.183000.json','["閲盡四家詩卷子，自然優劣在其中。", "石龜野鶴心相合，菊磵花翁道不同。", "鳴鳳翶翔上霄漢，亂蟬蕭瑟度秋風。", "一篇論盡諸家體，憶著當年鞏睡翁。"]'),
('0f92fcd6-af2e-46b5-b6ce-d3099d1aacf0','謝吳秘丞作石屏集後序','戴復古','宋','宋诗','song-poetry','','[]','說破當年舊石屏，自慙無德又無能。',64,'全唐诗/poet.song.183000.json','["說破當年舊石屏，自慙無德又無能。", "鄉來江海疎狂客，今作山林老病僧。", "高卧一樓成宇宙，冷看獨影當賓朋。", "惡詩有誤公題品，不是夔州杜少陵。"]'),
('00fdf4c3-4122-4f53-8408-b401f309db18','有感','戴復古','宋','宋诗','song-poetry','','[]','老子生來世法疎，白頭思欲把犁鋤。',64,'全唐诗/poet.song.183000.json','["老子生來世法疎，白頭思欲把犁鋤。", "摩挲此腹空無物，僥倖虛名愧有餘。", "憔悴不堪漁父笑，寒溫無益貴人書。", "詩家幸有嚴華谷，襟誼猶能眷眷予。"]'),
('f8083b4a-cdbe-4eb3-bf3d-04b963604670','湘中','戴復古','宋','宋诗','song-poetry','','[]','一棹無情度碧湘，行行不脫水雲鄉。',64,'全唐诗/poet.song.183000.json','["一棹無情度碧湘，行行不脫水雲鄉。", "旗亭少飲村醪薄，田舍新炊晚稻香。", "簫鼓遠來朝嶽去，包籠爭出趁虛忙。", "塗人有愧黄居士，十載看經不下堂。"]'),
('b851ca44-bb8b-4a5e-8481-0b935ba8a6cb','九日櫧洲舟中','戴復古','宋','宋诗','song-poetry','','[]','幾年重九客他州，少泊櫧田古渡頭。',64,'全唐诗/poet.song.183000.json','["幾年重九客他州，少泊櫧田古渡頭。", "人向飲中言我樂，誰知笑裏是吾愁。", "黄華可忍拋三徑，白髮猶堪柰幾秋。", "今日登高無處所，一樽携上枕江樓。"]'),
('a7ee357b-a416-428d-8c0d-3af526115d53','曾景建得罪道州聽讀','戴復古','宋','宋诗','song-poetry','','[]','聞說烏臺欲勘詩，此身幸不墮危機。',64,'全唐诗/poet.song.183000.json','["聞說烏臺欲勘詩，此身幸不墮危機。", "少陵酒後輕嚴武，太白花前忤貴妃。", "遷客芬芳窮也達，故人評論是耶非。", "飽參一勺濂溪水，带取光風霽月歸。"]'),
('a8831278-6362-4f81-a9c9-c8c9710b893c','朱行父留度歲','戴復古','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山之下湘江上，風月留連去較遲。',64,'全唐诗/poet.song.183000.json','["衡山之下湘江上，風月留連去較遲。", "四海弟兄多不遇，一門父子兩相知。", "梅邊竹外三盃酒，歲尾年頭幾局棋。", "羈旅宦游俱是客，細論心事共題詩。"]'),
('b038eea9-4208-4705-9fe4-f853489b2755','梅花','戴復古','宋','宋诗','song-poetry','','[]','瀟灑春葩縞壽陽，百花惟有此花强。',64,'全唐诗/poet.song.183000.json','["瀟灑春葩縞壽陽，百花惟有此花强。", "月中分外精神出，雪裏幾多風味長。", "折向書窗疑是玉，吟來齒頰亦生香。", "年年茅舍江村畔，勾引詩人費品量。"]'),
('b862c881-a841-400a-a7ff-a1ce6fa6a27e','金陵游覽用劉子明韵','戴復古','宋','宋诗','song-poetry','','[]','英雄割據已焉哉，逝水滔滔去不回。',64,'全唐诗/poet.song.183000.json','["英雄割據已焉哉，逝水滔滔去不回。", "里巷難尋王謝宅，江山空對鳳凰臺。", "登臨無伴詩爲侶，興廢不知梅自開。", "同是游人不同樂，青樓歌舞待君來。"]'),
('7066d5cc-c0f4-4587-a25e-d5ef357faeaf','呈趙園令','戴復古','宋','宋诗','song-poetry','','[]','翠雲屏嶂碧瑶池，萬象前陳屬指揮。',64,'全唐诗/poet.song.183000.json','["翠雲屏嶂碧瑶池，萬象前陳屬指揮。", "彷彿神仙居處好，尋常賓客到來稀。", "荷花香裏渾無暑，棋子聲中却有機。", "別院笙歌促君去，野夫自步月明歸。"]'),
('502590bc-0112-469e-8d73-abec9d92a2cd','吉州堆勝樓謝景周司理居其上','戴復古','宋','宋诗','song-poetry','','[]','半天輪奐獨嵬峩，遥望青原瞰碧螺。',64,'全唐诗/poet.song.183000.json','["半天輪奐獨嵬峩，遥望青原瞰碧螺。", "納納乾坤森萬象，重重洲渚繞層波。", "詩情雅與江山合，酒興偏於故舊多。", "靴笏縛君難放浪，樽前狂客自高歌。"]'),
('c9400670-e8fd-459a-a0a0-7277edf6f923','吳子似提幹九高亭小景','戴復古','宋','宋诗','song-poetry','','[]','前日作詩題大概，亭前小景亦堪題。',64,'全唐诗/poet.song.183000.json','["前日作詩題大概，亭前小景亦堪題。", "綠楊樹下茅三架，白水田頭菜兩畦。", "似酒新鵝初泛浦，如孩黄犢試牽犁。", "十分野趣關心事，到此令人憶剡溪。"]'),
('249dc1b1-d2dd-4c1f-ad69-279fb92e667d','泉州紫極宮壽星殿古檜諸葛機宜同賦','戴復古','宋','宋诗','song-poetry','','[]','浪說陳朝八檜碑，何如此檜古而奇。',64,'全唐诗/poet.song.183000.json','["浪說陳朝八檜碑，何如此檜古而奇。", "靈根據地高千尺，黛色浮空閲四時。", "入欲棟梁勞想像，樹存陵谷有遷移。", "壽星賜汝長生訣，化作蒼龍守殿墀。"]'),
('7d0d3c04-375d-4318-be5c-054539fb073b','都中次韵申季山','戴復古','宋','宋诗','song-poetry','','[]','車馬喧臨十二門，樂從閑處度朝昏。',64,'全唐诗/poet.song.183000.json','["車馬喧臨十二門，樂從閑處度朝昏。", "詩書豈爲功名重，軒冕何如道誼尊。", "志士不能行所學，明君亦或諱忠言。", "世間事事如人意，未必商山有綺園。"]'),
('dc986c40-310a-4e64-aa7f-45ad2f687244','蘄州上官節推同到浮光','戴復古','宋','宋诗','song-poetry','','[]','馬蹄相逐到浮光，客裏相寬對舉觴。',64,'全唐诗/poet.song.183000.json','["馬蹄相逐到浮光，客裏相寬對舉觴。", "夜暖試鋪新枕簟，曉寒仍索舊衣裳。", "櫻桃著雨便成腐，柳絮隨風如許狂。", "連歲經行淮上路，憂時嬴得鬢毛蒼。"]'),
('730d8009-756b-46d0-8ba0-5fc321e2f4ef','贛州呈雪蓬姚使君','戴復古','宋','宋诗','song-poetry','','[]','白旗走報山前事，昨日官軍破綠林。',64,'全唐诗/poet.song.183000.json','["白旗走報山前事，昨日官軍破綠林。", "千里人烟皆按堵，一春農事最關心。", "不知郊外雨多少，試探田間水淺深。", "翠玉樓中無限好，可無閑暇一登臨。"]'),
('2c1b72d4-4431-403c-b19d-7643d64e9c9c','撫州節推蕭學易衙宇一新','戴復古','宋','宋诗','song-poetry','','[]','掇取高科如拾芥，愛君才調望君深。',64,'全唐诗/poet.song.183000.json','["掇取高科如拾芥，愛君才調望君深。", "莫誇書判居蓮幕，要把文章入禁林。", "華屋修成官滿去，好詩改定客來吟。", "西窗共對蕭蕭竹，不負三杯話此心。"]'),
('fca59e99-6244-427f-bc74-f6ca12562520','汪見可教授約諸丈鳳山酌別','戴復古','宋','宋诗','song-poetry','','[]','鳳凰洲上鳳凰山，草草登臨見一斑。',64,'全唐诗/poet.song.183000.json','["鳳凰洲上鳳凰山，草草登臨見一斑。", "不立樊牆天廣大，賸栽花竹地寬閑。", "白雲四面峰千疊，綠柳前頭水一灣。", "行色催人詩未就，寄情庭院落花間。"]'),
('0e7fa163-e217-45eb-9dee-caa8565b36fb','吉州李伯高會判送鹽蠘子魚比海味之珍者未免爲鱸魚動歸興','戴復古','宋','宋诗','song-poetry','','[]','每思鄉味必流涎，一物何能到我前。',64,'全唐诗/poet.song.183000.json','["每思鄉味必流涎，一物何能到我前。", "怒奮兩螯眸烱烱，飽吞三印腹便便。", "形模突出鹽池底，風味橫生海嶠邊。", "合爲蓴鱸動歸興，久拋東浦釣魚船。"]'),
('4a1e4787-ca93-43ee-82b0-c7d3712745e1','癸巳端午呈李伯高','戴復古','宋','宋诗','song-poetry','','[]','客裏幾逢端午節，看成雪鬢與霜髯。',64,'全唐诗/poet.song.183000.json','["客裏幾逢端午節，看成雪鬢與霜髯。", "救人采得三年艾，背世翻成六日蟾。", "老境可憐歸未得，羈懷長是病相兼。", "猛思一醉酬風月，笑撚菖花揭酒帘。"]'),
('cbc52f29-2092-4abd-8a8c-e243d56b813c','李深道得蘇養直所爲深字韵一首不知題何處景俾跋其後','戴復古','宋','宋诗','song-poetry','','[]','都來五十有六字，寫出山林無限奇。',64,'全唐诗/poet.song.183000.json','["都來五十有六字，寫出山林無限奇。", "當日所題何處景，祇今但見後湖詩。", "一言一語堪傳世，某水某丘仍屬誰。", "試向愁烟推白鳥，無情白鳥又何知。"]'),
('1fd830bc-6d86-468d-a888-7b5d1d77379a','與姪南隠等賡和','戴復古','宋','宋诗','song-poetry','','[]','夢回啼鳥聒幽櫺，古篆香烟結畫屏。',64,'全唐诗/poet.song.183000.json','["夢回啼鳥聒幽櫺，古篆香烟結畫屏。", "談麈一揮塵事少，離騷纔讀醉魂醒。", "閑居便是人間樂，克己何須座右銘。", "但了耕桑□門戶，我生安分合寧馨。"]'),
('aad6cb84-fc6a-4e69-a070-17ecd9632848','石屏久遊湖海祖妣遂題二句於壁云機番白苧和愁織門掩黄花带恨吟後石屏歸祖妣已亡矣續成一律','戴復古','宋','宋诗','song-poetry','','[]','伊昔天邊望藁砧，天邊魚鴈幾浮沉。',64,'全唐诗/poet.song.183000.json','["伊昔天邊望藁砧，天邊魚鴈幾浮沉。", "機番白苧和愁織，門掩黄花带恨吟。", "自古詩人皆浪跡，誰知賢婦有關心。", "歸來却抱雙雛哭，碑刻雖深恨更深。"]'),
('e3b930e9-202b-419b-a555-f030834dcd77','臘梅二首  其一','戴復古','宋','宋诗','song-poetry','','[]','天寒好風日，清香透窗紗。',24,'全唐诗/poet.song.183000.json','["天寒好風日，清香透窗紗。", "誰知蜜脾底，有此返魂花。"]'),
('3f5ff818-2ba1-4453-911f-c043bc014ae2','臘梅二首  其二','戴復古','宋','宋诗','song-poetry','','[]','籬菊抱香死，化入歲寒枝。',24,'全唐诗/poet.song.183000.json','["籬菊抱香死，化入歲寒枝。", "依然色尚黄，雪中開更奇。"]'),
('2ebd723a-c2e6-415b-a3b9-86f0b6078cf5','汀州道上','戴復古','宋','宋诗','song-poetry','','[]','宇內何牢落，客行雙鬢華。',24,'全唐诗/poet.song.183000.json','["宇內何牢落，客行雙鬢華。", "千山萬山底，老眼付梅花。"]'),
('abf6b118-9c5a-44dd-89c7-98eeac317144','題周仁甫古香堂二首  其一','戴復古','宋','宋诗','song-poetry','','[]','一登君子堂，滿目是秋光。',24,'全唐诗/poet.song.183000.json','["一登君子堂，滿目是秋光。", "桂是月中桂，花非今日香。"]'),
('17432191-ed1d-4634-b1ac-6631e99014b9','題周仁甫古香堂二首  其二','戴復古','宋','宋诗','song-poetry','','[]','秋風動窗戶，兼聞書傳香。',24,'全唐诗/poet.song.183000.json','["秋風動窗戶，兼聞書傳香。", "種花兼種德，當有折桂郎。"]'),
('27b22b33-6ec6-4bd6-803a-395e7d29d973','寄興  其一','戴復古','宋','宋诗','song-poetry','','[]','長願如人意，一生無別離。',24,'全唐诗/poet.song.183000.json','["長願如人意，一生無別離。", "妾當年少日，花似半開時。"]'),
('aaec023d-6cca-4b5b-a0fe-a20cf7b2c355','寄興  其二','戴復古','宋','宋诗','song-poetry','','[]','黄金無足色，白璧有微瑕。',24,'全唐诗/poet.song.183000.json','["黄金無足色，白璧有微瑕。", "求人不求備，妾願老君家。"]'),
('98161443-eb45-4a02-b399-7abae1cbf9d3','贈萬杉老秀癡翁二首  其一','戴復古','宋','宋诗','song-poetry','','[]','識得慶雲和尚，不癡自號癡翁。',28,'全唐诗/poet.song.183000.json','["識得慶雲和尚，不癡自號癡翁。", "此老端如五老，高出廬阜諸峰。"]'),
('afcf9cd9-cd7d-4167-8e09-fabd38b39a8e','贈萬杉老秀癡翁二首  其二','戴復古','宋','宋诗','song-poetry','','[]','讀儒書五千卷，通禪門八萬條。',28,'全唐诗/poet.song.183000.json','["讀儒書五千卷，通禪門八萬條。", "宴坐萬杉林下，四旁風雨蕭蕭。"]'),
('8097682a-9a9e-4b8a-8a30-95550d1c09e0','江村晚眺二首  其一','戴復古','宋','宋诗','song-poetry','','[]','數點歸鴉過別村，隔灘漁笛遠相聞。',32,'全唐诗/poet.song.183000.json','["數點歸鴉過別村，隔灘漁笛遠相聞。", "菰蒲斷岸潮痕濕，日落空江生白雲。"]'),
('3413f4c0-5f3e-44bb-8c96-ccd3756cc0da','江村晚眺二首  其二','戴復古','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u666f"]','江頭落日照平沙，潮退漁舠閣岸斜。',32,'全唐诗/poet.song.183000.json','["江頭落日照平沙，潮退漁舠閣岸斜。", "白鳥一雙臨水立，見人驚起入蘆花。"]'),
('2a19be18-fb84-41c2-a0d3-63da90aecdc5','見山居可喜','戴復古','宋','宋诗','song-poetry','','[]','一溪盤曲到階除，四面青山畫不如。',32,'全唐诗/poet.song.183000.json','["一溪盤曲到階除，四面青山畫不如。", "脩竹罩門梅夾路，詩人居處野人居。"]'),
('9caced73-1ed9-49c4-9f2e-1e43be62a6df','初夏','戴復古','宋','宋诗','song-poetry','','[]','紅紫光陰不久長，一聲啼鴂靜年芳。',32,'全唐诗/poet.song.183000.json','["紅紫光陰不久長，一聲啼鴂靜年芳。", "陰陰綠樹黄鸝語，將與人間作夏凉。"]'),
('7c9ad275-297a-4636-97ac-4e1a6f7d08c2','桂','戴復古','宋','宋诗','song-poetry','','[]','金谷園林知幾家，競栽桃李作春華。',32,'全唐诗/poet.song.183000.json','["金谷園林知幾家，競栽桃李作春華。", "無人得似天工巧，明月中間種桂花。"]'),
('e0360a38-5cbb-4584-8af2-3d4d1b9b3ff6','江陰浮遠堂','戴復古','宋','宋诗','song-poetry','','[]','橫岡下瞰大江流，浮遠堂前萬里愁。',32,'全唐诗/poet.song.183000.json','["橫岡下瞰大江流，浮遠堂前萬里愁。", "最苦無山遮望眼，淮南極目盡神州。"]'),
('af86889e-5409-47f5-9f11-0f70b0bdc1a6','淮村兵後','戴復古','宋','宋诗','song-poetry','','["\u4e61\u6751", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u6218\u4e89", "\u5b8b\u8bd7"]','小桃無主自開花，烟草茫茫带曉鴉。',32,'全唐诗/poet.song.183000.json','["小桃無主自開花，烟草茫茫带曉鴉。", "幾處敗垣圍故井，鄉來一一是人家。"]'),
