('facdecec-2932-47f9-a6f2-26f4bd7128ef','山村','戴復古','宋','宋诗','song-poetry','','[]','野水開冰出，山雲带雨行。',48,'全唐诗/poet.song.183000.json','["野水開冰出，山雲带雨行。", "白鷗乘曉泛，黄犢試春耕。", "地僻民風古，年豐米價平。", "村居自蕭洒，况有讀書聲。"]'),
('84c3f786-4da4-4d9b-89be-38b79ed82e69','白鶴觀','戴復古','宋','宋诗','song-poetry','','[]','荒徑行如錯，蟠松看轉奇。',48,'全唐诗/poet.song.183000.json','["荒徑行如錯，蟠松看轉奇。", "鳥聲人靜處，山色雨晴時。", "賒得溪翁酒，閒尋道士棋。", "箇中有佳趣，莫怪下山遲。"]'),
('bc630b97-9b53-40b0-8f21-db6dd19a3787','嶽市勝業寺禹柏','戴復古','宋','宋诗','song-poetry','','[]','三千年老柏，怪怪復奇奇。',48,'全唐诗/poet.song.183000.json','["三千年老柏，怪怪復奇奇。", "剖彼一枯腹，離爲九折枝。", "蟠根半生死，閲世幾興衰。", "神禹所栽植，山靈常護持。"]'),
('95da448a-f3ee-4651-b577-6fa3fe294189','南劍溪上','戴復古','宋','宋诗','song-poetry','','[]','長舟不用柂，沙上木爲篙。',48,'全唐诗/poet.song.183000.json','["長舟不用柂，沙上木爲篙。", "溪路灣環轉，灘聲日夜號。", "居人不覺險，行客始知勞。", "四望無平地，山田級級高。"]'),
('94c59d19-f739-497f-b811-0dac90b4a19c','別嚴滄浪','戴復古','宋','宋诗','song-poetry','','[]','三生漢嚴助，筆陣抵千兵。',48,'全唐诗/poet.song.183000.json','["三生漢嚴助，筆陣抵千兵。", "雅志從南隠，吟詩到北征。", "結交疑泛愛，惜別見真情。", "來歲春花發，相期在上京。"]'),
('5874326b-463b-4c94-9973-b9703a3515c2','聞機上婦說蠶事之辛勤織未成縑往往取償債家','戴復古','宋','宋诗','song-poetry','','[]','荷君問訊蠶家事，此是婦人辛苦媒。',64,'全唐诗/poet.song.183000.json','["荷君問訊蠶家事，此是婦人辛苦媒。", "典盡衣裳酬葉價，忙無心緒向妝臺。", "繰聲未斷機聲續，私債未償官債催。", "織未成縑分翦盡，妾身爭得一絲來。"]'),
('dd988cf9-8dcc-4e0f-b737-6bf2b83ae14d','懷家三首  其一','戴復古','宋','宋诗','song-poetry','','[]','白髮出門來，三見梅花謝。',24,'全唐诗/poet.song.183000.json','["白髮出門來，三見梅花謝。", "客路有歲年，歸心無晝夜。"]'),
('19e27a12-d748-4a35-905f-7142eb3e6438','懷家三首  其二','戴復古','宋','宋诗','song-poetry','','[]','强言不思家，對人作意氣。',24,'全唐诗/poet.song.183000.json','["强言不思家，對人作意氣。", "惟有布被頭，見我思家淚。"]'),
('19fee643-5e50-4826-8cde-ca4ea43a9269','懷家三首  其三','戴復古','宋','宋诗','song-poetry','','[]','三年寄百書，幾書到我屋。',24,'全唐诗/poet.song.183000.json','["三年寄百書，幾書到我屋。", "昨夜夢中歸，及見老妻哭。"]'),
('6cbecb11-bfe4-49ef-95e3-24e91710eac5','家中作','戴復古','宋','宋诗','song-poetry','','[]','四海飄零似落花，十年秋鬢带霜華。',64,'全唐诗/poet.song.183000.json','["四海飄零似落花，十年秋鬢带霜華。", "歸無駟馬空題柱，敝盡貂裘忙到家。", "觸目半成愁境界，安心旋辦老生涯。", "可憐持蟹持杯手，小圃携鋤學種瓜。"]'),
('86d4b12b-544e-4665-a5ce-b3b0cb575edf','山村','戴復古','宋','宋诗','song-poetry','','[]','野老幽居處，成吾一首詩。',48,'全唐诗/poet.song.183000.json','["野老幽居處，成吾一首詩。", "桑枝礙行路，瓜蔓網疎籬。", "牧去牛將犢，人來犬護兒。", "生涯雖樸略，氣象自熙熙。"]'),
('1501ac77-91fa-4680-b9a3-9018ab5b8372','衡陽舟中','戴復古','宋','宋诗','song-poetry','','[]','蕭蕭風雨送行舟，小泊垂楊古渡頭。',32,'全唐诗/poet.song.183000.json','["蕭蕭風雨送行舟，小泊垂楊古渡頭。", "不忍緩行江上路，落梅片片是詩愁。"]'),
('5cc5ce05-7cb6-47e6-8618-1ab58eec5689','村景','戴復古','宋','宋诗','song-poetry','','[]','簫鼓迎神賽社筵，藤枝摇曳打鞦韆。',32,'全唐诗/poet.song.183000.json','["簫鼓迎神賽社筵，藤枝摇曳打鞦韆。", "坐中翁嫗鬢如雪，也把山花插滿顛。"]'),
('f73a52da-b415-430b-8cc1-dcdf38e2857a','溪上','戴復古','宋','宋诗','song-poetry','','[]','山腰有路穿脩竹，水面無橋涉淺沙。',32,'全唐诗/poet.song.183000.json','["山腰有路穿脩竹，水面無橋涉淺沙。", "夾岸人家盡農圃，秋風吹老木棉花。"]'),
('ac805342-afe6-4487-8296-4d1db47510f1','題尹惟曉芙蓉翠羽圖','戴復古','宋','宋诗','song-poetry','','[]','何人妙筆起秋風，吹破枝頭爛漫紅。',32,'全唐诗/poet.song.183000.json','["何人妙筆起秋風，吹破枝頭爛漫紅。", "翠羽飛來又飛去，一心祇在蓼花叢。"]'),
('b5a39b6e-f916-460f-8eef-43b844fc2434','廬山馬上','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','青松路徑白雲關，有客來尋半日閒。',32,'全唐诗/poet.song.183000.json','["青松路徑白雲關，有客來尋半日閒。", "十載灞橋馿子上，爭如騎馬看廬山。"]'),
('1b6ccf12-f104-4f59-b833-3d572267fb1d','海棠','戴復古','宋','宋诗','song-poetry','','[]','十月園林不雨霜，朝曦赫赫似秋陽。',32,'全唐诗/poet.song.183000.json','["十月園林不雨霜，朝曦赫赫似秋陽。", "夜來聽得游人語，不見梅花見海棠。"]'),
('dc5b01ae-82df-4e1b-a4c1-74cbca05a866','新歲','戴復古','宋','宋诗','song-poetry','','[]','新年試筆欲題詩，老去才衰得句遲。',32,'全唐诗/poet.song.183000.json','["新年試筆欲題詩，老去才衰得句遲。", "春事未容桃李覺，梅花開到北邊枝。"]'),
('6b13ba3d-23e8-464a-a565-6764a2c9793f','雪後暖','戴復古','宋','宋诗','song-poetry','','[]','先臘梅花謝，不冰溪水流。',48,'全唐诗/poet.song.183000.json','["先臘梅花謝，不冰溪水流。", "早嘗春菜餠，暖卸木終裘。", "去歲三冬雪，今年百穀秋。", "此冬無此瑞，又爲老農憂。"]'),
('58a12d8a-3338-42c0-9263-824bd33bef04','畫山','戴復古','宋','宋诗','song-poetry','','[]','幾簇雲煙幾段山，畫成煙雨渺茫間。',32,'全唐诗/poet.song.183000.json','["幾簇雲煙幾段山，畫成煙雨渺茫間。", "扁舟三兩溪橋上，一路更無人往還。"]'),
('d14a4bf2-0e92-4369-bcc8-f3d4f57ab071','洞霄宮','戴復古','宋','宋诗','song-poetry','','[]','天柱峰頭一振衣，雲開巖路雨晴時。',64,'全唐诗/poet.song.183000.json','["天柱峰頭一振衣，雲開巖路雨晴時。", "登臨欲訪神仙事，紀述都無漢晉碑。", "拍手數聲龍井躍，篝燈一覽洞天奇。", "林間安得棲身處，欲煉金丹餌玉芝。"]'),
('58662c80-64e5-4b43-8417-addd7a698fcd','山村','戴復古','宋','宋诗','song-poetry','','[]','雨過山村六月凉，田田流水稻花香。',32,'全唐诗/poet.song.183000.json','["雨過山村六月凉，田田流水稻花香。", "松邊一石平如榻，坐聽風蟬送夕陽。"]'),
('f47441cc-d740-4aa1-941a-f8a42145902c','泉廣載銅錢入外國','戴復古','宋','宋诗','song-poetry','','[]','人望南風賈舶歸，利通中國海南夷。',32,'全唐诗/poet.song.183000.json','["人望南風賈舶歸，利通中國海南夷。", "珠珍犀象來無限，但恐青錢有盡時。"]'),
('40829651-3c3e-4e5e-a00c-8e4a3d80ecb5','羅漢寺','戴復古','宋','宋诗','song-poetry','','[]','半空紫翠隔微茫，隠隠鐘聲落下方。',64,'全唐诗/poet.song.183000.json','["半空紫翠隔微茫，隠隠鐘聲落下方。", "名勝直同天地老，青山不管古今忙。", "散分瀑布煙霞潤，點檢蒼松歲月長。", "絕頂好雲如戀客，儘教怡閲到斜陽。"]'),
('97eef532-a7d4-4116-b23e-53d97827b42c','留守參政大資范公余同年進士往歲帥桂林題刻最多四方傳之暇日嘗與同寮遍觀因即公所名壺天觀題數語','戴復古','宋','宋诗','song-poetry','','[]','宣政喜邊功，隆兌築州縣。',156,'全唐诗/poet.song.183000.json','["宣政喜邊功，隆兌築州縣。", "程公自名巖，刻石記所建。", "得既不償費，中興棄不繕。", "誕謾磨崖辭，當日妄誇衒。", "英英石湖仙，改作壺天觀。", "壁間三大字，莊重如峩弁。", "詩文鸞鶴音，筆勢龍蛇變。", "登高瞰洞戶，灕水澄如練。", "勝概聳靈臺，遐觀起三歎。", "玲瓏二十四，妙墨鎸題徧。", "我來爲拂塵，端若侍顔面。", "邦人頌遺愛，壽骨癯且健。", "今坐玉麟堂，安得使之見。"]'),
('aa63da74-65f9-49ac-be40-aab5992cc273','句  其一','戴復古','宋','宋诗','song-poetry','','[]','槎牙老樹得春早，摘索好枝和雪攀。',16,'全唐诗/poet.song.183000.json','["槎牙老樹得春早，摘索好枝和雪攀。"]'),
('28d35583-26b3-4cde-b760-6ed7cb755aeb','句  其二','戴復古','宋','宋诗','song-poetry','','[]','每遇花時人競取，祇愁斫盡春風枝。',16,'全唐诗/poet.song.183000.json','["每遇花時人競取，祇愁斫盡春風枝。"]'),
('336a81db-d665-4469-a9f9-cced8c79f247','句  其三','戴復古','宋','宋诗','song-poetry','','[]','就中一種芙蓉別，只恐鵝黄學道粧。',16,'全唐诗/poet.song.183000.json','["就中一種芙蓉別，只恐鵝黄學道粧。"]'),
('393465cb-70be-4550-944c-0a2390e2522b','句  其四','戴復古','宋','宋诗','song-poetry','','[]','詩骨梅花瘦，歸心江水流。',12,'全唐诗/poet.song.183000.json','["詩骨梅花瘦，歸心江水流。"]'),
('8976745a-1d68-4a22-a503-1d3c92dbab13','句','戴復古前妻','宋','宋诗','song-poetry','','[]','機番白苧和愁織，門掩黄花带恨吟。',16,'全唐诗/poet.song.183000.json','["機番白苧和愁織，門掩黄花带恨吟。"]'),
('a06099f5-d363-48c8-9c42-f8bbd24dcb18','別曹松山','趙汝績','宋','宋诗','song-poetry','','[]','柳條能幾長，袖手不忍折。',156,'全唐诗/poet.song.183000.json','["柳條能幾長，袖手不忍折。", "東風惡作劇，客袂吹欲裂。", "男兒數寸管，平世三尺鐵。", "何門無鄒裾，有國駐孔轍。", "鷹鸇擊飄風，不受錦鞲紲。", "驊騮踏飛電，寧顧黄金埒。", "中年易悲傷，浩歎彌激烈。", "常恐兒曹覺，况與我輩別。", "侏儒囊粟飽，壯士唾壺闕。", "子行亦何以，問口尚存舌。", "但惜新相知，未是古决絕。", "長安萬花春，蘆鞭裊晴雪。", "一第宜慁子，相期抱貞節。"]'),
('df20ba5d-5c16-42f4-9e9e-e598b0ac3efd','無罪言','趙汝績','宋','宋诗','song-poetry','','[]','哀哀民何辜，遭此凶歉厄。',288,'全唐诗/poet.song.183000.json','["哀哀民何辜，遭此凶歉厄。", "初聞數米炊，次復併日食。", "草根掘欲盡，木皮屑不給。", "疲老就枯僵，少壯作捐瘠。", "千百存什一，烏喙仍菜色。", "朝憂夕恐懼，不得見新麥。", "城市逐末徒，奔走困貴糴。", "剝牀遂及膚，近半死於疫。", "吾皇素仁惠，一念軫饑溺。", "發粟通有無，寬逋已徵索。", "郡縣乏宣化，鞭扑庭下赤。", "貪官猴而冠，健吏虎而翼。", "天災偶參會，人意莫致詰。", "淮楚困烽塵，荆蜀斃鋒鏑。", "湘潭煩調戍，洪贛事供億。", "昔聞惟內地，可以稱樂國。", "豈料一年饑，狼狽如此極。", "公卿飽輿臺，王侯羅第宅。", "私財足苞苴，公帑罄符籍。", "匪難活民命，何以壽國脈。", "子牟心徒勞，之武壯自惜。", "安得扣九關，玉階面咫尺。", "天地本至仁，君臣願一德。", "賢人斯在位，能者各效職。"]'),
('00c2db94-3f80-4588-8474-245d23aa6238','環碧園餞信守趙蘭皋分韵得燕字','趙汝績','宋','宋诗','song-poetry','','[]','開窗俯平湖，折柳舉離宴。',96,'全唐诗/poet.song.183000.json','["開窗俯平湖，折柳舉離宴。", "五馬遲未發，暗雨雜飛霰。", "江東古名州，廣信今近甸。", "兵驕費紀律，民瘠易咨怨。", "磽田歲少登，孔道楮常賤。", "正須儒者事，毋媿循吏傳。", "休辭一杯酒，往副千里願。", "有語不敢留，低間媿檣燕。"]'),
('83dfde5a-95d3-472d-8e50-dee38e204e32','墨歌','趙汝績','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','空山老桐勁如鐵，英枝翦翦夜撐月。',192,'全唐诗/poet.song.183000.json','["空山老桐勁如鐵，英枝翦翦夜撐月。", "霜風著子涵玉膏，烈手崇朝剖融結。", "別令刳木環清泉，翠缸紙羃籠輕烟。", "霏霏玄霧掃難聚，斷犀烹煉凝蛟涎。", "和成萬杵擣圭璧，良工欲售常自惜。", "絕憐剡水多夭藤，又慮端溪欠奇石。", "久知此藝人罕精，作者未必識者明。", "九華山下祝公子，頗以膠法成其名。", "相逢但問詩有幾，以詩換墨兩自喜。", "酴醾園館已謝春，楊柳池塘正藏水。", "薰風拂拂吹硯波，呼兒教作病手磨。", "須臾滿硯片雲黑，無詩可寫如君何。"]'),
('382a9cbf-1279-46cb-ae8d-aa962228f27e','陳老畫牛','趙汝績','宋','宋诗','song-poetry','','[]','老融棄髮逃於禪，胸藏丘壑身林泉。',224,'全唐诗/poet.song.183000.json','["老融棄髮逃於禪，胸藏丘壑身林泉。", "時拈寸草幻墨汁，慘淡咫尺生風烟。", "尤工畫牛古絕比，不特形似真神全。", "平生知己一攻媿，惜墨如命詩猶傳。", "至今鄞人懷片紙，如護圭璧珠璣然。", "陳生少壯曾入室，妙處已覺牆及肩。", "岸痕樹影彷彿地，雲陰雨氣冥濛天。", "寒禽立背渡淺水，野葑沒足行淤田。", "礪角思鬭力居尾，倚木揩癢勢擁前。", "或沿草徑逐羣去，或傍茅簷抱犢眠。", "如何盡得此態度，前身想住桃林邊。", "世人貴耳不貴目，嗚呼此畫空爾妍。", "我方求之不論錢，卷收更閲三十年。", "欲尋此老不可得，摩挲陳迹方爭憐。"]'),
('ae660671-c5fc-48eb-a9ab-683862f5ab84','題黄存之春莊雨急圖','趙汝績','宋','宋诗','song-poetry','','[]','山濃樹密春欲浮，農夫有事營西疇。',192,'全唐诗/poet.song.183000.json','["山濃樹密春欲浮，農夫有事營西疇。", "鵓鴣聲歇風雨急，田塍滑澾如翻油。", "牢披蓑衣緊繫笠，渾身水流兩股慄。", "揀時浸種開稻包，心急鞭牛牛步急。", "前年春寒再移秧，去年夏旱赤地荒。", "東隣西保幾人在，渠今尚得本身强。", "低頭無言心似苦，定願五風十日雨。", "禾頭粒粒飽秋露，糠籺充腸米田主。", "我家鏡湖烟水湄，身雖不耕眼見之。", "何人得此畎畝趣，短紙寫出無聲詩。", "坐令展卷三太息，力穡莫供浮末食。", "君看此輩終歲勤，返向溝中作捐瘠。"]'),
('1a718fd8-3add-4275-b3a7-3c6ec80b58a8','憶昔一首','趙汝績','宋','宋诗','song-poetry','','[]','憶昔三十氣拂雲，鉞神纛鬼泣禡文。',64,'全唐诗/poet.song.183000.json','["憶昔三十氣拂雲，鉞神纛鬼泣禡文。", "欲提河洛數千里，重收圖版歸明君。", "只今萬事付孤憤，坐看江西竹生粉。", "苧絲成疋剪釣衣，一櫂賀湖烟水遠。"]'),
('5c8a869c-102a-45ec-be0c-0962f96a48f3','離越','趙汝績','宋','宋诗','song-poetry','','[]','東關寒水深，遊子別家心。',48,'全唐诗/poet.song.183000.json','["東關寒水深，遊子別家心。", "櫂急波鳴枕，篷疎月在衾。", "半生多道路，何日定山林。", "隔岸聞漁唱，離騷不敢吟。"]'),
('f387ea72-300a-4ee1-b920-14294d9e222a','游石窗','趙汝績','宋','宋诗','song-poetry','','[]','玉妃箋天收雪權，東皇領春行人寰。',208,'全唐诗/poet.song.183000.json','["玉妃箋天收雪權，東皇領春行人寰。", "恍如身在五雲表，游到海上神仙山。", "翠鳳婀娜竹夾道，蒼龍偃蹇松當關。", "壽籐絡崖半青白，文蘚繡徑全斕斑。", "亭臺隠映樹石罅，樓觀突兀烟霄間。", "遥峰前後獻奇峭，流水左右供潺湲。", "珍禽倏來不可致，瑶草已種何容刪。", "目光貪翫忽炫焜，足力亦倦難躋攀。", "日斜路轉歸意迫，忽見洞府臨銀灣。", "洞中仙官笑呼客，光風霽月冰雪顔。", "云是四明石窗主，新自五老峰頭還。", "猿留鶴戀不覺久，碧落有詔行催班。", "却愁曳履踐台斗，三十六峰花木閒。"]'),
('dc5b8890-fdcf-47bd-a412-88ffc885508d','峽江龍祠','趙汝績','宋','宋诗','song-poetry','','[]','坐占山回抱，平看水怒流。',48,'全唐诗/poet.song.183000.json','["坐占山回抱，平看水怒流。", "丹青今古像，香火往來舟。", "石插青莎岸，雲橫夕照樓。", "揚靈相恐動，巫覡有深謀。"]'),
('cf56d206-5672-4b00-ae80-477c59c4bcc7','檜房','趙汝績','宋','宋诗','song-poetry','','[]','老檜倚虛房，能生九夏凉。',48,'全唐诗/poet.song.183000.json','["老檜倚虛房，能生九夏凉。", "讀書參句讀，臨字識偏傍。", "婢織蒲爲履，童燒朮當香。", "興來吟不就，頻與月商量。"]'),
('a2bd7d46-de6f-496d-955f-d15b30507c5f','溪翁惠秋蘭','趙汝績','宋','宋诗','song-poetry','','[]','不夢靈均久，西風爲返魂。',48,'全唐诗/poet.song.183000.json','["不夢靈均久，西風爲返魂。", "頓忘千載遠，但喜一香存。", "勁葉牽湘色，疎花洗露痕。", "勿嫌盆盎小，能貯雪霜根。"]'),
('fae5dfe7-a723-4fd2-93e0-c0f1750fc440','漁父','趙汝績','宋','宋诗','song-poetry','','[]','換米活妻子，餘錢付酒家。',48,'全唐诗/poet.song.183000.json','["換米活妻子，餘錢付酒家。", "身前舟似葉，世上事如麻。", "獨鼈過深浦，伴鷗眠淺沙。", "旁人問醒醉，鼓枻入蘆花。"]'),
('6f8fd94a-59c1-438c-b1c2-72bac942a02b','出郊','趙汝績','宋','宋诗','song-poetry','','[]','難得晴如許，春游第一番。',48,'全唐诗/poet.song.183000.json','["難得晴如許，春游第一番。", "鳥啼花底樹，雲裹面前山。", "馬躍平沙地，帆投落日村。", "戲呼漁子問，吾與汝誰閑。"]'),
('60ee4801-1ffe-40f4-8a6a-c8690e726138','和牡丹韵','趙汝績','宋','宋诗','song-poetry','','[]','園工巧栽接，樹樹品新奇。',48,'全唐诗/poet.song.183000.json','["園工巧栽接，樹樹品新奇。", "富覺春無厭，貧疑地有私。", "色須綃幄護，名記玉牌垂。", "若說能傾日，牆根有晚葵。"]'),
('2e241873-f648-4f40-ba52-c7d1495afcc0','道中登嶺','趙汝績','宋','宋诗','song-poetry','','[]','慚愧輕輿寄僕肩，蛇蟠小徑入層巔。',64,'全唐诗/poet.song.183000.json','["慚愧輕輿寄僕肩，蛇蟠小徑入層巔。", "升高但覺少平地，視下方知在半天。", "尺壠寸田皆石級，堵牆椽屋即人烟。", "客程到此更風雪，聞一禽聲恐杜鵑。"]'),
('00addd07-e310-49dd-bc72-72087f818559','雁山章君以江山無盡圖求詩','趙汝績','宋','宋诗','song-poetry','','[]','寫此何人雲夢胸，色塵真幻等成空。',64,'全唐诗/poet.song.183000.json','["寫此何人雲夢胸，色塵真幻等成空。", "看君一軸畫圖上，在我半生行記中。", "剡水回舟乘夜雪，楚江燃燭聽秋風。", "轉蓬蹤跡徒勞耳，心媿鴈山頭白翁。"]'),
('13f25db4-0235-4b86-9183-1b6bdef11f2d','送蔡廉父赴贛辟  其一','趙汝績','宋','宋诗','song-poetry','','[]','同游兩見菊花時，忍對西風話別離。',64,'全唐诗/poet.song.183000.json','["同游兩見菊花時，忍對西風話別離。", "官遠人應觀所主，心平事必得其宜。", "急流進進常思退，公事惺惺要带癡。", "執手羞爲兒女語，此言或可當箴規。"]'),
('14bab75f-d206-447e-beda-d5e6e5186067','送蔡廉父赴贛辟  其二','趙汝績','宋','宋诗','song-poetry','','[]','西山影淡水無聲，知道扁舟破曉行。',64,'全唐诗/poet.song.183000.json','["西山影淡水無聲，知道扁舟破曉行。", "我欲夢魂隨去櫂，君應望眼斷高城。", "紅蓮綠水官中事，白酒黄花客裏程。", "從此鬰孤臺上月，十分知爲故人明。"]'),
('fe8e24b7-58cd-461e-8c17-073213f40479','南坡','趙汝績','宋','宋诗','song-poetry','','[]','小園路口安柴戶，日日山翁手自開。',64,'全唐诗/poet.song.183000.json','["小園路口安柴戶，日日山翁手自開。", "禽有色聲皆可玩，花無香實不須栽。", "柳根著石宜安釣，巖罅通泉可泛盃。", "更向南坡臨水處，參差純種百株梅。"]'),
('ce62ffd8-1322-4000-81a2-281938777981','將歸','趙汝績','宋','宋诗','song-poetry','','[]','拄笏西山一笑中，掛帆猶及楝花風。',64,'全唐诗/poet.song.183000.json','["拄笏西山一笑中，掛帆猶及楝花風。", "此身可是屠羊說，餘事寧非失馬翁。", "不問鬢毛成早白，免將癡面發羞紅。", "故人新寄虔州布，歸製吟袍管釣篷。"]'),
('84b16c8a-0c9f-4b0e-8569-2ac62bd59b88','送荷渚歸越','趙汝績','宋','宋诗','song-poetry','','[]','湘湖蓴線正宜羹，一舸濤江汎曉晴。',64,'全唐诗/poet.song.183000.json','["湘湖蓴線正宜羹，一舸濤江汎曉晴。", "屋破不妨從客借，田荒自欲課奴耕。", "不隨不激真吾事，乍佞乍賢皆世情。", "從此一麾江海去，西風斷鴈冷無聲。"]'),
('82604655-61d4-4446-a967-a8ad77c6cc92','送荷渚兄自永嘉歸越  其一','趙汝績','宋','宋诗','song-poetry','','[]','荷渚盟鷗冷不飛，此番可與報歸期。',64,'全唐诗/poet.song.183000.json','["荷渚盟鷗冷不飛，此番可與報歸期。", "結廬雖小尚堪隠，負郭縱荒何慮饑。", "吟得四靈無避處，鑄成一錯在來時。", "吾家浸碧幸無恙，草夢何須必謝池。"]'),
('e8287f9e-7bc3-4040-9743-e77c1c722f06','送荷渚兄自永嘉歸越  其二','趙汝績','宋','宋诗','song-poetry','','[]','客鬢蕭疎漸禿翁，歸來恍與鶴仙同。',64,'全唐诗/poet.song.183000.json','["客鬢蕭疎漸禿翁，歸來恍與鶴仙同。", "山川米老畫圖上，風月放翁詩句中。", "隣圃有蔬羹釜滿，私田無秫酒樽空。", "欲尋上竈雲門路，湖水不多船未通。"]'),
('7687cadb-c7d9-4de9-bab7-be7e6bcda90a','林壑閒步二絕  其一','趙汝績','宋','宋诗','song-poetry','','[]','懶不看書不賦詩，樹陰濃處坐移時。',32,'全唐诗/poet.song.183000.json','["懶不看書不賦詩，樹陰濃處坐移時。", "世間此等清閑福，問著漁樵却不知。"]'),
('c460358d-a838-4971-886d-14981b034dca','林壑閒步二絕  其二','趙汝績','宋','宋诗','song-poetry','','[]','參差臺榭碧雲中，柳北松南一徑通。',32,'全唐诗/poet.song.183000.json','["參差臺榭碧雲中，柳北松南一徑通。", "带得碁枰無敵手，與僧不語立薰風。"]'),
('e955243e-4701-4444-ac89-19cd5adb07d1','漁父','趙汝績','宋','宋诗','song-poetry','','[]','魚滿笭箵酒滿壺，渚鷗汀鶴伴清孤。',32,'全唐诗/poet.song.183000.json','["魚滿笭箵酒滿壺，渚鷗汀鶴伴清孤。", "此身漂泊雖無定，能與人間作畫圖。"]'),
('b621f665-6ee5-412b-bac3-086add17d816','迎慶避暑','趙汝績','宋','宋诗','song-poetry','','[]','古寺無風地亦凉，人家難得此修廊。',32,'全唐诗/poet.song.183000.json','["古寺無風地亦凉，人家難得此修廊。", "老僧貪說葛藤話，不覺山童上晚香。"]'),
('c783ad3a-62f0-4db5-9b08-14abdf8e187c','柬陳宗之','趙汝績','宋','宋诗','song-poetry','','[]','略約東風客袖寒，賣花聲裏立闌干。',32,'全唐诗/poet.song.183000.json','["略約東風客袖寒，賣花聲裏立闌干。", "有錢不肯沽春酒，旋買唐詩對雨看。"]'),
('1a267cbb-7401-45c7-b5e4-7fc26a684eeb','姚江道中','趙汝績','宋','宋诗','song-poetry','','[]','漉酒蒸糕餽歲時，紛紛兒女換新衣。',32,'全唐诗/poet.song.183000.json','["漉酒蒸糕餽歲時，紛紛兒女換新衣。", "隣翁七十看鵝鴨，日暮破船撐未歸。"]'),
('4db2b5c4-90c2-4004-ace3-ee4fc631d34e','謝高左藏惠墨竹','趙汝績','宋','宋诗','song-poetry','','[]','幅牋幻墨起秋風，便與蘭亭景致同。',32,'全唐诗/poet.song.183000.json','["幅牋幻墨起秋風，便與蘭亭景致同。", "料得揮毫盤礴際，渭川千畝在胸中。"]'),
('1b9e9394-5af5-4fb2-a636-658c1b440c92','韓仲龢墨竹','趙汝績','宋','宋诗','song-poetry','','[]','墨暈生冰硯影寒，素毫幻出碧琅玕。',32,'全唐诗/poet.song.183000.json','["墨暈生冰硯影寒，素毫幻出碧琅玕。", "尋常夜月窗前見，此度秋風紙上看。"]'),
('10652f4f-9f0c-4cc3-be13-71f47de49b81','送竹軒歸越','趙汝績','宋','宋诗','song-poetry','','[]','東風隔岸繫歸航，怕送君行重憶鄉。',32,'全唐诗/poet.song.183000.json','["東風隔岸繫歸航，怕送君行重憶鄉。", "爲探山臺牆下柳，新來添得幾絲黄。"]'),
('f486a364-b1ea-4736-ba4c-6bf901d1c720','菊花','趙汝績','宋','宋诗','song-poetry','','[]','汛掃官廳頓菊栽，老兵怕礙客車來。',32,'全唐诗/poet.song.183000.json','["汛掃官廳頓菊栽，老兵怕礙客車來。", "費人早晚勤澆灌，何似籬邊自在開。"]'),
('cf8e26f2-0de2-4f87-9cc1-8175d4e388dd','雞冠花','趙汝績','宋','宋诗','song-poetry','','[]','木雞不與衆雞同，曾逐旌陽上碧空。',32,'全唐诗/poet.song.183000.json','["木雞不與衆雞同，曾逐旌陽上碧空。", "學得仙家餐玉法，至今木血不能紅。"]'),
('3930c98e-0b80-4bd6-abc9-ab4c9650eb47','瓜','趙汝績','宋','宋诗','song-poetry','','[]','冰泉浸綠玉，霜刃破黄金。',24,'全唐诗/poet.song.183000.json','["冰泉浸綠玉，霜刃破黄金。", "凉冷消晚暑，清甘洗渴心。"]'),
('92564cf8-3052-4358-9427-c0b048e201b3','貧居','趙汝績','宋','宋诗','song-poetry','','[]','適愛貧居好，全憐鷗鷺鄉。',48,'全唐诗/poet.song.183000.json','["適愛貧居好，全憐鷗鷺鄉。", "布衾魂夢穩，蔬食齒牙香。", "俗事吟邊少，時光靜裏長。", "向南多隙地，無力創書臺。"]'),
('cbff25d8-6b4f-46bb-9da4-531bce3e7917','剡中戴亭','趙汝績','宋','宋诗','song-poetry','','[]','抱得琴歸只自聽，何心商略少微星。',32,'全唐诗/poet.song.183000.json','["抱得琴歸只自聽，何心商略少微星。", "雪中不管人回棹，正使敲門未必應。"]'),
('c5b6530d-edf7-40e0-ab37-b99c5cc50f2c','句  其一','趙汝績','宋','宋诗','song-poetry','','[]','纔有數花香便遠，更無一葉影方奇。',16,'全唐诗/poet.song.183000.json','["纔有數花香便遠，更無一葉影方奇。"]'),
('809fcf8e-213c-4462-8a41-d99241f43d5d','句  其二','趙汝績','宋','宋诗','song-poetry','','[]','秋來難得花成染，閒引牽牛上短籬。',16,'全唐诗/poet.song.183000.json','["秋來難得花成染，閒引牽牛上短籬。"]'),
('8c7624a2-1237-4186-87b8-d786f09efa27','寄趙紫芝','張弋','宋','宋诗','song-poetry','','[]','獨游非一事，書札故應遲。',48,'全唐诗/poet.song.183000.json','["獨游非一事，書札故應遲。", "江上逢春月，湖邊憶醉時。", "有雲爲我伴，終日誦君詩。", "百鳥鳴花樹，聲聲在遠思。"]'),
('66f10f3d-b675-4477-9547-d7aba357bc7f','得山中友人書','張弋','宋','宋诗','song-poetry','','[]','近得山中信，山中頗寂寥。',48,'全唐诗/poet.song.183000.json','["近得山中信，山中頗寂寥。", "酒方收秫釀，薪旋割茅燒。", "破屋秋多雨，平湖暗有潮。", "不曾逢客至，默坐過清宵。"]'),
('529dc76b-7756-45c4-9a2c-2f1a03dd9a50','春晚','張弋','宋','宋诗','song-poetry','','[]','萬事吾今飛絮輕，此身如燕又巢成。',32,'全唐诗/poet.song.183000.json','["萬事吾今飛絮輕，此身如燕又巢成。", "暗思庾信家邊竹，綠籜新添有幾莖。"]'),
('a14b9297-1206-42a1-9bf6-019cc36b6b05','夏日從陳宗之借書偶成','張弋','宋','宋诗','song-poetry','','[]','自從春去後，少省出柴扉。',48,'全唐诗/poet.song.183000.json','["自從春去後，少省出柴扉。", "樹暗鴉巢隠，簷空燕迹稀。", "憶山憐有夢，當暑詠無衣。", "案上書堆滿，多應借得歸。"]'),
('4abb8b0d-eb9d-402b-8279-1503787150ff','楚州','張弋','宋','宋诗','song-poetry','','[]','落帆停鼓鸛湖頭，兩度因循到楚州。',32,'全唐诗/poet.song.183000.json','["落帆停鼓鸛湖頭，兩度因循到楚州。", "柳下人家曾識面，笑求新句寫粧樓。"]'),
('85ffcd5f-7f37-47c3-92dc-84e7cc1b58bd','江樓飲客','張弋','宋','宋诗','song-poetry','','[]','鄰家貰酒尊，斟酌共王孫。',48,'全唐诗/poet.song.183000.json','["鄰家貰酒尊，斟酌共王孫。", "老菜羹遲熟，凍油燈屢昏。", "夜寒人罷市，坐久僕敲門。", "隔岸歌明月，月明江水渾。"]'),
('54aa94b8-d868-45eb-a00b-b23c28571773','游蔣山','張弋','宋','宋诗','song-poetry','','[]','綀布作方袍，因閑偶出遨。',48,'全唐诗/poet.song.183000.json','["綀布作方袍，因閑偶出遨。", "秋風城郭凈，寒色樹林高。", "鹿守禪關老，僧修佛殿勞。", "再來思久住，人世事如毛。"]'),
('73454c7c-441f-47d0-8d38-3693fbd71c0b','送蔡監丞赴高郵','張弋','宋','宋诗','song-poetry','','[]','城古似盤盂，榮分刺史符。',48,'全唐诗/poet.song.183000.json','["城古似盤盂，榮分刺史符。", "夏新看藕葉，夜久見蠙珠。", "吏過朱方接，山從邵伯無。", "文遊遺迹在，民俗易相孚。"]'),
('5b542666-1174-4f06-bf28-c1718fc6f65d','送杜晦之兄弟歸閩','張弋','宋','宋诗','song-poetry','','[]','秋來猶苦熱，歸去莫貪程。',48,'全唐诗/poet.song.183000.json','["秋來猶苦熱，歸去莫貪程。", "官寫新銜位，詩傳舊姓名。", "幾家村酒賤，一路澗泉清。", "想到鄉閭日，爭看兩弟兄。"]'),
('b009095f-c448-49bb-8a4b-a98c2146e74f','簡周宗聖','張弋','宋','宋诗','song-poetry','','[]','曠野有芳芷，近江無早鶑。',48,'全唐诗/poet.song.183000.json','["曠野有芳芷，近江無早鶑。", "春詩定多少，旬日又清明。", "樹暗憐楊柳，花開認橘橙。", "相尋每乖阻，夢裏亦愁生。"]'),
('4c793f83-d05f-45a2-a350-90dfb5414aca','莫春','張弋','宋','宋诗','song-poetry','','[]','日日雨霏霏，閉門無所知。',48,'全唐诗/poet.song.183000.json','["日日雨霏霏，閉門無所知。", "謾尋花發處，已過絮飛時。", "替紙蠶生遍，修巢燕立危。", "但催人老去，羞作送春詩。"]'),
('95847b97-f938-499c-a4f8-c30cf16f04f0','遊長干留寄聰公','張弋','宋','宋诗','song-poetry','','[]','僧去尋芳草，客來看落花。',48,'全唐诗/poet.song.183000.json','["僧去尋芳草，客來看落花。", "就齋槃乞菜，借水鼎煎茶。", "日炙春無色，風吹天有沙。", "欲回成再住，此意問林鴉。"]'),
('eef016c1-9226-4bef-a2fd-3ff55576c90d','舟次湖口追憶任明府','張弋','宋','宋诗','song-poetry','','[]','重來又十年，山水故凄然。',48,'全唐诗/poet.song.183000.json','["重來又十年，山水故凄然。", "獨鴈仍爲旅，雙鳬已作仙。", "濁流分蜀派，青色聚淮烟。", "石上罾魚者，猶言縣令賢。"]'),
('df58401b-4eb9-40e9-9cd8-e3e4aeb34f63','慈母磯','張弋','宋','宋诗','song-poetry','','[]','莫嫌舟逆上，子細得看山。',48,'全唐诗/poet.song.183000.json','["莫嫌舟逆上，子細得看山。", "衆草名難識，孤花影自閑。", "避人鷹翅響，經雨石文斑。", "夜久江風冷，神仙定往還。"]'),
('66b9e50a-fb2b-45c3-b376-276b5d722bb2','寄別顔伯奇','張弋','宋','宋诗','song-poetry','','[]','情深袂怕分，豈不欲辭君。',48,'全唐诗/poet.song.183000.json','["情深袂怕分，豈不欲辭君。", "轉柁方乘曉，思山已隔雲。", "菊當前路見，鴈在半江聞。", "把盞秋纔好，遥憐白鷺群。"]'),
('2cdb1541-064e-4aab-8824-27c1d801e4e1','送宋謙父之清江因簡希亮','張弋','宋','宋诗','song-poetry','','[]','吟詩夕陽裏，相送上瀟灘。',48,'全唐诗/poet.song.183000.json','["吟詩夕陽裏，相送上瀟灘。", "前路逢梅處，同誰倚棹看。", "歲窮風力緊，江闊鴈聲寒。", "持此呈蘇李，人生識面難。"]'),
('10369eef-c7fe-4882-8fc4-50674e48c8a9','高郵送紫芝','張弋','宋','宋诗','song-poetry','','[]','重逢又重別，把盞更凄然。',48,'全唐诗/poet.song.183000.json','["重逢又重別，把盞更凄然。", "明日帆開岸，平湖水接天。", "好詩應自作，狂夢與誰圓。", "我欲來相趁，揚州且住船。"]'),
('ab66505a-ef86-4f7d-91b1-e0c5e35d0f40','逢王元任','張弋','宋','宋诗','song-poetry','','[]','寂寞淮南道，憑君獨記余。',48,'全唐诗/poet.song.183000.json','["寂寞淮南道，憑君獨記余。", "始知元住此，久悔不通書。", "暮岳留同眺，寒房與借居。", "共懷京邑燕，已是二年餘。"]'),
('32cc04b9-2960-4741-ae82-d69da9f9d30a','李景文移居','張弋','宋','宋诗','song-poetry','','[]','能詩留幕府，借宅近南湖。',48,'全唐诗/poet.song.183000.json','["能詩留幕府，借宅近南湖。", "吏去少公事，客來多釣徒。", "雲爲今夜雪，梅發去年株。", "我亦同州住，相過路不迂。"]'),
('a71a8cfd-8c3d-4d73-82b9-55dfeff9bbe6','元日','張弋','宋','宋诗','song-poetry','','[]','曆以寅爲正，風從艮位來。',48,'全唐诗/poet.song.183000.json','["曆以寅爲正，風從艮位來。", "桃符當壁寫，竹戶趁鍾開。", "宿雨滋初茁，長年老不材。", "滿庭青柏葉，惆悵獨持杯。"]'),
('ac50acc9-c91f-4c87-98a0-0481ea44d7d8','送胡道士歸康廬','張弋','宋','宋诗','song-poetry','','[]','避世懷孤往，爲庵近五巒。',48,'全唐诗/poet.song.183000.json','["避世懷孤往，爲庵近五巒。", "出無人作伴，歸有鶴相看。", "老石苔衣凈，深山瀑布寒。", "自言猶養母，應未得燒丹。"]'),
('ba88bd72-6a98-4a1b-ab54-9c985c70e7cd','豫章別紫芝','張弋','宋','宋诗','song-poetry','','[]','吟苦事俱廢，拙深貧未除。',48,'全唐诗/poet.song.183000.json','["吟苦事俱廢，拙深貧未除。", "年來如旅鴈，秋至即移居。", "古道行黄葉，空囊貯素書。", "一生江海恨，惟子最知余。"]'),
('9539e816-41ac-4b86-84e2-c646aee0e7fc','子山寺','張弋','宋','宋诗','song-poetry','','[]','迢遞前朝寺，經過遂一遊。',48,'全唐诗/poet.song.183000.json','["迢遞前朝寺，經過遂一遊。", "白雲鴉樹曉，黄葉鳳臺秋。", "僧舉開山話，人消在世愁。", "殿廊經劫火，已費十年修。"]'),
('4d57ce61-ac95-4eed-88bd-f39b13f708c0','送郭道士之江州','張弋','宋','宋诗','song-poetry','','[]','盡看山南景，忽思山北遊。',48,'全唐诗/poet.song.183000.json','["盡看山南景，忽思山北遊。", "屐過雲亦動，琴罷月空流。", "世上無非熱，林間一似秋。", "雖然乍相識，別去也能愁。"]'),
('ea5778b1-1360-4680-888d-4f0f3bee37d1','彭蠡阻風寄城中故人','張弋','宋','宋诗','song-poetry','','[]','欲行行未得，累日滯孤舟。',48,'全唐诗/poet.song.183000.json','["欲行行未得，累日滯孤舟。", "月照山皆近，風吹水倒流。", "地名人不識，秋景客相愁。", "憶你惟成夢，遥知獨倚樓。"]'),
('d5822611-b78b-44ff-8de3-31c75ec4401e','留滯','張弋','宋','宋诗','song-poetry','','[]','蕭條十日餘，留滯別人居。',48,'全唐诗/poet.song.183000.json','["蕭條十日餘，留滯別人居。", "借吏抄陳作，黏碑學草書。", "煙清數村曉，月落一潭虛。", "吾自疑秋色，那堪樹木疏。"]'),
('e38481eb-704c-456e-a840-d4cc310806aa','送翁十赴舉','張弋','宋','宋诗','song-poetry','','[]','今年科詔下，頗亦動山情。',48,'全唐诗/poet.song.183000.json','["今年科詔下，頗亦動山情。", "丹竈留雲守，書裝冒熱行。", "卜知三命勝，業擅一經明。", "倘赴瓊林宴，能詩舊有聲。"]'),
('87dbfb65-c385-4ea6-ac6f-75e1a8577d67','再送盛君之昇州','張弋','宋','宋诗','song-poetry','','[]','君與余皆懶，余如君更貧。',48,'全唐诗/poet.song.183000.json','["君與余皆懶，余如君更貧。", "今年再同夏，兩鬢獨非春。", "去棹孤山浪，征衫西府塵。", "似聞仍用武，爲算立功人。"]'),
('451c5ce5-c1bd-4a8c-bcae-50db348f231f','再送丕父','張弋','宋','宋诗','song-poetry','','[]','弟行兄出送，有約共憑欄。',48,'全唐诗/poet.song.183000.json','["弟行兄出送，有約共憑欄。", "草木雨初過，江湖路轉難。", "同懷年各長，重別酒無歡。", "明日雙鍾下，蒼崖應獨看。"]'),
('97ed9dd8-fd58-444e-9d41-b44f1b83283f','移菊','張弋','宋','宋诗','song-poetry','','[]','秋風籬落遠，晨起自移栽。',48,'全唐诗/poet.song.183000.json','["秋風籬落遠，晨起自移栽。", "稍覺微根損，須遲數日開。", "最清人愛重，乍見蝶疑猜。", "昔有陶元亮，因茲歸去來。"]'),
('a9f3aa76-5f66-4512-9a5a-a005efa31c87','贈沈莊可','張弋','宋','宋诗','song-poetry','','[]','卷上芳名舊所知，見君還恨識君遲。',64,'全唐诗/poet.song.183000.json','["卷上芳名舊所知，見君還恨識君遲。", "數莖短髮沾霜白，一葉扁舟觸浪危。", "問遍菊名因作譜，畫將蘭本要求詩。", "向南郡邑多經過，楚士能狂更有誰。"]'),
('647f23f6-64a0-4db2-9610-1c922b971417','寄蘇希亮','張弋','宋','宋诗','song-poetry','','[]','因何也識閑名字，遂托交遊索近詩。',64,'全唐诗/poet.song.183000.json','["因何也識閑名字，遂托交遊索近詩。", "想像獨吟應更苦，分明此意似相知。", "空林日短歸鴉早，遠水寒多鴈到遲。", "安得你來同度歲，傳聞畫筆最清奇。"]'),
('676abd7c-59c4-4635-b0fc-7519991e09b4','送徐和卿之上饒','張弋','宋','宋诗','song-poetry','','[]','江樹雜丹青，江寒少得晴。',48,'全唐诗/poet.song.183000.json','["江樹雜丹青，江寒少得晴。", "亦知君去路，多是水爲程。", "銜位猶書岳，游從半作卿。", "如逢二泉子，因說野人名。"]'),
('2acbceac-5097-4a06-9468-6aae300c6305','山行','張弋','宋','宋诗','song-poetry','','[]','偶作山行只杖藜，歸逢寒日下山時。',32,'全唐诗/poet.song.183000.json','["偶作山行只杖藜，歸逢寒日下山時。", "與僧並立看紅樹，忽有鶴來栖樹枝。"]'),
('82b16aa5-f939-4a4b-9b94-9b162f1d5070','送人歸南康','張弋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我來方與廬山別，你去廬山是故鄉。',32,'全唐诗/poet.song.183000.json','["我來方與廬山別，你去廬山是故鄉。", "前日住山渾不覺，如今山遠却思量。"]'),
('fd633843-989b-4ceb-8711-1b0e968b9f44','舒州歲暮','張弋','宋','宋诗','song-poetry','','[]','窮冬日日愛天晴，古寺門開絕送迎。',64,'全唐诗/poet.song.183000.json','["窮冬日日愛天晴，古寺門開絕送迎。", "野鶴忽來橋上立，山僧獨向水邊行。", "過寒梅樹白全少，入臘草牙青漸生。", "又是舒州一年了，怕看新曆動鄉情。"]'),
('97ddd064-90a2-46cc-8e6f-10c61642f088','廣教寺','張弋','宋','宋诗','song-poetry','','[]','英雄居處終奇特，幾度欲來今始能。',64,'全唐诗/poet.song.183000.json','["英雄居處終奇特，幾度欲來今始能。", "騎省文高存古篆，橋公樹朽長寒藤。", "清流併遶分三澗，翠竹相依住數僧。", "沙鳥詎知千載恨，日斜飛下立漁罾。"]'),
('4eb3e263-3fa3-4b1b-a3fb-a804a7dbfc0a','游禪林寺','張弋','宋','宋诗','song-poetry','','[]','寺置蕭梁曾識少，今朝蘚磴始經過。',64,'全唐诗/poet.song.183000.json','["寺置蕭梁曾識少，今朝蘚磴始經過。", "天低落日江湖遠，煙冷風清竹樹多。", "蟲引翠禽行壞屋，馬驚白犬吠懸蘿。", "一僧九十形容古，岩下逢予忽浩歌。"]'),
('b771731e-0e04-402a-ae59-25849271e166','漢東郡齋夕坐','張弋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山解夏洪山去，自到山邊葉已飄。',64,'全唐诗/poet.song.183000.json','["廬山解夏洪山去，自到山邊葉已飄。", "鴻鴈影多憐塞近，交朋書少覺身遥。", "屢游騎慣將軍馬，不飲還封道士瓢。", "心憶清吟更岑寂，玉京誰與話寒宵。"]'),
('b5317fd8-3f52-4f2c-aaa0-1a270ae3996a','遊智門寺  其一','張弋','宋','宋诗','song-poetry','','[]','一間瓦屋荒山裏，山路縈迴夕照明。',32,'全唐诗/poet.song.183000.json','["一間瓦屋荒山裏，山路縈迴夕照明。", "祇有比丘頭雪白，旋收經卷入相迎。"]'),
('35995124-57cb-4b28-9998-f521544fb676','遊智門寺  其二','張弋','宋','宋诗','song-poetry','','[]','傳聞此地有龍飛，佛殿殘磚刻鳳螭。',32,'全唐诗/poet.song.183000.json','["傳聞此地有龍飛，佛殿殘磚刻鳳螭。", "事去千年無問處，寂寥霜草卧苔碑。"]'),
('af6f00bb-3a33-4070-be95-b7ad78f14158','晝坐','張弋','宋','宋诗','song-poetry','','[]','出門無所往，獨自坐胡床。',48,'全唐诗/poet.song.183000.json','["出門無所往，獨自坐胡床。", "雨濯殘梅盡，風吹百草長。", "近邊人喜戰，偶病客傳方。", "不奈春愁密，思君對酒觴。"]'),
('f36e1347-dffc-41b2-9c68-68a73466beb3','寄秋塘','張弋','宋','宋诗','song-poetry','','[]','五湖風雪分頭去，千里淮山信脚行。',64,'全唐诗/poet.song.183000.json','["五湖風雪分頭去，千里淮山信脚行。", "涉世真成妄男子，談詩長憶老先生。", "塘邊瓜茹須頻灌，郭外田疇粗可耕。", "莫倚瘦筇吟白髮，浪傳詩句入都城。"]'),
('2ffed19f-bae0-4b34-a3b6-e5fc869ec132','寄劉潛夫','張弋','宋','宋诗','song-poetry','','[]','八斗文章用有餘，數車聲譽滿江湖。',32,'全唐诗/poet.song.183000.json','["八斗文章用有餘，數車聲譽滿江湖。", "今年好獻南郊賦，幕府文書有暇無。"]'),
('02601701-409e-40fb-ac15-657b9b32f0e9','龍灣','張弋','宋','宋诗','song-poetry','','[]','畫船椎鼓過龍灣，回首昇州只見山。',32,'全唐诗/poet.song.183000.json','["畫船椎鼓過龍灣，回首昇州只見山。", "前日方來今又去，閑人元自不曾閑。"]'),
('7ac45098-f450-44b3-8987-19530cd08c72','東門野興','張弋','宋','宋诗','song-poetry','','[]','偶爾行坰野，何曾載酒觴。',48,'全唐诗/poet.song.183000.json','["偶爾行坰野，何曾載酒觴。", "草長難望遠，樹密易尋凉。", "月子聞吳唱，漁翁愛楚狂。", "還聽路人說，□□□□□。"]'),
('c53aba77-3991-45a5-8826-0773ee9bcdb2','送趙秘著赴湖北倉','張弋','宋','宋诗','song-poetry','','[]','聖君私七澤，使事浼清高。',48,'全唐诗/poet.song.183000.json','["聖君私七澤，使事浼清高。", "俗古山川闊，路長車馬勞。", "峒人耕綠野，隠者醉紅桃。", "閒暇應登賞，詞章繼楚騷。"]'),
('db989b89-5d15-4708-b994-c87ad036c5fc','送謝耕道謁趙史君','張弋','宋','宋诗','song-poetry','','[]','櫧葉陰深杜宇啼，遠遊還欲過淮西。',64,'全唐诗/poet.song.183000.json','["櫧葉陰深杜宇啼，遠遊還欲過淮西。", "呂蒙城下河流濁，亞父祠邊草色齊。", "太守舊來相愛重，故交老去惜分携。", "年年慈母手中綫，縫得征衫當一犁。"]'),
('b18a66d2-0c91-42dc-8f92-aaff1678f69d','題式之詩卷後','李賈','宋','宋诗','song-poetry','','[]','矯首天地間，凄其望終古。',120,'全唐诗/poet.song.183000.json','["矯首天地間，凄其望終古。", "前輩久零落，斯文日榛莽。", "戴君天台秀，忽向南方來。", "老氣橫九州，胸次何崔嵬。", "藻□晚更奇，崩騰豁高趣。", "疑是赤城霞，飄颻墮章句。", "白首一孤劍，誰人薦子虛。", "有時杯酒間，高論傾淮湖。", "既有四海名，何慚萬鍾樂。", "君看榮與賤，千載俱冥漠。"]'),
('22afb7bf-4bf4-45c9-8635-b514ed7ccf27','題式之詩卷後','林璧','宋','宋诗','song-poetry','','[]','少年曾讀石屏詩，老去江湖幸見之。',64,'全唐诗/poet.song.183000.json','["少年曾讀石屏詩，老去江湖幸見之。", "百倍尋常真足惜，十存八九實堪悲。", "蛙鳴蟬噪人爭羨，天巧神功彼自知。", "我欲流傳天下去，爲求完本補亡誰。"]'),
('25e62ff1-c09a-4a13-85e8-efda04ffa122','賀杜清獻入相  其一','戴木','宋','宋诗','song-poetry','','[]','玉陛傳呼宰相來，歡騰海內翕如雷。',64,'全唐诗/poet.song.183000.json','["玉陛傳呼宰相來，歡騰海內翕如雷。", "律身清介祁公操，佐主謀謨如晦才。", "夢弼已知符衆望，生賢益信應三台。", "從容宰席調天紀，協氣從頭徧九垓。"]'),
('ad677f3a-d9af-4c66-9f4d-5a432b3f49d9','賀杜清獻入相  其二','戴木','宋','宋诗','song-poetry','','[]','相公出處繫安危，當務何先諒熟思。',64,'全唐诗/poet.song.183000.json','["相公出處繫安危，當務何先諒熟思。", "守令近民須選擇，憸壬蠹國亟芟夷。", "精蒐邊面三軍帥，早建皇儲萬世基。", "納誨進賢尤素志，佇看經濟大猷爲。"]'),
('c2aef416-d12a-42ca-bd71-85f22e0d577b','送趙侯之任','戴震伯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','趙侯東南彥，遠作西南征。',72,'全唐诗/poet.song.183000.json','["趙侯東南彥，遠作西南征。", "驪駒向前路，高秋不留行。", "送以奉林鶴，仍吹子晉笙。", "淵淵洞庭湖，古月今猶明。", "流輝千萬里，何但光連城。", "懸知有佳惠，終始心和平。"]'),
('007000eb-e2aa-457c-b89a-44d206523f88','送趙侯之任','戴雨耕','宋','宋诗','song-poetry','','[]','送君遠作羊荆州，送君西上黄鶴樓。',112,'全唐诗/poet.song.183000.json','["送君遠作羊荆州，送君西上黄鶴樓。", "漢晉諸公舊遊處，斷磯黄葉風雨秋。", "只今麾纛□南斗，整暇坐列皆公侯。", "江湖浩蕩青天流，清風千古吹棹謳。", "專城分符得召杜，見此文彩珊瑚鈎。", "請因諫議思岳陽，遂歌羽人仍丹丘。", "杜蘅吹香結衣珮，思與老子同遨遊。"]'),
('595bd3d3-1f38-4c44-93a7-5ccbadc925ce','送留雲上人住翠屏澄照寺','戴成祖','宋','宋诗','song-poetry','','[]','雲出於山復戀山，至今留住翠屏隠。',32,'全唐诗/poet.song.183000.json','["雲出於山復戀山，至今留住翠屏隠。", "片雲既被山留住，雲自留山我自還。"]'),
('166992d1-86db-4616-ad6b-498c41e9b34f','題姚雪蓬騎牛像','趙時習','宋','宋诗','song-poetry','','[]','騎牛無笠又無簑，斷隴橫岡到處過。',32,'全唐诗/poet.song.183000.json','["騎牛無笠又無簑，斷隴橫岡到處過。", "暖日暄風不常有，前村雨暗却如何。"]'),
('b66ce1c3-16bd-4367-96d6-1a0aee30f25a','同舍弟游紫陽','陳芾','宋','宋诗','song-poetry','','[]','紫陽高不極，舊是許仙家。',48,'全唐诗/poet.song.183000.json','["紫陽高不極，舊是許仙家。", "古觀開山麓，懸崖吐杏花。", "雲飛籠晚樹，鶴唳落殘霞。", "且共探玄理，從他日欲斜。"]'),
('9e2b26c5-ffcd-4f01-82f9-66f61a59cb07','紫陽觀和家兄作','陳阜','宋','宋诗','song-poetry','','[]','相將到靈觀，正值雨初晴。',48,'全唐诗/poet.song.183000.json','["相將到靈觀，正值雨初晴。", "花近香逾妙，峰遥色更清。", "鶴盤雲外影，磬和澗中聲。", "再拜真人像，還丹願指明。"]'),
('c8c17bc5-2047-4ca8-87ec-a375f777dd09','龍泉觀','何行','宋','宋诗','song-poetry','','[]','蓬萊境界隔風烟，一带銀河接九天。',64,'全唐诗/poet.song.183000.json','["蓬萊境界隔風烟，一带銀河接九天。", "禮斗瑶臺春草合，豢龍石鉢玉沙圓。", "紅雲幾片危樓上，古木千尋落照邊。", "惆悵仙人何處去，空餘月色滿山川。"]'),
('77928d82-8e80-4221-ac6d-e973fa8f113d','登麻姑山','曾漸','宋','宋诗','song-poetry','','[]','躡石捫蘿得得來，人間塵累已忘懷。',64,'全唐诗/poet.song.183000.json','["躡石捫蘿得得來，人間塵累已忘懷。", "行窮險道忽平地，立看飛泉傾斷崖。", "邃宇半依蒼木裏，秀峰長是白雲埋。", "方平羽駕今何在，欲會仙姑恨未諧。"]'),
('fa4ff5fc-0a2e-4e68-8ba6-d4e627bc7f9a','寒夜','杜耒','宋','宋诗','song-poetry','','["\u6708\u8272", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u6885\u82b1", "\u8bbf\u53cb", "\u82b1", "\u5199\u82b1"]','寒夜客來茶當酒，竹爐湯沸火初紅。',32,'全唐诗/poet.song.183000.json','["寒夜客來茶當酒，竹爐湯沸火初紅。", "尋常一樣窗前月，纔有梅花便不同。"]'),
('f51c16b9-23c1-4017-b900-b85cb9501813','送吳太博赴莆中','杜耒','宋','宋诗','song-poetry','','[]','貴爲五馬只儒酸，都說先生大耐官。',64,'全唐诗/poet.song.183000.json','["貴爲五馬只儒酸，都說先生大耐官。", "去國十年雖已久，愛君一念不曾寒。", "定知前輩如公少，好與今人作樣看。", "歸日不須囊薏苡，有書堪錄荔堪乾。"]'),
('d68efb3b-96a9-46ba-bad0-69be4c958110','苕溪  其一','杜耒','宋','宋诗','song-poetry','','[]','晚立苕溪溪上頭，往來無數採菱舟。',32,'全唐诗/poet.song.183000.json','["晚立苕溪溪上頭，往來無數採菱舟。", "採菱歸去明朝賣，安識人聞樂與愁。"]'),
('d6bbc831-232a-450e-93b6-75125a8890ff','苕溪  其二','杜耒','宋','宋诗','song-poetry','','[]','風掠篷窗兩鬢秋，生涯無歲不扁舟。',32,'全唐诗/poet.song.183000.json','["風掠篷窗兩鬢秋，生涯無歲不扁舟。", "吟詩本欲相消遣，及到吟成字字愁。"]'),
('f07c08a9-0dbe-4b22-8387-8615d6dc7c80','送胡季昭竄象郡','杜耒','宋','宋诗','song-poetry','','[]','廬陵一小郡，百歲兩胡公。',48,'全唐诗/poet.song.183000.json','["廬陵一小郡，百歲兩胡公。", "論事雖小異，處心應略同。", "有書莫焚稿，無恨豈傷弓。", "病媿不遠別，寫詩霜月中。"]'),
('092ddee3-210c-45e1-ace6-bea25f7051f1','窗間','杜耒','宋','宋诗','song-poetry','','[]','秋香爛熳入屏帷，金粟樓臺富貴時。',32,'全唐诗/poet.song.183000.json','["秋香爛熳入屏帷，金粟樓臺富貴時。", "曉起旋收花上露，窗間閒寫夜來詩。"]'),
('b3d0f5c1-d209-4846-99a6-0f1f598e5e99','同紫芝游西山','杜耒','宋','宋诗','song-poetry','','[]','幾番江上凭欄久，今在西山山裏行。',64,'全唐诗/poet.song.183000.json','["幾番江上凭欄久，今在西山山裏行。", "天遣得隨三客後，春來無此一朝晴。", "方穿藤蔓尋源去，忽見煙霏趁步生。", "幽鳥向人作清哢，似應知我有詩成。"]'),
('e2594848-135e-4d4e-a974-7fd3f75b9dc7','同紫芝宿雙嶺','杜耒','宋','宋诗','song-poetry','','[]','本作翠巖游，反成雙嶺留。',48,'全唐诗/poet.song.183000.json','["本作翠巖游，反成雙嶺留。", "雲深山易晚，雨過寺如秋。", "野水連青竹，殘僧半白頭。", "上方成共宿，劇語到元幽。"]'),
('ca8514d1-2d96-4d8d-90b1-bf4a01a9d582','凌歊臺','杜耒','宋','宋诗','song-poetry','','[]','幾年聽客話凌歊，不似臺邊目力遥。',64,'全唐诗/poet.song.183000.json','["幾年聽客話凌歊，不似臺邊目力遥。", "千古江山猶昨日，六宮歌舞自前朝。", "苔碑有字多漫滅，野寺無僧轉寂寥。", "碧聚雙蛾愁不斂，闌干落照重魂消。"]'),
('cc80c7b8-db1e-4311-a8e1-72e2f32f968a','朱令招作社獻','杜耒','宋','宋诗','song-poetry','','[]','閒官得趁宰官行，農務村村早辦耕。',64,'全唐诗/poet.song.183000.json','["閒官得趁宰官行，農務村村早辦耕。", "燕子知時還記舊，社公合雨却成晴。", "登壇飲福雖無稱，割肉懷歸似有情。", "宿露盡披山歷歷，賣花人起欲天明。"]'),
('100adfa1-53cb-4cf1-a375-d11542697d36','題李少保家傳','杜耒','宋','宋诗','song-poetry','','[]','將軍忠憤世無雙，忍見狂童作假王。',64,'全唐诗/poet.song.183000.json','["將軍忠憤世無雙，忍見狂童作假王。", "全蜀不移唐日月，四州重著漢衣裳。", "節旄凜凜風霜在，兄弟班班史傳香。", "若使中營星未殞，生擒頡利到龍荒。"]'),
('b1c9f7e9-bafc-4ae1-b11a-00875f63df03','秋晚','杜耒','宋','宋诗','song-poetry','','[]','穫稻已空霜未落，秋風雖老鴈猶遲。',32,'全唐诗/poet.song.183000.json','["穫稻已空霜未落，秋風雖老鴈猶遲。", "丹林黄葉斜陽外，絕勝春山暮雨時。"]'),
('173afe50-c6da-444e-9121-c16f826cf2a5','小山即事  其一','杜耒','宋','宋诗','song-poetry','','[]','一閒殊足樂，物物入吾詩。',48,'全唐诗/poet.song.183000.json','["一閒殊足樂，物物入吾詩。", "雨過苔逾碧，風來竹屢欹。", "日長思睡急，磨老出茶遲。", "近得邊頭信，今當六月師。"]'),
('d8978270-510b-4b81-8852-156923a8274e','小山即事  其二','杜耒','宋','宋诗','song-poetry','','[]','當時嘗愛酒，此夕更登樓。',48,'全唐诗/poet.song.183000.json','["當時嘗愛酒，此夕更登樓。", "月有十分好，人無一點愁。", "雲山開宿霧，燈火近清秋。", "何事太孤絕，前身是楚囚。"]'),
('1480a01f-df0a-4d23-bc4e-91cb98153209','遊禪寂寺訪隠居','杜耒','宋','宋诗','song-poetry','','[]','官閒仍暇日，乘興共尋芳。',48,'全唐诗/poet.song.183000.json','["官閒仍暇日，乘興共尋芳。", "久雨山蹊潤，新晴花氣香。", "春偏藏古寺，水漸滿閒塘。", "忽有隠居者，留人看海棠。"]'),
('c850a18e-aaa2-42b8-966d-05c4da4392fe','贈陳宗之','杜耒','宋','宋诗','song-poetry','','[]','往年曾見趙天樂，數說君家書滿牀。',64,'全唐诗/poet.song.183000.json','["往年曾見趙天樂，數說君家書滿牀。", "成卷好詩人借看，盈壺名酒母先嘗。", "對河却見桐陰合，隔壁應聞芸葉香。", "老不愛文空手出，從今煩爲蓄仙方。"]'),
('a36272ae-4a53-4d03-8636-d918b99e846b','重宿紫芝','杜耒','宋','宋诗','song-poetry','','[]','書窗隔湖水，寒氣倍馮陵。',48,'全唐诗/poet.song.183000.json','["書窗隔湖水，寒氣倍馮陵。", "集宿因重到，新詩得再承。", "月明山入坐，酒渴夜敲冰。", "爲爾二三友，令人去未能。"]'),
('e6c6d46a-1fa2-4e9b-9ba6-9292a178aed2','子規','杜耒','宋','宋诗','song-poetry','','[]','不論南北與東西，但是春山有子規。',32,'全唐诗/poet.song.183000.json','["不論南北與東西，但是春山有子規。", "啼到日邊啼未了，何嘗勸得二人歸。"]'),
('4c6f2b8d-254e-4b01-b717-0d51c7ddee5b','重遊禪林寺','杜耒','宋','宋诗','song-poetry','','[]','不到禪林又幾春，依然風景自清新。',32,'全唐诗/poet.song.183000.json','["不到禪林又幾春，依然風景自清新。", "竹窗松逕幽深處，只有黄花認著人。"]'),
('ad18a2cf-4f51-4201-ba5a-dfdcbd475182','句  其一','杜耒','宋','宋诗','song-poetry','','[]','生就石橋羅漢面，吟成雪屋閬仙詩。',16,'全唐诗/poet.song.183000.json','["生就石橋羅漢面，吟成雪屋閬仙詩。"]'),
('b536ebd0-19e7-4433-ade4-6fddda2fa38b','句  其二','杜耒','宋','宋诗','song-poetry','','[]','塵事分清事。',6,'全唐诗/poet.song.183000.json','["塵事分清事。"]'),
('d4e53923-93a5-4ee7-bb72-821e7d12278b','句  其三','杜耒','宋','宋诗','song-poetry','','[]','不畫涪翁畫李翁。',8,'全唐诗/poet.song.183000.json','["不畫涪翁畫李翁。"]'),
('03bc0375-1953-4c07-ab53-cab5f45da560','句  其四','杜耒','宋','宋诗','song-poetry','','[]','鴟夷讓員滑，混沌慚瘦爽。',12,'全唐诗/poet.song.183000.json','["鴟夷讓員滑，混沌慚瘦爽。"]'),
('652ad89e-907f-45f8-a2c8-39506fc4d7e6','句  其五','杜耒','宋','宋诗','song-poetry','','[]','青燈夜深雨，破帽曉來風。',12,'全唐诗/poet.song.183000.json','["青燈夜深雨，破帽曉來風。"]'),
('81f8d3a3-f308-4e4f-bd51-4e2c037985ff','句  其六','杜耒','宋','宋诗','song-poetry','','[]','釀雪不成微有雨，被風吹散却爲晴。',16,'全唐诗/poet.song.183000.json','["釀雪不成微有雨，被風吹散却爲晴。"]'),
('5ddf4aed-03cb-4704-a95a-996924f8f258','句  其七','杜耒','宋','宋诗','song-poetry','','[]','行窮十里嶺。',6,'全唐诗/poet.song.183000.json','["行窮十里嶺。"]'),
('6abcdbed-4df3-4825-846e-39d6fd695a9c','句  其八','杜耒','宋','宋诗','song-poetry','','[]','巖花隨處發。',6,'全唐诗/poet.song.183000.json','["巖花隨處發。"]'),
('e200f5d7-c0a8-4933-a7f2-cae71c30aac4','句  其九','杜耒','宋','宋诗','song-poetry','','[]','無風花自落。',6,'全唐诗/poet.song.183000.json','["無風花自落。"]'),
('484fe25f-7eaf-4d6c-be7e-2021d7b23c82','致爽軒','杜子更','宋','宋诗','song-poetry','','[]','西鄰東老總爲虛，料想君家樂有餘。',32,'全唐诗/poet.song.183000.json','["西鄰東老總爲虛，料想君家樂有餘。", "白酒黄金都是幻，爭如好客與收書。"]'),
('1a540399-2c72-41df-acd5-14961078584d','題絃風亭','趙潛夫','宋','宋诗','song-poetry','','[]','怪他蟹舍蠔房地，不是吟情住亦難。',64,'全唐诗/poet.song.183000.json','["怪他蟹舍蠔房地，不是吟情住亦難。", "數尺短牆圍晝寂，半鈎疏箔障春寒。", "水生草滿蛙鳴合，日薄花陰鶴夢安。", "底處青衫病司馬，浩歌東望取琴彈。"]'),
('2025cf62-1290-41d6-8bd0-b1909e91ebd4','送胡季昭謫象州','丁黼','宋','宋诗','song-poetry','','[]','一封書奏觸天威，萬里徒行出帝畿。',64,'全唐诗/poet.song.183000.json','["一封書奏觸天威，萬里徒行出帝畿。", "始得明時來讜論，豈知薄命墮危機。", "身同季弟辭兄去，女抱嬰兒伴母歸。", "風雨瀟瀟秋又老，雁應不到嶺南飛。"]'),
('98a65372-6881-40cb-adf0-ba8f906eb88b','送親戚錢尉入國','丁黼','宋','宋诗','song-poetry','','[]','正是朔風吹雪初，行縢結束問征途。',64,'全唐诗/poet.song.183000.json','["正是朔風吹雪初，行縢結束問征途。", "不能刺刺對婢子，已是昂昂真丈夫。", "常惠舊曾隨屬國，烏孫今亦病匈奴。", "不知漢節歸何日，準擬殷勤說汴都。"]'),
('ae0c2b7c-be4a-4452-a2b9-bbd1ad0bcaa9','寄題翠蛟亭','丁黼','宋','宋诗','song-poetry','','[]','每到秋風憶翠蛟，三年此地小遊遨。',32,'全唐诗/poet.song.183000.json','["每到秋風憶翠蛟，三年此地小遊遨。", "如今著脚緇塵裏，猶夢亭中閲怒濤。"]'),
('bf6597a5-c404-4286-939c-5fc8127e66e3','寄題不礙雲軒二首  其一','丁黼','宋','宋诗','song-poetry','','[]','傑閣臨無地，僊家小洞天。',24,'全唐诗/poet.song.183000.json','["傑閣臨無地，僊家小洞天。", "循簷自來往，非霧亦非煙。"]'),
('b6d4ec3d-df4e-45e7-acd8-5e2850c54b7d','寄題不礙雲軒二首  其二','丁黼','宋','宋诗','song-poetry','','[]','駕鶴歸三島，騎麟入九霄。',24,'全唐诗/poet.song.183000.json','["駕鶴歸三島，騎麟入九霄。", "祗應明月夜，來此坐吹簫。"]'),
('4bcba946-bf20-40f0-a973-880339d5b86a','自詠','蔡沈','宋','宋诗','song-poetry','','[]','世事多顛倒，惟仁實可依。',48,'全唐诗/poet.song.183000.json','["世事多顛倒，惟仁實可依。", "幾多豪富貴，少不草萊歸。", "孺子宅猶在，令公園已非。", "躊躇不能去，端恐寸心違。"]'),
('c7b12bf4-4d34-4214-b5eb-0a40ddcc9af7','武夷山中四首  其一','蔡沈','宋','宋诗','song-poetry','','[]','余昔隠屏東，扁舟夾雙龍。',48,'全唐诗/poet.song.183000.json','["余昔隠屏東，扁舟夾雙龍。", "浩歌碧雲間，萬壑生清風。", "群仙幔亭宴，玉女雙鬢蓬。", "夕景落寒巖，照耀金芙蓉。"]'),
('3b9102a1-630a-440a-bed3-9f10ad0034c1','武夷山中四首  其二','蔡沈','宋','宋诗','song-poetry','','[]','余昔隠屏西，乘閑卧幽棲。',48,'全唐诗/poet.song.183000.json','["余昔隠屏西，乘閑卧幽棲。", "巖花雪端發，野鳥林際啼。", "仙掌神所刓，石崖天與齊。", "月華結清夢，啁哳聞金雞。"]'),
('98c36f2c-384c-4c41-b476-d406c5690662','武夷山中四首  其三','蔡沈','宋','宋诗','song-poetry','','[]','余昔隠屏南，春風駐征驂。',48,'全唐诗/poet.song.183000.json','["余昔隠屏南，春風駐征驂。", "開門傍水面，結屋依山嵐。", "千崖互紆鬰，萬象中渾涵。", "居然歲月深，寒花露毿毿。"]'),
('ccfeb9e2-1f54-417a-8b61-df67fe268569','武夷山中四首  其四','蔡沈','宋','宋诗','song-poetry','','[]','余昔隠屏北，飄然度巖側。',48,'全唐诗/poet.song.183000.json','["余昔隠屏北，飄然度巖側。", "誰知神仙居，自與塵世隔。", "瑶草霜更青，琪花雪仍白。", "橫玉叫寒雲，萬里天一色。"]'),
('1bbfef92-766e-476c-8723-6c9cea56cc6e','贈琴士劉伯華','蔡沈','宋','宋诗','song-poetry','','[]','公子方年少，絲桐長有名。',48,'全唐诗/poet.song.183000.json','["公子方年少，絲桐長有名。", "曲雖仍舊譜，指要發新聲。", "澗落泉初響，風清月正明。", "起予千古意，愴惻不勝情。"]'),
('cecda446-2e67-45cb-8fa9-c3ecbc2a8b04','山中','蔡沈','宋','宋诗','song-poetry','','[]','才既非時用，性本愛岑寂。',72,'全唐诗/poet.song.183000.json','["才既非時用，性本愛岑寂。", "決策西山遊，幽隠遂成癖。", "春風百花紅，秋月千嶂碧。", "煙霞結綢繆，猿鳥自疇昔。", "乘間撫深曠，噴薄轟鐵笛。", "笑挹天柱峰，高寒幾千尺。"]'),
('81c0251c-7c05-4f69-bdc5-397ff724c882','咏西山','蔡沈','宋','宋诗','song-poetry','','[]','紫荆相依倚，綠篠自蒙密。',96,'全唐诗/poet.song.183000.json','["紫荆相依倚，綠篠自蒙密。", "秋蘭澗中花，山果路邊實。", "沿崗引霜藤，臨流坐寒石。", "日暮陰崖開，雲收遠山出。", "疏籬尚存菊，荒庭舊垂橘。", "絲桐想虛堂，簡策居靜室。", "俯仰今幾時，漫然已陳跡。", "摩挲蒼苔痕，屐齒不可識。"]'),
('904210bb-43b3-47d0-9a35-75e65fbefe0e','贈棋士兼相','蔡沈','宋','宋诗','song-poetry','','[]','嵯峨遠遊冠，過我田里居。',144,'全唐诗/poet.song.183000.json','["嵯峨遠遊冠，過我田里居。", "手談達要妙，心計有卷舒。", "把握殺活機，操持開闔樞。", "總總如亂兵，紛紛若奔車。", "觀者皆怵惕，敵人更揶揄。", "一著起疲廢，萬口驚諠呼。", "巧思自神授，智慧非常拘。", "又聞風鑒精，許與且不渝。", "群公贈詩文，稱述良匪虛。", "自昔少兼能，今挾二術俱。", "奕秋與許負，世異同一軀。", "惜哉惟藝名，問學當何如。"]'),
('c994b9fa-bfda-401e-96e5-cd2fb3eb9e07','咏武夷','蔡沈','宋','宋诗','song-poetry','','[]','四曲遊人欵乃歌，舊磯千古老漁蓑。',32,'全唐诗/poet.song.183000.json','["四曲遊人欵乃歌，舊磯千古老漁蓑。", "題詩巖下人來往，春雨年年長綠莎。"]'),
('66b65927-a544-4a5a-9663-1e6117c6d455','贈談命余圓機','蔡沈','宋','宋诗','song-poetry','','[]','談命誰稱妙莫窮，圓機端的與天通。',32,'全唐诗/poet.song.183000.json','["談命誰稱妙莫窮，圓機端的與天通。", "試看今日飛騰者，多在當年許與中。"]');
